      const _hasStaleToolCall = !!c.stale_tool_call;
      const _hasLivePendingTool = c.is_live && !!c.pending_tool && !_hasStaleToolCall;
      // 30-min open-turn window was too generous — flagged a session as
      // "working" for up to half an hour after the user last typed, even
      // when the agent had clearly stopped. 5 min is enough to bridge a
      // slow streaming response without misreading idle sessions.
      const _OPEN_TURN_FRESH_S = 5 * 60;
      const _codexStateWorking = isCodexRow && c.codex_state === 'working';
      const _codexHasOpenTool = isCodexRow && !c.sidecar_status && !!c.pending_tool;
      const _codexOpenTurn = isCodexRow
        && c.is_live
        && !c.sidecar_status
        && !_hasStaleToolCall
        && (_codexHasOpenTool
          || (!!(c.last_event_type === 'user' || c.last_event_type === 'assistant')
            && _rowActivityAge < _OPEN_TURN_FRESH_S));
      const _geminiHasOpenTool = isGeminiRow && !c.sidecar_status && !!c.pending_tool;
      const _geminiOpenTurn = isGeminiRow
        && c.is_live
        && !c.sidecar_status
        && (_geminiHasOpenTool
          || (!!(c.last_event_type === 'user' || c.last_event_type === 'assistant')
            && _rowActivityAge < _OPEN_TURN_FRESH_S));
      const _cursorHasOpenTool = isCursorRow && !c.sidecar_status && !!c.pending_tool;
      const _cursorOpenTurn = isCursorRow
        && c.is_live
        && !c.sidecar_status
        && (_cursorHasOpenTool
          || (!!(c.last_event_type === 'user' || c.last_event_type === 'assistant')
            && _rowActivityAge < _OPEN_TURN_FRESH_S));
      const _antigravityHasOpenTool = isAntigravityRow && !c.sidecar_status && !!c.pending_tool;
      const _antigravityOpenTurn = isAntigravityRow
        && c.is_live
        && !c.sidecar_status
        && (_antigravityHasOpenTool
          || (!!(c.last_event_type === 'user' || c.last_event_type === 'assistant')
            && _rowActivityAge < _OPEN_TURN_FRESH_S));
      // _isWip = "the session is actually doing something right now". The
      // gh_in_progress flag (linked GitHub issue carries the
      // claude-in-progress label) is NOT a liveness signal — the label
      // can persist on an idle session for days — so it's surfaced as a
      // calmer separate chip below instead of dressing the row up like
      // live work.
      //
      // Trust the server's single-source-of-truth `state` for Claude WIP
      // instead of re-deriving from the sticky `sidecar_status==='active'`
      // marker. That marker only flips to "waiting" when the Stop hook fires,
      // so an interrupted turn left it "active" and — paired with a 30-min
      // staleness cap and the `_midTurn` escape hatch — read WIP for up to
      // half an hour after the agent stopped. The server now bounds the same
      // signal at _WORKING_GAP_WINDOW (120s) and exposes it as `state`, so the
      // 5-min-board-vs-30-min-server split is gone: both read one value.
      const _claudeWipFromSidecar = c.state === 'working';
      // Distinguish "agent is actively running" from "agent paused
      // waiting for the user". They render very differently — running
      // is the yellow pulsing WIP chip, waiting is a calm cyan WAITING /
      // QUESTION / APPROVE? chip with no pulse. Conflating them made
      // idle sessions blocked on the human read as "the agent is still
      // doing something", which is the bug the user kept reporting.
      // Optimistic-sending counts as agent-running for the WIP chip.
      // Without this, an injected session (e.g. UX-fixes-queue receive)
      // showed "Sending…" briefly in the live-tool slot but the
      // lifecycle chip stayed on whatever was there before (read-only /
      // no-edits / pushed) and the user saw NO indication that work was
      // currently happening. The optimistic flag is set by
      // markSessionSending on send/inject and auto-clears after
      // _SENDING_TIMEOUT_MS — long enough to bridge most agent turns.
      // CCC-181: the optimistic-sending flag bridges WIP for up to 5min after
      // a send/inject, but it was only ever cleared when a live TOOL landed —
      // never when the turn simply FINISHED. So an injected session that
      // completed (or went to "waiting") kept flashing WIP for minutes. The
      // bridge is only needed until the SERVER reflects the turn: once it has
      // stamped a definitive `state` (idle/waiting/working/ended), trust that
      // and drop the optimistic override. While `state` is still unknown
      // (brand-new send, server hasn't scanned yet) the bridge still applies.
      const _isOptimisticallySending = sidVal && (!c.state || c.state === 'interactive') && sessionIsOptimisticallySending(sidVal);
      let _isAgentRunning = !!c.pending_spawn
        || _hasLivePendingTool
        || _codexOpenTurn
        || _codexStateWorking
        || _geminiOpenTurn
        || _cursorOpenTurn
        || _antigravityOpenTurn
        || _claudeWipFromSidecar
        || _isOptimisticallySending;
      // Final sanity gate: if the agent's last event was a `result`
      // (turn-finished marker) AND the row hasn't seen any new activity
      // in the last 60s AND we don't have a fresh optimistic-send tag,
      // the agent is genuinely idle. Suppress WIP regardless of stale
      // pending_tool / sidecar_tool fields that the server forgot to
      // clear — those let the row show "Shell" or "Bash" indefinitely
      // even though no work was running (user-reported).
      if (
        _isAgentRunning
        && !_isOptimisticallySending
        && !c.pending_spawn
        && c.last_event_type === 'result'
        && _rowActivityAge > 60
      ) {
        _isAgentRunning = false;
      }
      if (_isAgentRunning) {
        rel = c.sidecar_ts ? relativeTime(c.sidecar_ts) : 'now';
      }
      if (_hasStaleToolCall && !liveToolHtml) {
        const stuckTool = _knownActivityTool || 'tool call';
        const stuckAge = c.pending_tool_ts ? relativeTime(c.pending_tool_ts) : (c.stale_tool_age_s ? Math.floor(c.stale_tool_age_s / 60) + 'm' : '');
        const stuckTitle = 'Codex has not logged a result for ' + stuckTool
          + (stuckAge ? ' for ' + stuckAge : '')
          + '. Use Wake to nudge it.';
        signals += '<span class="conv-signal codex-stuck" title="' + escapeHtml(stuckTitle) + '">stuck</span>';
      } else if (!liveToolHtml && _isWaitingForUser && !_isAgentRunning) {
        // Agent has stopped and is blocked on user input — distinct
        // chip + tooltip + class so it doesn't masquerade as live work.
        // Only AskUserQuestion gets the louder QUESTION label; every
        // other "needs_approval" case is just generic "Claude is
        // waiting for your input" (the sidecar type is usually empty),
        // so labeling them APPROVE? was misleading — the agent isn't
        // asking for tool permission, it's asking "what next?".
        const waitTitle = c.question_text
          ? c.question_text
          : (c.needs_approval_message || c.sidecar_file || 'Agent is paused waiting for your input');
        const waitLabel = _isQuestionWaiting ? 'QUESTION' : 'WAITING';
        signals += '<span class="conv-signal activity-waiting" title="' + escapeHtml(waitTitle) + '">' + escapeHtml(waitLabel) + '</span>';
      } else if (_isAgentRunning && !liveToolHtml) {
        const wipTitle = _knownActivityTool
          ? ((c.sidecar_in_flight ? 'Currently running' : 'Last known tool') + ': ' + _knownActivityTool)
          : (isCodexRow ? 'Codex is working' : (isGeminiRow ? 'Gemini is working' : (isCursorRow ? 'Cursor is working' : (isAntigravityRow ? 'Antigravity is working' : 'Agent is working'))));
        const wipLabel = (_codexOpenTurn || _codexStateWorking || _geminiOpenTurn || _cursorOpenTurn || _antigravityOpenTurn) ? 'WIP' : (_knownActivityTool || 'WIP');
        signals += '<span class="conv-signal activity-working" title="' + escapeHtml(wipTitle) + '">' + escapeHtml(wipLabel) + '</span>';
      } else if (c.gh_in_progress && !liveToolHtml) {
        // Calmer "issue is in progress" chip — distinct from live WIP so
        // the row doesn't masquerade as actively running. Uses a muted
        // class (.gh-in-progress) instead of .activity-working.
        signals += '<span class="conv-signal gh-in-progress" title="Linked GitHub issue carries the claude-in-progress label">issue: in progress</span>';
      }
      const _showGitStateSignals = !_rowsCompactOn;
      if (c.source === 'pkood') {
        const ps = (c.pkood_status || '').toUpperCase();
        if (ps === 'RUNNING') signals += '<span class="conv-signal pkood-running">running</span>';
        else if (ps === 'IDLE') signals += '<span class="conv-signal pkood-idle">idle</span>';
        else if (ps === 'BLOCKED') signals += '<span class="conv-signal pkood-blocked">blocked</span>';
        if (c.pkood_is_stuck) signals += '<span class="conv-signal pkood-stuck">stuck</span>';
      } else if (c.spawn_failed) {
        signals += '<span class="conv-signal spawn-failed" title="' + escapeHtml(c.spawn_error || 'Spawn process exited before a session was created') + '">failed</span>';
      } else if (_showGitStateSignals && isWorktree && c.worktree_dirty) {
        signals += '<span class="conv-signal uncommitted" title="git status: this worktree has uncommitted changes">uncommitted</span>';
      } else if (_showGitStateSignals && c.tail_pr_number) {
        // Any session with a PR: surface it instead of the generic
        // committed/pushed chip — the PR is the actionable signal.
        // State-aware styling: merged → purple ✓, open → cyan ↗, closed
        // → muted ×. Falls back to neutral "pushed" if pr_state hasn't
        // been resolved yet (gh fetch in flight, missing, or errored).
        const ps = (c.pr_state || '').toUpperCase();
        let prCls, prGlyph, prTitle;
        if (ps === 'MERGED') {
          prCls = 'pr-merged'; prGlyph = '✓ '; prTitle = 'PR merged';
        } else if (ps === 'CLOSED') {
          prCls = 'pr-closed'; prGlyph = '× '; prTitle = 'PR closed without merge';
        } else if (ps === 'OPEN') {
          prCls = 'pr-open';   prGlyph = '↗ '; prTitle = 'PR open';
        } else {
          prCls = 'pushed';    prGlyph = '';   prTitle = 'PR opened by this session';
        }
        // For github_pr rows: make the chip a button that opens GitHub directly
        // (the row click now opens an in-pane PR detail, not GitHub).
        if (isGithubPrRow && c.tail_pr_url) {
          signals += '<button type="button" class="conv-signal ' + prCls + '" data-role="pr-external-link" data-pr-url="' + escapeAttr(c.tail_pr_url) + '" title="Open PR #' + c.tail_pr_number + ' on GitHub ↗">' + prGlyph + 'PR #' + c.tail_pr_number + ' ↗</button>';
        } else {
          signals += '<span class="conv-signal ' + prCls + '" title="' + prTitle + '">' + prGlyph + 'PR #' + c.tail_pr_number + '</span>';
        }
        if (Array.isArray(c.pr_notes)) {
          for (const note of c.pr_notes) {
            if (!note || !note.label) continue;
            const noteCls = note.kind === 'danger' ? 'pr-note-danger' : 'pr-note';
            signals += '<span class="conv-signal ' + noteCls + '" title="' + escapeHtml(note.title || note.label) + '">' + escapeHtml(note.label) + '</span>';
          }
        }
      } else if (_showGitStateSignals && c.has_push) {
        signals += '<span class="conv-signal pushed">pushed</span>';
      } else if (_showGitStateSignals && c.has_commit) {
        signals += '<span class="conv-signal committed">committed</span>';
      } else if (_showGitStateSignals && hasReadOnlyWork(c)) {
        signals += '<span class="conv-signal read-only" title="Agent completed read-only work without file edits">read-only</span>';
      } else if (_showGitStateSignals && hasNoEdits(c)) {
        signals += '<span class="conv-signal no-edits" title="Agent has not edited any files in this session">no edits</span>';
      }

      // Merge button: shown when this row plausibly has an open PR.
      // Strong signal: tail_pr_number (extracted from `gh pr create` output).
      // Weak fallback: pushed + a non-default feature branch — gh resolves
      // the PR by branch on click; if there is none, the toast surfaces it.
      const _MERGE_PROTECTED_BRANCHES = ['main', 'master', 'develop', 'trunk'];
      const _hasFeatureBranch = !!branchValue
        && _MERGE_PROTECTED_BRANCHES.indexOf(branchValue) === -1;
      const _showMerge = c.source !== 'pkood' && !c.archived
        && (!!c.tail_pr_number || (!!c.has_push && _hasFeatureBranch));
      const _mergeTitle = c.tail_pr_number
        ? 'Squash-merge PR #' + c.tail_pr_number
        : 'Squash-merge PR for ' + branchValue;
      const mergeBtn = _showMerge
        ? '<button class="conv-merge-btn" data-role="merge" title="' + escapeHtml(_mergeTitle) + '">&#128256;</button>'
        : '';
      const wakeBtn = (isCodexRow && c.stale_tool_call && !c.archived && !c.verified)
        ? '<button class="conv-wake-btn" data-role="wake-codex" title="Wake Codex with a status check" aria-label="Wake Codex">&#8635;</button>'
        : '';
      const elevateObjectBtn = (opts.elevateToObject && !isBacklogRow && !isGithubPrRow)
        ? '<button class="conv-elevate-object-btn" data-role="elevate-to-object"'
          + ' data-conv-id="' + escapeAttr(c.id) + '"'
          + ' title="Elevate to its own object" aria-label="Elevate to its own object">&#8593;</button>'
        : '';

      let startBtn = '';
      let archiveBtn;
      const pinTitle = c.pinned ? 'Unpin conversation' : 'Pin conversation';
      const pinBtn = '<button class="conv-pin-btn' + (c.pinned ? ' is-unpin' : '') + '" data-role="pin" title="' + pinTitle + '" aria-label="' + pinTitle + '"><span class="conv-pin-glyph">&#128204;</span></button>';
      if (isBacklogRow) {
        const _issueAttr = escapeAttr(c.issue_number || '');
        const _titleAttr = escapeAttr(c.display_name || c.ai_title || c.first_message || '');
        // Issue rows carry their concrete repo so the spawn handler can target
        // the right folder without relying on server state.
        const _spawnCwdAttr = escapeAttr(c.spawn_cwd || c.folder_path || '');
        startBtn = '<button class="conv-start-btn" data-role="start" data-issue="' + _issueAttr + '" data-title="' + _titleAttr + '" data-spawn-cwd="' + _spawnCwdAttr + '" title="Spawn a session to work on this issue" aria-label="Start issue session">&#9654;</button>';
        archiveBtn = '<button class="conv-archive-btn is-close" data-role="archive" title="Archive issue (close as not planned)" aria-label="Archive issue">&#128229;</button>';
      } else if (isGithubPrRow) {
        archiveBtn = '';
      } else {
        // Archiving moves the session into the Trash section, but this control
        // performs the reversible archive action rather than permanent deletion.
        archiveBtn = c.archived
          ? '<button class="conv-archive-btn is-restore" data-role="archive" title="Restore to Active" aria-label="Restore to Active"><span class="conv-archive-glyph">&#8617;</span><span class="conv-archive-label">Restore</span></button>'
          : '<button class="conv-archive-btn" data-role="archive" title="Archive session" aria-label="Archive session">&#128229;</button>';
      }
      // CCC-467 follow-up: the transcript-size badge ("3MB") was dropped from
      // the meta row — it wrapped onto a second line and is redundant with the
      // size shown in the status rail (#statusRailSize, see CCC-280/CCC-475).
      const rowSizeHtml = '';
      // Suppressed when the row sits under a folder
      // group header that already labels the folder — chip would be noise.
      const folderChipHtml = (c.folder_label_chip && !opts.suppressFolderChip)
        ? '<span class="conv-folder-chip' + (c.folder_chip_orphan ? ' is-orphan' : '')
            + '" style="--chip-hue:' + (c.folder_chip_hue | 0) + ';"'
            + ' title="' + escapeHtml(c.folder_path || c.session_cwd || '') + '">'
            + escapeHtml(c.folder_label_chip) + '</span>'
        : '';
      // Worktree badge — shown when the session came from a sibling worktree
      // dir (e.g. "claude-command-center-wt-gemini" → badge shows "wt-gemini").
      const worktreeBadgeHtml = c.worktree_label
        ? '<span class="conv-wt-badge" title="Worktree: wt-' + escapeAttr(c.worktree_label) + '">wt-' + escapeHtml(c.worktree_label) + '</span>'
        : '';

      // Pin indicator — shown when the row's repo bucket has been
      // overridden by the user. Click unpins via /api/repo/pin.
      const pinnedHtml = c.pinned_repo
        ? '<button class="conv-repo-pin" data-role="unpin-repo" title="Pinned to this repo. Click to reset to the session’s real repo.">repo</button>'
        : '';

      // History-search match indicators. `_historySnippet` (with HTML <mark>
      // already embedded) is set when this session was matched by the
      // claude-index FTS5 backend in addition to / instead of the local
      // session-list filter. Badge renders as a sibling of `.conv-title`
      // so the rename flow that reads the title's textContent doesn't
      // scoop the badge text into the edit box; the snippet previews why
      // the row matched.
      // Differentiate semantic vs lexical hits: "semantic history" badge
      // (purple) appears when this row matched via the vector path (vec or
      // fused). "history" (blue) for lexical-only.
      const _historyIsSemantic = c._historySource === 'vec' || c._historySource === 'fused';
      const _historyIsRecall = c._historySource === 'recall';
      const _historyBadgeClass = _historyIsSemantic ? ' is-semantic' : (_historyIsRecall ? ' is-recall' : '');
      const _historyBadgeLabel = _historyIsRecall ? 'TR' : (_historyIsSemantic ? 'semantic history' : 'history');
      const _historyBadgeTitle = _historyIsRecall
        ? 'Matched by Total Recall'
        : 'Matched in conversation history' + (_historyIsSemantic ? ' (semantic)' : '');
      const historyBadgeHtml = c._historyMatch
        ? '<span class="conv-history-badge' + _historyBadgeClass + '" title="' + escapeAttr(_historyBadgeTitle) + '">' + _historyBadgeLabel + '</span>'
        : '';
      const repoBadgeHtml = c._repoSearchMatch
        ? '<span class="conv-history-badge" title="Matched repo search; showing latest sessions from ' + escapeHtml(c._repoSearchLabel || 'repo') + '">repo</span>'
        : '';
      const historySnippetHtml = c._historySnippet
        ? '<div class="conv-history-snippet is-search-result">' + c._historySnippet + '</div>'
        : '';

      const ctxPct = _convRowContextPct(c);
      let pctBadgeHtml = '';
      let pctBadgeRowActionHtml = '';
      if (ctxPct) {
        const tip = ctxPct.source + ' ' + ctxPct.displayTokens.toLocaleString() + ' / ' + ctxPct.limit.toLocaleString() + ' tokens — click to run /compact';
        const pctLevel = ctxPct.pct > 60 ? ' is-danger' : (ctxPct.pct > 30 ? ' is-warn' : '');
        // Tagged as an action target so the delegated click handler can
        // offer /compact without scooping the surrounding row click.
        const _pctBadge = tabIndex => '<span class="conv-pct-badge is-actionable' + pctLevel + '"'
          + ' role="button" tabindex="' + tabIndex + '"'
          + ' data-role="conv-pct-compact"'
          + ' data-pct="' + ctxPct.pct + '"'
          + ' title="' + escapeAttr(tip) + '">' + ctxPct.pct + '%</span>';
        pctBadgeHtml = _pctBadge(0);
        // Second copy, rendered as the first item INSIDE the hover action
        // bar (CCC-449): the absolutely-positioned bar extends left over the
        // main-row badge on wide button sets, so CSS fades the main-row copy
        // on hover and this one keeps click-to-/compact reachable (CCC-295).
        // tabindex -1 so rows don't grow a duplicate tab stop.
        pctBadgeRowActionHtml = _pctBadge(-1);
      }
      const qcBadgeHtml = pctBadgeHtml ? _convRowQualityBadge(c) : '';
      // Context-utilized % is rendered in the always-visible main row, just left
      // of the elapsed-time slot (see pctBadgeHtml placement below) — it's too
      // important to hide in the hover row or bury in the branch slot. (CCC-294)
      const branchSlotHtml = worktreeBadgeHtml + branch;
      const sessionIdChipHtml = sidebarSessionIdChipHtml(c);
      const objectChipHtml = flowObjectChipHtml(c);
      // Current-goal chip — codex sessions only (the native `/goal` feature,
      // read server-side from ~/.codex/goals_1.sqlite into c.goal). Status
      // colors mirror codex's enum: active=green, complete=muted, anything
      // else (paused/blocked/usage_limited/budget_limited) = amber. Truncated
      // by CSS; full objective + status in the tooltip.
      let goalChipHtml = '';
      const _goalText = (c.goal || '').trim();
      let _gui = null;
      let _gcls = '';
      let _gTip = '';
      if (_goalText) {
        const _gs = (c.goal_status || '').trim();
        _gui = goalStatusUi(_gs);
        _gcls = ' ' + _gui.className;
        _gTip = 'Goal' + (_gs ? ' (' + _gs + ')' : '') + ': ' + _goalText;
        goalChipHtml = '<span class="conv-goal' + _gcls + '" data-role="goal" title="'
          + escapeAttr(_gTip) + '">'
          + '<span class="conv-goal-icon" aria-hidden="true">' + _gui.iconHtml + '</span>'
          + '<span class="conv-goal-text">' + escapeHtml(_goalText) + '</span>'
          + '</span>';
      }
      const goalIconHtml = _goalText && goalIconOnly
        ? '<span class="conv-goal-icon-only' + _gcls + '" title="' + escapeAttr(_gTip) + '"'
          + ' aria-label="' + escapeAttr(_gTip) + '">' + _gui.iconHtml + '</span>'
        : '';
      const goalMetaHtml = goalIconOnly ? '' : goalChipHtml;
      const evergreenGoalHtml = opts.evergreenAgent ? goalChipHtml : '';
      let evergreenStateHtml = '';
      if (opts.evergreenAgent) {
        const _evergreenStateLabel = _isAgentRunning ? 'WIP' : (_isWaitingForUser ? 'waiting' : 'idle');
        const _evergreenStateCls = _isAgentRunning ? ' is-wip' : (_isWaitingForUser ? ' is-waiting' : ' is-idle');
        const _evergreenStateTitle = (_isAgentRunning ? 'WIP' : (_isWaitingForUser ? 'Waiting for input' : 'Not WIP'))
          + (rel ? ' · last run ' + rel : '');
        evergreenStateHtml = '<span class="conv-evergreen-state' + _evergreenStateCls
          + '" title="' + escapeAttr(_evergreenStateTitle) + '">'
          + escapeHtml(_evergreenStateLabel) + '</span>';
      }
      const rowMetaHtml = (liveToolHtml || signals)
        ? '<span class="conv-row-meta">'
          + '<span class="conv-status-slot">' + liveToolHtml + signals + '</span>'
          + '</span>'
        : '';
      // Hover meta row — chip order: object → folder → session-id → goal → others.
      // Suppress object chip when rows are already grouped under an object header
      // (elevateToObject = by-objects sidebar mode — the chip would be noise).
      // Dedupe: if the object title matches the folder label exactly (case-insensitive),
      // drop the folder chip — they're showing the same thing.
      const _hmObj = flowObjectForConversation(c);
      const _hmObjTitle = _hmObj ? String(_hmObj.title || '').trim() : '';
      const _hmObjectChip = opts.elevateToObject ? '' : objectChipHtml;
      const _hmFolderChip = (folderChipHtml && _hmObjTitle && c.folder_label_chip
        && _hmObjTitle.toLowerCase() === String(c.folder_label_chip).toLowerCase())
        ? '' : folderChipHtml;
      // Brief disclosure chevron — only for rows that have a did brief.
      // _briefExpandedRows is loaded once per render from localStorage.
      const _briefSid = c.session_id || c.id || '';
      const _briefDid = (!isBacklogRow && !isGithubPrRow && c.session_state && c.session_state.did)
        ? String(c.session_state.did).trim() : '';
      const _hasBrief = !!_briefDid;
      const _briefOpen = _hasBrief && _briefExpandedRows.has(_briefSid);
      const _briefChevronHtml = _hasBrief
        ? '<button type="button" class="conv-brief-chevron" data-role="brief-toggle"'
          + ' data-brief-sid="' + escapeHtml(_briefSid) + '"'
          + ' title="Show / hide brief" aria-expanded="' + (_briefOpen ? 'true' : 'false') + '">'
          + (_briefOpen ? '&#9662;' : '&#9656;') + '</button>'
        : '';
      // Meta row: always shown when there are chips or a brief chevron.
      const _hasMetaContent = !opts.evergreenAgent && (_hmObjectChip || _hmFolderChip || sessionIdChipHtml || goalMetaHtml || pinnedHtml || rowSizeHtml || branchSlotHtml || _hasBrief);
      const hoverMetaRowHtml = _hasMetaContent
        ? '<div class="conv-hover-meta-row">'
          + _briefChevronHtml
          + _hmObjectChip
          + _hmFolderChip
          + sessionIdChipHtml
          + goalMetaHtml
          + pinnedHtml
          + (rowSizeHtml || '')
          + (branchSlotHtml ? '<span class="conv-branch-slot">' + branchSlotHtml + '</span>' : '')
          + '</div>'
        : '';

      const groupedRowClass = opts.suppressFolderChip ? ' is-grouped-row' : '';
      const evergreenRowClass = opts.evergreenAgent ? ' is-evergreen-agent-row' : '';
      // Single-line evergreen variant (TRIGGERED WORKERS queue rows): name + the
      // same badges (state / quality / context %) + last-active time all on one
      // line, instead of a title line plus a separate meta line. Scoped flag so
      // the project-tree evergreen rows (evergreenAgent without this flag) are
      // unaffected. Reuses the exact badge markup — just moves it inline.
      const _egSingleLine = !!(opts.evergreenAgent && opts.evergreenSingleLine);
      const evergreenSingleLineClass = _egSingleLine ? ' is-evergreen-single-line' : '';
      const currentChildDepth = Math.max(0, Math.min(4, Number(opts.currentChildDepth || 0) || 0));
      const currentChildRowClass = currentChildDepth > 0 ? ' is-current-child-row' : '';
      const currentChildStyle = currentChildDepth > 0
