      const _evergreenBadgesInner = evergreenGoalHtml
        + uxFixesQueueProgressHtml
        + evergreenStateHtml
        + rowMetaHtml
        + cooStatusHtml
        + cooEscalatedHtml
        + (qcBadgeHtml || '')
