    // fall into a trailing flat list.
    const _shouldGroupByObjects = _ipGrouping === 'objects';
    const _currentSessionsMode = (() => {
      try { return localStorage.getItem('ccc-current-sessions-mode') === 'objects' ? 'objects' : 'time'; }
      catch (_) { return 'time'; }
    })();
