          + '<button class="ceq-add-btn" type="button" data-ceq-add-queue="' + escapeAttr(label) + '" title="Add a ticket to ' + escapeAttr(label) + '" aria-label="Add ticket to ' + escapeAttr(label) + '">+</button>'
