        +   '<button type="button" class="conv-archived-gc-unarchive-btn"'
        +     ' data-role="archived-gc-unarchive"'
        +     ' data-gc-id="' + escapeHtml(gcId) + '"'
        +     ' data-gc-path="' + escapeHtml(gc.path_tilde) + '"'
