      +     '</div>'
      +     answerSectionHtml
      +     commentSectionHtml
      +     reopenSectionHtml
      +     closeSectionHtml
      +   '</div>'
      +   '<aside class="uxq-td-sidebar">' + sideHtml + '</aside>'
      + '</div>'
      + '<div class="uxq-td-footer">'
      +   '<div class="uxq-td-footer-meta">'
