  let whatsNewActiveId = WHATS_NEW_FEATURES[0].id;
  let whatsNewVersion = '';

  function whatsNewRenderMenu() {
    if (!$whatsNewMenu) return;
    $whatsNewMenu.innerHTML = WHATS_NEW_FEATURES.map(f => {
      const activeClass = f.id === whatsNewActiveId ? ' active' : '';
      return '<button class="whats-new-menu-item' + activeClass + '" data-id="' + f.id + '" type="button" role="tab" aria-selected="' + (f.id === whatsNewActiveId) + '">' +
        '<span class="menu-item-title">' + f.title + '</span>' +
        '<span class="menu-item-date">' + f.date + '</span>' +
        '</button>';
    }).join('');

    // Add click listeners to menu items
    const items = $whatsNewMenu.querySelectorAll('.whats-new-menu-item');
    items.forEach(el => {
      el.addEventListener('click', () => {
        whatsNewActiveId = el.getAttribute('data-id');
        whatsNewRenderMenu();
        whatsNewRenderFeature(whatsNewActiveId);
      });
    });
  }

  function whatsNewRenderFeature(id) {
    if (!$whatsNewContent) return;
    const f = WHATS_NEW_FEATURES.find(item => item.id === id);
    if (!f) return;

    $whatsNewContent.innerHTML =
      '<div class="whats-new-header-row">' +
        '<span class="whats-new-pill">' + f.tag + '</span>' +
        '<span class="whats-new-feature-date">' + f.date + '</span>' +
      '</div>' +
      '<h2 class="whats-new-feature-title" id="whatsNewTitle">' + f.title + '</h2>' +
      '<div class="whats-new-feature-desc">' + f.desc + '</div>' +
      '<div class="whats-new-preview-box">' + f.mockup + '</div>';
  }

  function whatsNewOpenModal() {
    if (!$whatsNewModal) return;
    whatsNewActiveId = WHATS_NEW_FEATURES[0].id;
    whatsNewRenderMenu();
    whatsNewRenderFeature(whatsNewActiveId);
    if ($whatsNewDontShowAgain) $whatsNewDontShowAgain.checked = false;
    $whatsNewModal.classList.add('open');
  }

  function whatsNewCloseModal() {
    if (!$whatsNewModal) return;
    $whatsNewModal.classList.remove('open');
    if (whatsNewVersion) {
      localStorage.setItem('ccc-last-seen-version', whatsNewVersion);
      if ($whatsNewDontShowAgain && $whatsNewDontShowAgain.checked) {
        localStorage.setItem('ccc-whats-new-dismissed-version', whatsNewVersion);
      }
    }
  }

  if ($whatsNewCloseX) $whatsNewCloseX.addEventListener('click', whatsNewCloseModal);
  if ($whatsNewExploreBtn) $whatsNewExploreBtn.addEventListener('click', whatsNewCloseModal);
  if ($whatsNewBackdrop) $whatsNewBackdrop.addEventListener('click', whatsNewCloseModal);
  if ($cccWhatsNewLink) {
    $cccWhatsNewLink.addEventListener('click', (e) => {
      e.preventDefault();
      whatsNewOpenModal();
    });
  }

  document.addEventListener('keydown', (e) => {
    if (e.key === 'Escape' && $whatsNewModal && $whatsNewModal.classList.contains('open')) {
      whatsNewCloseModal();
    }
  });

  // Fetch version and optionally show popup
  (async () => {
    try {
      const r = await fetch('/api/version', { cache: 'no-store' });
      const d = await r.json();
      if (d && d.version) {
        whatsNewVersion = String(d.version);
        const lastSeen = localStorage.getItem('ccc-last-seen-version');
        const dismissedVer = localStorage.getItem('ccc-whats-new-dismissed-version');
        if (lastSeen !== whatsNewVersion && dismissedVer !== whatsNewVersion && !CONV_POPOUT_MODE) {
          whatsNewOpenModal();
        }
      }
    } catch (_) {}
  })();

  // ── Manual server restart ─────────────────────────────────────
  // Settings menu → POST /api/restart → wait for the same port to answer.
  const $restartServerBtn = document.getElementById('restartServerBtn');
  const $restartServerLabel = document.getElementById('restartServerLabel');
  let restartServerPort = '';

  function restartServerSetPort(port) {
    const clean = String(port || '').replace(/[^\d]/g, '');
    restartServerPort = clean;
    if ($restartServerLabel) {
      $restartServerLabel.textContent = 'Restart server' + (clean ? ' (:' + clean + ')' : '');
    }
    if ($restartServerBtn) {
      $restartServerBtn.title = clean
        ? 'Restart the Command Center server on :' + clean
        : 'Restart the Command Center server';
    }
  }

  function restartServerShowOverlay(title, detail) {
    const $overlay = document.getElementById('cccLoadingOverlay');
    const $label = document.getElementById('cccLoadingLabel');
    if (!$overlay) return;
    $overlay.classList.remove('fade-out', 'gone');
    if ($label) {
      $label.innerHTML =
        '<strong>' + title + '</strong>' +
        '<div class="ccc-loading-detail">' + detail + '</div>';
    }
  }

  async function restartServerRefreshPort() {
    restartServerSetPort(window.location.port || '');
    try {
      const r = await fetch('/api/identity', { cache: 'no-store' });
      if (!r.ok) return;
      const data = await r.json();
      if (data && data.port) restartServerSetPort(data.port);
    } catch (_) { /* location.port fallback is good enough */ }
  }

  async function restartServerRun() {
    if (!$restartServerBtn) return;
    if ($settingsPopover) {
      $settingsPopover.classList.remove('open');
      if ($settingsBtn) $settingsBtn.setAttribute('aria-expanded', 'false');
    }
    $restartServerBtn.disabled = true;
    restartServerShowOverlay(
      'Restarting&hellip;',
      'Waiting for the server' + (restartServerPort ? ' on :' + restartServerPort : '') + ' to bind again.'
    );
    try { sessionStorage.setItem('ccc-restarting', '1'); } catch (_) {}

    let postError = null;
    try {
      const r = await fetch('/api/restart', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
      });
      const data = await r.json().catch(() => ({}));
      if (data && data.port) restartServerSetPort(data.port);
      if (!r.ok || !data.ok) {
        postError = new Error((data && data.error) || ('restart failed (' + r.status + ')'));
      }
    } catch (_) {
      // The socket can drop while execvp replaces the process; poll below.
    }

    if (postError) {
      try { sessionStorage.removeItem('ccc-restarting'); } catch (_) {}
      const $overlay = document.getElementById('cccLoadingOverlay');
      if ($overlay) $overlay.classList.add('fade-out', 'gone');
      $restartServerBtn.disabled = false;
      showOpToast('Restart failed: ' + postError.message, 'error');
      return;
    }

    const ok = await updWaitForServer(30);
    if (ok) {
      location.reload();
    } else {
      try { sessionStorage.removeItem('ccc-restarting'); } catch (_) {}
      const $overlay = document.getElementById('cccLoadingOverlay');
      if ($overlay) $overlay.classList.add('fade-out', 'gone');
      $restartServerBtn.disabled = false;
      showOpToast("Server didn't come back within 30s - try reloading manually", 'error');
    }
  }

  if ($restartServerBtn) {
    if (!READER_ONLY_POPOUT) restartServerRefreshPort();
    $restartServerBtn.addEventListener('click', restartServerRun);
  }

  // ── Sidebar refresh split-button ──────────────────────────────
  // Primary action: hard reload (cache-bust via ?_r=<ts>). The caret
  // opens a small menu whose only entry today is "Restart server",
  // which delegates to the same restartServerRun() the settings menu
  // uses.
  const $sidebarRefreshWrap = document.querySelector('.sh-refresh-wrap');
  const $sidebarRefreshBtn = document.getElementById('sidebarRefreshBtn');
  const $sidebarRefreshCaret = document.getElementById('sidebarRefreshCaret');
  const $sidebarRefreshMenu = document.getElementById('sidebarRefreshMenu');
  const $sidebarRestartServerItem = document.getElementById('sidebarRestartServerItem');

  function hideSidebarRefreshMenu() {
    if (!$sidebarRefreshMenu) return;
    $sidebarRefreshMenu.style.display = 'none';
    if ($sidebarRefreshCaret) $sidebarRefreshCaret.setAttribute('aria-expanded', 'false');
  }
  function toggleSidebarRefreshMenu() {
    if (!$sidebarRefreshMenu) return;
    const open = $sidebarRefreshMenu.style.display !== 'none';
    if (open) {
      hideSidebarRefreshMenu();
    } else {
      $sidebarRefreshMenu.style.display = 'block';
      if ($sidebarRefreshCaret) $sidebarRefreshCaret.setAttribute('aria-expanded', 'true');
    }
  }
  if ($sidebarRefreshBtn) {
    $sidebarRefreshBtn.addEventListener('click', () => {
      if ($sidebarRefreshWrap) {
        $sidebarRefreshWrap.classList.add('spinning');
        setTimeout(() => $sidebarRefreshWrap.classList.remove('spinning'), 600);
      }
      const url = new URL(window.location.href);
      url.searchParams.set('_r', String(Date.now()));
      window.location.replace(url.toString());
    });
  }
  if ($sidebarRefreshCaret) {
    $sidebarRefreshCaret.addEventListener('click', (ev) => {
      ev.stopPropagation();
      toggleSidebarRefreshMenu();
    });
  }
  if ($sidebarRestartServerItem) {
    $sidebarRestartServerItem.addEventListener('click', () => {
      hideSidebarRefreshMenu();
      if (typeof restartServerRun === 'function') {
        restartServerRun();
      }
    });
  }
  document.addEventListener('click', (ev) => {
    if (!$sidebarRefreshMenu) return;
    if ($sidebarRefreshMenu.style.display === 'none') return;
    if ($sidebarRefreshWrap && $sidebarRefreshWrap.contains(ev.target)) return;
    hideSidebarRefreshMenu();
  });
  document.addEventListener('keydown', (ev) => {
    if (ev.key === 'Escape' && $sidebarRefreshMenu && $sidebarRefreshMenu.style.display !== 'none') {
      hideSidebarRefreshMenu();
    }
  });

  // ── Page annotations ───────────────────────────────────────────
  // Browser-page MVP: mark a region or element, write a local note, and
  // persist URL/selector/rect/text anchors for agent handoff.
  const $annotationStartBtn = document.getElementById('annotationStartBtn');
  const $annotationScreenBtn = document.getElementById('annotationScreenBtn');
  const $annotationNotesBtn = document.getElementById('annotationNotesBtn');
  let annotationState = null;
  let annTabCaptureStream = null;
  let annTabCapturePending = null;
  let annTabCaptureLastError = null;

  function annCssEscape(value) {
    const s = String(value == null ? '' : value);
    if (window.CSS && typeof window.CSS.escape === 'function') return window.CSS.escape(s);
    return s.replace(/[^a-zA-Z0-9_-]/g, '\\$&');
  }

  function annText(value, maxLen) {
    const s = String(value == null ? '' : value).replace(/\s+/g, ' ').trim();
    if (!maxLen || s.length <= maxLen) return s;
    return s.slice(0, maxLen).trim() + '…';
  }

  function annSelectorFor(el) {
    if (!el || !el.tagName) return '';
    if (el.id) return '#' + annCssEscape(el.id);
    const parts = [];
    let cur = el;
    while (cur && cur.nodeType === 1 && cur !== document.body && cur !== document.documentElement && parts.length < 7) {
      let part = cur.tagName.toLowerCase();
      if (cur.classList && cur.classList.length) {
        part += '.' + Array.from(cur.classList).slice(0, 2).map(annCssEscape).join('.');
      }
      const parent = cur.parentElement;
      if (parent) {
        const sameTag = Array.from(parent.children).filter(ch => ch.tagName === cur.tagName);
        if (sameTag.length > 1) part += ':nth-of-type(' + (sameTag.indexOf(cur) + 1) + ')';
      }
      parts.unshift(part);
      cur = parent;
    }
    return parts.join(' > ') || el.tagName.toLowerCase();
  }

  function annElementText(el) {
    if (!el) return '';
    const tag = (el.tagName || '').toLowerCase();
    if (tag === 'input' || tag === 'textarea') {
      return annText(el.value || el.getAttribute('placeholder') || '', 2000);
    }
    if (tag === 'select') {
      return annText(el.options && el.selectedIndex >= 0 ? el.options[el.selectedIndex].text : '', 2000);
    }
    return annText(el.innerText || el.textContent || '', 2000);
  }

  function annRectObject(rect) {
    return {
      x: Math.round(rect.left * 100) / 100,
      y: Math.round(rect.top * 100) / 100,
      width: Math.round(rect.width * 100) / 100,
      height: Math.round(rect.height * 100) / 100,
    };
  }

  function annElementSummary(el) {
    if (!el || !el.tagName) return {};
    // Capture identifying attributes beyond the bare selector so the worker
    // can anchor on a meaningful element even when the dot lands on a generic
    // container (e.g. #convInputBar): classes, aria-label, title, data-* keys.
    const data = {};
    if (el.dataset) {
      let n = 0;
      for (const k in el.dataset) {
        if (n++ >= 8) break;
        data[k] = annText(el.dataset[k], 80);
      }
    }
    return {
      tag: el.tagName.toLowerCase(),
      id: el.id || '',
      role: el.getAttribute('role') || '',
      selector: annSelectorFor(el),
      href: el.getAttribute('href') || '',
      classes: el.classList ? Array.from(el.classList).slice(0, 8).join(' ') : '',
      aria: el.getAttribute('aria-label') || '',
      title: el.getAttribute('title') || '',
      data,
      text: annText(annElementText(el), 200),
    };
  }

  function annNormalizeRect(a, b) {
    const left = Math.max(0, Math.min(a.x, b.x));
    const top = Math.max(0, Math.min(a.y, b.y));
    const right = Math.min(window.innerWidth, Math.max(a.x, b.x));
    const bottom = Math.min(window.innerHeight, Math.max(a.y, b.y));
    return { x: left, y: top, width: Math.max(0, right - left), height: Math.max(0, bottom - top) };
  }

  function annSelectionRectForElement(el, x, y) {
    if (!el || !el.getBoundingClientRect || el === document.body || el === document.documentElement) {
      return {
        x: Math.max(0, x - 40),
        y: Math.max(0, y - 24),
        width: Math.min(80, window.innerWidth),
        height: Math.min(48, window.innerHeight),
      };
    }
    const r = el.getBoundingClientRect();
    if (r.width < 2 || r.height < 2) {
      return { x: Math.max(0, x - 40), y: Math.max(0, y - 24), width: 80, height: 48 };
    }
    return {
      x: Math.max(0, r.left),
      y: Math.max(0, r.top),
      width: Math.min(r.width, window.innerWidth - Math.max(0, r.left)),
      height: Math.min(r.height, window.innerHeight - Math.max(0, r.top)),
    };
  }

  function annElementAtPoint(x, y) {
    if (!annotationState || !annotationState.overlay) return document.elementFromPoint(x, y);
    const overlay = annotationState.overlay;
    const prev = overlay.style.pointerEvents;
    overlay.style.pointerEvents = 'none';
    let el = null;
    try { el = document.elementFromPoint(x, y); } finally { overlay.style.pointerEvents = prev; }
    return el;
  }

  function annUpdateSelection(rect) {
    if (!annotationState || !annotationState.selectionEl) return;
    const el = annotationState.selectionEl;
    el.style.left = rect.x + 'px';
    el.style.top = rect.y + 'px';
    el.style.width = rect.width + 'px';
    el.style.height = rect.height + 'px';
    el.hidden = false;
  }

  function annUpdateHoverLabel(rect, target) {
    if (!annotationState || !annotationState.hoverLabelEl) return;
    const labelEl = annotationState.hoverLabelEl;
    if (!target || !target.tagName || annotationState.dragging || annotationState.editor) {
      labelEl.hidden = true;
      return;
    }
    const summary = annElementSummary(target);
    const label = summary.selector || summary.tag || 'selected area';
    labelEl.textContent = label.length > 90 ? label.slice(0, 89) + '…' : label;
    const margin = 8;
    let left = rect.x;
    let top = rect.y - 28;
    if (top < margin) top = rect.y + rect.height + margin;
    const maxLeft = window.innerWidth - 280 - margin;
    if (left > maxLeft) left = maxLeft;
    if (left < margin) left = margin;
    labelEl.style.left = left + 'px';
    labelEl.style.top = top + 'px';
    labelEl.hidden = false;
  }

  function annPreviewAtPoint(x, y) {
    if (!annotationState || annotationState.dragging || annotationState.editor) return;
    const target = annElementAtPoint(x, y);
    const rect = annSelectionRectForElement(target, x, y);
    annotationState.hoverElement = target;
    annotationState.hoverRect = rect;
    annUpdateSelection(rect);
    annUpdateHoverLabel(rect, target);
  }

  function annEstimateScreenRect(rect) {
    const outerW = window.outerWidth || window.innerWidth;
    const outerH = window.outerHeight || window.innerHeight;
    const borderX = Math.max(0, (outerW - window.innerWidth) / 2);
    const chromeY = Math.max(0, (outerH - window.innerHeight) - borderX);
    const sx = typeof window.screenX === 'number' ? window.screenX : (window.screenLeft || 0);
    const sy = typeof window.screenY === 'number' ? window.screenY : (window.screenTop || 0);
    const vv = window.visualViewport;
    const vvLeft = vv && typeof vv.offsetLeft === 'number' ? vv.offsetLeft : 0;
    const vvTop = vv && typeof vv.offsetTop === 'number' ? vv.offsetTop : 0;
    const dpr = window.devicePixelRatio || 1;
    return {
      x: Math.round(sx + borderX + rect.x + vvLeft),
      y: Math.round(sy + chromeY + rect.y + vvTop),
      width: Math.round(rect.width),
      height: Math.round(rect.height),
      estimated: true,
      window_screen_x: sx,
      window_screen_y: sy,
      outer_width: outerW,
      outer_height: outerH,
      chrome_border_x: borderX,
      chrome_offset_y: chromeY,
      device_pixel_ratio: dpr,
    };
  }

  function annReleaseTabCaptureStream() {
    annTabCapturePending = null;
    annTabCaptureLastError = null;
    if (!annTabCaptureStream) return;
    try {
      annTabCaptureStream.getTracks().forEach((track) => track.stop());
    } catch (_) {}
    annTabCaptureStream = null;
  }

  function annTabCaptureSupported() {
    // WKWebView in the .app shell does not expose a working getDisplayMedia picker.
    if (typeof isCccMacApp === 'function' && isCccMacApp()) return false;
    return !!(navigator.mediaDevices && typeof navigator.mediaDevices.getDisplayMedia === 'function');
  }

  /** Start getDisplayMedia synchronously (must run inside a user-gesture handler). */
  function annBeginTabCaptureRequest() {
    if (!annTabCaptureSupported()) return null;
    if (annTabCaptureStream) {
      const tracks = annTabCaptureStream.getVideoTracks();
      if (tracks.length && tracks[0].readyState === 'live') {
        return Promise.resolve(annTabCaptureStream);
      }
      annReleaseTabCaptureStream();
    }
    if (annTabCapturePending) return annTabCapturePending;
    annTabCaptureLastError = null;
    const request = navigator.mediaDevices.getDisplayMedia({
      video: {
        displaySurface: 'browser',
        width: { ideal: window.innerWidth },
        height: { ideal: window.innerHeight },
      },
      audio: false,
      preferCurrentTab: true,
      selfBrowserSurface: 'include',
    });
    annTabCapturePending = request
      .then((stream) => {
        annTabCapturePending = null;
        const track = stream.getVideoTracks()[0];
        if (!track) {
          stream.getTracks().forEach((t) => t.stop());
          return null;
        }
        track.addEventListener('ended', annReleaseTabCaptureStream);
        annTabCaptureStream = stream;
        return stream;
      })
      .catch((err) => {
        annTabCapturePending = null;
        annTabCaptureLastError = err;
        return null;
      });
    return annTabCapturePending;
  }

  async function annAcquireTabCaptureStream() {
    const pending = annBeginTabCaptureRequest();
    if (!pending) return null;
    return pending;
  }

  async function annCaptureTabRegionB64(rect) {
    if (!rect || rect.width < 2 || rect.height < 2) return null;
    const pending = annBeginTabCaptureRequest();
    const stream = pending ? await pending : null;
    if (!stream) return null;
    const track = stream.getVideoTracks()[0];
    if (!track || track.readyState !== 'live') return null;
    const video = document.createElement('video');
    video.muted = true;
    video.playsInline = true;
    video.srcObject = stream;
    try {
      await video.play();
      await new Promise((resolve) => {
        if (typeof video.requestVideoFrameCallback === 'function') {
          video.requestVideoFrameCallback(() => resolve());
        } else if (video.readyState >= 2) {
          resolve();
        } else {
          video.addEventListener('loadeddata', () => resolve(), { once: true });
          setTimeout(resolve, 200);
        }
      });
      const vw = video.videoWidth;
      const vh = video.videoHeight;
      if (!vw || !vh) return null;
      const scaleX = vw / window.innerWidth;
      const scaleY = vh / window.innerHeight;
      const sx = Math.max(0, Math.round(rect.x * scaleX));
      const sy = Math.max(0, Math.round(rect.y * scaleY));
      const sw = Math.max(1, Math.min(vw - sx, Math.round(rect.width * scaleX)));
      const sh = Math.max(1, Math.min(vh - sy, Math.round(rect.height * scaleY)));
      const canvas = document.createElement('canvas');
      canvas.width = sw;
      canvas.height = sh;
      const ctx = canvas.getContext('2d');
      if (!ctx) return null;
      ctx.drawImage(video, sx, sy, sw, sh, 0, 0, sw, sh);
      const dataUrl = canvas.toDataURL('image/png');
      const comma = dataUrl.indexOf(',');
      return comma >= 0 ? dataUrl.slice(comma + 1) : null;
    } catch (_) {
      return null;
    } finally {
      video.srcObject = null;
    }
  }

  async function annCaptureRegionB64(rect, element) {
    const dom = await annCaptureDomRegionB64(rect, element);
    if (dom) return dom;
    if (annTabCaptureSupported()) return annCaptureTabRegionB64(rect);
    return null;
  }

  // Walk up the DOM until we find an ancestor at least ~1.8x the area of
  // the annotated element (or +4000px²) so the screenshot includes enough
  // context to recognize where the element sits — a tight 14×14 swatch on
  // its own is meaningless. Cap at 4 levels and clamp to the viewport with
  // a small visual padding so the parent's border is visible.
  function annContextElement(element, rect) {
    if (!element || !rect) return element || null;
    const elArea = Math.max(1, rect.width * rect.height);
    let node = element.parentElement;
    let chosenEl = null;
    let depth = 0;
    while (node && node !== document.body && depth < 4) {
      const pr = node.getBoundingClientRect();
      const prArea = pr.width * pr.height;
      if (prArea >= Math.max(elArea * 1.8, elArea + 4000)) {
        chosenEl = node;
        break;
      }
      node = node.parentElement;
      depth++;
    }
    return chosenEl || element.parentElement || element;
  }

  function annContextRect(element, rect) {
    if (!element || !rect) return rect;
    const chosenEl = annContextElement(element, rect);
    if (!chosenEl || !chosenEl.getBoundingClientRect) return rect;
    const chosen = chosenEl.getBoundingClientRect();
    const pad = 8;
    const x = Math.max(0, Math.floor(chosen.left - pad));
    const y = Math.max(0, Math.floor(chosen.top - pad));
    const width = Math.max(rect.width, Math.min(window.innerWidth - x, Math.ceil(chosen.width + pad * 2)));
    const height = Math.max(rect.height, Math.min(window.innerHeight - y, Math.ceil(chosen.height + pad * 2)));
    return { x, y, width, height };
  }

  function annInlineCloneStyles(src, dst) {
    if (!src || !dst || src.nodeType !== 1 || dst.nodeType !== 1) return;
    try {
      const cs = getComputedStyle(src);
      let cssText = '';
      for (let i = 0; i < cs.length; i++) {
        const prop = cs[i];
        cssText += prop + ':' + cs.getPropertyValue(prop) + ';';
      }
      dst.setAttribute('style', cssText);
    } catch (_) {}
    const srcKids = src.children;
    const dstKids = dst.children;
    for (let i = 0; i < srcKids.length && i < dstKids.length; i++) {
      annInlineCloneStyles(srcKids[i], dstKids[i]);
    }
  }

  function annCaptureDomRegionB64(rect, element) {
    if (!rect || rect.width < 2 || rect.height < 2) return Promise.resolve(null);
    const root = annContextElement(element, rect) || element;
    if (!root || !root.cloneNode || !root.getBoundingClientRect) return Promise.resolve(null);
    const w = Math.max(1, Math.round(rect.width));
    const h = Math.max(1, Math.round(rect.height));
    if (w * h > 6_000_000) return Promise.resolve(null);
    const scale = window.devicePixelRatio || 1;
    const rootRect = root.getBoundingClientRect();
    const offsetX = rect.x - rootRect.left;
    const offsetY = rect.y - rootRect.top;
    const clone = root.cloneNode(true);
    annInlineCloneStyles(root, clone);
    const xhtmlNs = 'http://www.w3.org/1999/xhtml';
    const svgNs = 'http://www.w3.org/2000/svg';
    const wrap = document.createElementNS(xhtmlNs, 'div');
    wrap.setAttribute('xmlns', xhtmlNs);
    const bg = getComputedStyle(root).backgroundColor || getComputedStyle(document.body).backgroundColor || '#0d1117';
    wrap.style.cssText = [
      'margin:0',
      'padding:0',
      'background:' + bg,
      'width:' + Math.ceil(root.scrollWidth) + 'px',
      'height:' + Math.ceil(root.scrollHeight) + 'px',
      'transform:translate(' + (-offsetX) + 'px,' + (-offsetY) + 'px)',
      'transform-origin:top left',
    ].join(';');
    wrap.appendChild(clone);
    const fo = document.createElementNS(svgNs, 'foreignObject');
    fo.setAttribute('width', String(w));
    fo.setAttribute('height', String(h));
    fo.appendChild(wrap);
    const svg = document.createElementNS(svgNs, 'svg');
    svg.setAttribute('xmlns', svgNs);
    svg.setAttribute('width', String(w));
    svg.setAttribute('height', String(h));
    svg.appendChild(fo);
    const svgText = new XMLSerializer().serializeToString(svg);
    return new Promise((resolve) => {
      const img = new Image();
      img.onload = () => {
        try {
          const canvas = document.createElement('canvas');
          canvas.width = Math.round(w * scale);
          canvas.height = Math.round(h * scale);
          const ctx = canvas.getContext('2d');
          if (!ctx) { resolve(null); return; }
          ctx.scale(scale, scale);
          ctx.drawImage(img, 0, 0, w, h);
          const parts = canvas.toDataURL('image/png').split(',');
          resolve(parts[1] || null);
        } catch (_) {
          resolve(null);
        }
      };
      img.onerror = () => resolve(null);
      img.src = 'data:image/svg+xml;charset=utf-8,' + encodeURIComponent(svgText);
    });
  }

  function annBeginPreEditorScreenshotCapture() {
    if (!annotationState || !annotationState.rect) return Promise.resolve(null);
    const contextRect = annContextRect(annotationState.element, annotationState.rect);
    const captureElement = annotationState.element;
    return annCaptureDomRegionB64(contextRect, captureElement)
      .catch(() => null)
      .then((b64) => {
        if (annotationState) annotationState.preEditorScreenshotB64 = b64 || '';
        return b64 || null;
      });
  }

  async function annResolvePreEditorScreenshot() {
    if (annotationState && annotationState.preEditorScreenshotB64) {
      return annotationState.preEditorScreenshotB64;
    }
    if (!annotationState || !annotationState.preEditorScreenshotPromise) return null;
    try { return await annotationState.preEditorScreenshotPromise; }
    catch (_) { return null; }
  }

  function annBuildPayload(note, screenshotB64) {
    const rect = annotationState.rect;
    const element = annotationState.element;
    // Use the element's tight rect for selector / positioning data, but
    // capture the screenshot over a wider context rect so the reader can
    // see where the element lives in the page.
    const contextRect = annContextRect(element, rect);
    const screen = annEstimateScreenRect(contextRect);
    // Snapshot the session's live process state AT ANNOTATION TIME so
    // liveness bugs ("is this headless? is the terminal alive?") arrive with
    // evidence instead of needing reconstruction later.
    const _ls = (typeof liveStatus !== 'undefined' && liveStatus) || {};
    const liveStatusSnapshot = {
      source: (typeof currentSession !== 'undefined' && currentSession && currentSession.source) || '',
      live: !!_ls.live,
      headless_present: !!_ls.headlessPresent,
      headless_pid: _ls.headlessPid || null,
      headless_stale: !!_ls.headlessStale,
      terminal_present: !!_ls.terminalPresent,
      bg_present: !!_ls.bgPresent,
      bg_pid: _ls.bgPid || null,
      tty: _ls.tty || null,
    };
    const caps = (APP_CONFIG && APP_CONFIG.capabilities) || {};
    const canNativeScreenshot = caps.screenshots !== false;
    const payload = {
      note,
      url: window.location.href,
      title: document.title || '',
      session_id: (typeof currentSession !== 'undefined' && currentSession && currentSession.id) || '',
      repo_path: (typeof popoutRepoPath === 'function' && popoutRepoPath()) || '',
      rect,
      viewport_crop: contextRect,
      device_pixel_ratio: screen.device_pixel_ratio || (window.devicePixelRatio || 1),
      screen,
      element: annElementSummary(element),
      live_status: liveStatusSnapshot,
      capture_screen: !screenshotB64 && canNativeScreenshot,
    };
    if (screenshotB64) payload.screenshot_b64 = screenshotB64;
    return payload;
  }

  function annStop() {
    if (!annotationState) return;
    if (annotationState.overlay) annotationState.overlay.remove();
    document.removeEventListener('keydown', annHandleKeydown, true);
    if ($annotationStartBtn) $annotationStartBtn.classList.remove('active');
    if ($annotationFabBtn) $annotationFabBtn.classList.remove('active');
    annotationState = null;
    annReleaseTabCaptureStream();
  }

  function annPositionEditor(editor, rect) {
    const margin = 12;
    const w = Math.min(340, window.innerWidth - margin * 2);
    editor.style.width = w + 'px';
    let left = rect.x + rect.width + margin;
    if (left + w > window.innerWidth - margin) left = Math.min(window.innerWidth - w - margin, rect.x);
    if (left < margin) left = margin;
    let top = rect.y + rect.height + margin;
    const h = editor.offsetHeight || 220;
    if (top + h > window.innerHeight - margin) top = Math.max(margin, rect.y - h - margin);
    editor.style.left = left + 'px';
    editor.style.top = top + 'px';
  }

  async function annRenderPreEditorScreenshotPreview(editor) {
    if (!editor) return;
    const shotPreviewEl = editor.querySelector('.ann-editor-shot-preview');
    const shotPreviewImg = shotPreviewEl && shotPreviewEl.querySelector('img');
    if (!shotPreviewEl || !shotPreviewImg) return;
    const screenshotB64 = await annResolvePreEditorScreenshot();
    if (!annotationState || annotationState.editor !== editor || !screenshotB64) return;
    shotPreviewImg.src = 'data:image/png;base64,' + screenshotB64;
    shotPreviewEl.hidden = false;
    annPositionEditor(editor, annotationState.rect);
  }

  function annOpenNewSessionWithContext(ann, closeFn, errEl) {
    if (!ann) return;
    const text = annContextForClipboard(ann);
    if (!text) return;
    try {
      if (typeof enterNewSessionMode !== 'function') throw new Error('new session mode is unavailable');
      enterNewSessionMode(text);
      if (typeof closeFn === 'function') closeFn();
      showOpToast('Annotation loaded into new session', 'success');
    } catch (err) {
      if (errEl) {
        errEl.textContent = 'Open new session failed: ' + ((err && err.message) || 'unknown');
        errEl.hidden = false;
      }
    }
  }

  function annUxFixesQueuePrompt(ann) {
    return 'Fix the following UX issue based on this annotation:\n\n' + annContextForClipboard(ann);
  }

  // Pre-submit review for "Add to UX fixes queue". Shows EXACTLY what the
  // worker will receive (annUxFixesQueuePrompt), whether a screenshot is
  // attached, and which fields were truncated when stored — plus a Copy
  // button — so nothing is sent blind. Submit forwards to the queue; Cancel
  // aborts (the annotation is already persisted, so nothing is lost).
  function annShowUxFixesPreview(ann, onSubmit) {
    const existing = document.getElementById('annUxPreviewModal');
    if (existing) existing.remove();
    const promptText = annUxFixesQueuePrompt(ann);
    const el = (ann && ann.element) || {};
    // Limits annContextForClipboard applies when building the stored text.
    const trunc = [];
    if ((ann.note || '').length > 2000) trunc.push('note → first 2000 chars');
    if ((el.selector || '').length > 200) trunc.push('selector → 200');
    if ((el.text || '').length > 160) trunc.push('element text → 160');
    if ((ann.url || '').length > 240) trunc.push('URL → 240');
    const hasShot = !!(ann && ann.screenshot_path);
    const shotSrc = hasShot ? ('/api/pasted-image?path=' + encodeURIComponent(ann.screenshot_path)) : '';
    const modal = document.createElement('div');
    modal.id = 'annUxPreviewModal';
    modal.className = 'ann-ux-preview-modal';
    modal.innerHTML =
      '<div class="ann-ux-preview-card">' +
        '<div class="ann-ux-preview-title">Review before adding to UX fixes queue</div>' +
        '<div class="ann-ux-preview-shot">' +
          (hasShot
            ? '<span class="ann-ux-ok">✓ Screenshot attached</span>'
              + '<a href="' + shotSrc + '" target="_blank" rel="noopener">'
              + '<img class="ann-ux-preview-thumb" src="' + shotSrc + '" alt="annotation screenshot"></a>'
            : '<span class="ann-ux-warn">⚠ No screenshot. Use the Screen button for a manual region capture, or paste an image into this prompt before submitting.</span>') +
        '</div>' +
        (trunc.length
          ? '<div class="ann-ux-warn">⚠ Stored truncated: ' + escapeHtml(trunc.join(', ')) + '</div>'
          : '') +
        '<div class="ann-ux-preview-label">Exactly what the worker receives — edit before submitting if needed:</div>' +
        '<textarea class="ann-ux-preview-text" rows="14" spellcheck="false"></textarea>' +
        '<div class="ann-ux-preview-actions">' +
          '<button type="button" class="ann-btn" data-ux-copy>Copy</button>' +
          '<button type="button" class="ann-btn" data-ux-cancel>Cancel</button>' +
          '<button type="button" class="ann-btn ann-primary" data-ux-submit>Submit to queue</button>' +
        '</div>' +
      '</div>';
    document.body.appendChild(modal);
    const textArea = modal.querySelector('.ann-ux-preview-text');
    textArea.value = promptText;
    try { if (typeof attachImagePaste === 'function') attachImagePaste(textArea); } catch (_) {}
    const close = () => { modal.remove(); document.removeEventListener('keydown', onKey, true); };
    const onKey = (e) => { if (e.key === 'Escape') { e.preventDefault(); close(); } };
    document.addEventListener('keydown', onKey, true);
    modal.addEventListener('click', (e) => { if (e.target === modal) close(); });
    modal.querySelector('[data-ux-copy]').addEventListener('click', async () => {
      // Copy the LIVE textarea value — the user may have edited it.
      try { await navigator.clipboard.writeText(textArea.value); showOpToast('Annotation copied', 'success'); }
      catch (_) { try { textArea.select(); document.execCommand('copy'); } catch (e) {} }
    });
    modal.querySelector('[data-ux-cancel]').addEventListener('click', close);
    const submitBtn = modal.querySelector('[data-ux-submit]');
    let submitting = false;
    submitBtn.addEventListener('click', async () => {
      if (submitting) return;
      submitting = true;
      submitBtn.disabled = true;
      submitBtn.textContent = 'Submitting…';
      const edited = textArea.value;
      // Hand the (possibly edited) prompt to the submitter so what the
      // user reviewed is exactly what the worker receives.
      const queued = typeof onSubmit === 'function' && await onSubmit(edited);
      if (queued) {
        close();
        return;
      }
      submitting = false;
      submitBtn.disabled = false;
      submitBtn.textContent = 'Submit to queue';
    });
  }

  async function annOpenUxFixesQueue(ann, closeFn, _errEl, textOverride) {
    if (!ann) return;
    // Require an actionable anchor before sending. A note alone leaves the
    // fix-worker with nothing to locate, so it blocks the ticket and the queue
    // silts up (CCC-396..402). An anchor is at least one of: a CSS selector, a
    // screenshot path, or a URL. Give instant feedback instead of a silent
    // junk ticket; the server enforces the same rule authoritatively.
    const _annSelector = (ann.element && ann.element.selector) || ann.selector || '';
    const _hasAnchor = !!(
      String(_annSelector || '').trim()
      || String(ann.screenshot_path || '').trim()
      || String(ann.url || '').trim()
    );
    if (!_hasAnchor) {
      if (typeof showOpToast === 'function') {
        showOpToast('Annotation needs an element, screenshot, or URL before it can go to the fix queue', 'warn');
      }
      return;
    }
    // Close the editor up front — the user clicked the button and
    // doesn't need to stare at the modal while the fetch is in flight.
    // The annotation is already persisted (persistAnnotation runs
    // before we get here) so closing now doesn't lose it. Feedback —
    // success OR failure — arrives via showOpToast a moment later.
    if (typeof closeFn === 'function') {
      try { closeFn(); } catch (_) {}
    }
    if (typeof showOpToast === 'function') showOpToast('Sending annotation to UX fixes queue…', 'info');
    try {
      const res = await fetch('/api/annotations/ux-fixes-queue', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          annotation_id: ann.id || '',
          text: (typeof textOverride === 'string' && textOverride.trim())
            ? textOverride
            : annUxFixesQueuePrompt(ann),
          note: ann.note || '',
          url: ann.url || '',
          title: ann.title || '',
          selector: (ann.element && ann.element.selector) || ann.selector || '',
          screenshot_path: ann.screenshot_path || '',
          source: 'ccc',
          engine: getSpawnEngine(),
        }),
      });
      const data = await res.json().catch(() => ({}));
      if (!res.ok || !data.ok) throw new Error((data && data.error) || ('HTTP ' + res.status));
      // Optimistically mark the receiving UX-fixes-queue session as
      // sending so its row shows "Sending…" / WIP immediately, just like
      // a user-typed message would. Without this, the inject lands in
      // the target session's terminal but the conv list shows no
      // activity signal until the next sidecar tick — reads as "did
      // anything actually happen?"
      const _targetSid = data.session_id
        || (data.inject && data.inject.session_id)
        || '';
      if (_targetSid && typeof markSessionSending === 'function') {
        markSessionSending(_targetSid);
      }
      if (typeof refreshUxFixesQueueMeta === 'function') {
        refreshUxFixesQueueMeta({ force: true }).catch(() => {});
      }
      showOpToast(
        data.number
          ? ('Queued as UX fix #' + data.number)
          : (data.action === 'spawned' ? 'UX fixes queue session created' : 'Annotation sent to UX fixes queue'),
        'success'
      );
      // When a NEW session was spawned, force-pull the sessions list so
      // the new row appears in the conv sidebar immediately — don't wait
      // for the next poll cycle. Also schedule a few tighter polls so a
      // session created just after the immediate refresh window still
      // surfaces fast.
      if (data.action === 'spawned' && typeof refreshConversationList === 'function') {
        try { refreshConversationList(); } catch (_) {}
        setTimeout(refreshConversationList, 600);
        setTimeout(refreshConversationList, 1500);
        setTimeout(refreshConversationList, 3000);
      }
      try {
        if (typeof refreshArchiveData === 'function') {
          await refreshArchiveData({ force: true });
          const $search = document.getElementById('convSearch');
          if (typeof renderArchiveList === 'function') renderArchiveList($search ? $search.value : '');
        }
      } catch (_) {}
      return true;
    } catch (err) {
      // Modal is already closed; the toast is the only feedback channel
      // left. Use it for both transports (in-page editor + screen-cap).
      showOpToast('UX fixes queue failed: ' + ((err && err.message) || 'unknown'), 'error');
      return false;
    }
  }

  function annShowEditor() {
    if (!annotationState || !annotationState.overlay) return;
    if (annotationState.editor) annotationState.editor.remove();
    const summary = annElementSummary(annotationState.element);
    const editor = document.createElement('div');
    editor.className = 'ann-editor';
    editor.innerHTML =
      '<div class="ann-editor-title">Annotation</div>' +
      '<textarea class="ann-editor-note" rows="4" placeholder="Write a note for Claude…"></textarea>' +
      '<div class="ann-editor-meta">' + escapeHtml(summary.selector || summary.tag || 'selected area') + '</div>' +
      '<div class="ann-editor-shot-preview" hidden><img alt="Annotation screenshot preview"></div>' +
      '<div class="ann-editor-shot-hint" hidden></div>' +
      '<div class="ann-editor-error" hidden></div>' +
      '<div class="ann-editor-actions">' +
        '<button type="button" class="ann-btn" data-ann-enable-shot hidden>Allow screenshot</button>' +
        '<button type="button" class="ann-btn" data-ann-cancel>Cancel</button>' +
        '<button type="button" class="ann-btn" data-ann-open-session>Open new session</button>' +
        // CCC-179: split the single "Add to UX fixes queue" into two — a 1-click
        // "Queue" that enqueues the note as-is, and "Queue + edit" that opens the
        // pre-submit preview to tweak the prompt first (the prior flow).
        '<button type="button" class="ann-btn ann-queue-btn" data-ann-ux-queue title="Edit the prompt before adding to the UX-fixes queue">Queue + edit</button>' +
        '<button type="button" class="ann-btn ann-primary ann-queue-btn" data-ann-ux-queue-now title="Add this annotation to the UX-fixes queue immediately, no edit">Queue</button>' +
        // CCC-171: the standalone "Save" button was redundant — both action
        // buttons above already persist the annotation first (persistAnnotation),
        // and ⌘/Ctrl+Enter still saves a note-only annotation for agent context.
      '</div>';
    annotationState.overlay.appendChild(editor);
    annotationState.editor = editor;
    annPositionEditor(editor, annotationState.rect);
    annRenderPreEditorScreenshotPreview(editor);
    const noteEl = editor.querySelector('.ann-editor-note');
    // Cmd-V image paste in the note (CCC-89): same uploader as the composer
    // — pasted screenshots land as a path token the worker can open.
    try { if (typeof attachImagePaste === 'function') attachImagePaste(noteEl); } catch (_) {}
    const errEl = editor.querySelector('.ann-editor-error');
    // CCC-171: the visible Save button was removed (redundant — the two action
    // buttons persist, and ⌘/Ctrl+Enter saves a note-only annotation). Fall
    // back to a detached <button> so the shared persist flow's busy/label
    // writes and the click wiring below are harmless no-ops when it's absent.
    const saveBtn = editor.querySelector('[data-ann-save]') || document.createElement('button');
    const cancelBtn = editor.querySelector('[data-ann-cancel]');
    const openSessionBtn = editor.querySelector('[data-ann-open-session]');
    const uxQueueBtn = editor.querySelector('[data-ann-ux-queue]');
    const uxQueueNowBtn = editor.querySelector('[data-ann-ux-queue-now]');
    const enableShotBtn = editor.querySelector('[data-ann-enable-shot]');
    const shotHintEl = editor.querySelector('.ann-editor-shot-hint');
    let savedAnnotation = null;
    const annRefreshScreenshotUi = () => {
      const macApp = typeof isCccMacApp === 'function' && isCccMacApp();
      const supported = annTabCaptureSupported();
      const live = !!(annTabCaptureStream
        && annTabCaptureStream.getVideoTracks()[0]
        && annTabCaptureStream.getVideoTracks()[0].readyState === 'live');
      if (shotHintEl) {
        if (macApp) {
          shotHintEl.textContent = 'CCC will try to attach a screenshot automatically. If it does not, use the Screen button for a manual region capture.';
          shotHintEl.hidden = false;
        } else if (supported && !live) {
          shotHintEl.textContent = 'Click “Allow screenshot” and choose this tab in the browser prompt.';
          shotHintEl.hidden = false;
        } else if (supported && live) {
          shotHintEl.textContent = 'Screenshot capture is enabled for this annotation.';
          shotHintEl.hidden = false;
        } else {
          shotHintEl.hidden = true;
        }
      }
      if (enableShotBtn) {
        enableShotBtn.hidden = !supported || live;
      }
    };
    annRefreshScreenshotUi();
    if (enableShotBtn) {
      enableShotBtn.addEventListener('click', () => {
        const pending = annBeginTabCaptureRequest();
        if (!pending) {
          // The WebKit-based native CCC app doesn't expose
          // getDisplayMedia (the browser tab-capture API), so the
          // in-page "Allow screenshot" path can't work here. Direct
          // the user to the topbar "Screen" button instead — that
          // uses the macOS native `screencapture` picker, which works
          // whenever Screen Recording is granted to Claude Command
          // Center in System Settings → Privacy → Screen Recording.
          errEl.innerHTML = 'In-page tab capture is not available in this app shell. '
            + 'Use the <strong>Screen</strong> button at the top right instead — '
            + 'it triggers the macOS area screenshot picker (granted via '
            + '<em>System Settings → Privacy → Screen Recording → Claude Command Center</em>).';
          errEl.hidden = false;
          return;
        }
        pending.then((stream) => {
          annRefreshScreenshotUi();
          if (stream) {
            errEl.hidden = true;
            showOpToast('Screenshot capture enabled', 'success');
          } else {
            const denied = annTabCaptureLastError && annTabCaptureLastError.name === 'NotAllowedError';
            errEl.textContent = denied
              ? 'Tab capture was blocked — allow it in the browser prompt and choose this tab.'
              : 'Tab capture failed — try again.';
            errEl.hidden = false;
          }
        });
      });
    }
    const copySaved = async () => {
      if (!savedAnnotation) return;
      try {
        await navigator.clipboard.writeText(annContextForClipboard(savedAnnotation));
        annStop();
      } catch (_) {
        errEl.textContent = 'Copy failed.';
        errEl.hidden = false;
      }
    };
    const persistAnnotation = async (busyLabel) => {
      if (savedAnnotation) return savedAnnotation;
      const note = noteEl.value.trim();
      if (!note) {
        errEl.textContent = 'Note is required.';
        errEl.hidden = false;
        noteEl.focus();
        return null;
      }
      errEl.hidden = true;
      if (saveBtn) saveBtn.disabled = true;
      if (openSessionBtn) openSessionBtn.disabled = true;
      if (uxQueueBtn) uxQueueBtn.disabled = true;
      if (saveBtn) saveBtn.textContent = busyLabel || 'Saving…';
      const screenshotB64 = await annResolvePreEditorScreenshot();
      const payload = annBuildPayload(note, screenshotB64);
      try {
        const res = await fetch('/api/annotations', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify(payload),
        });
        const data = await res.json().catch(() => ({}));
        if (!res.ok || !data.ok) throw new Error((data && data.error) || ('HTTP ' + res.status));
        // Merge the payload we built (enriched element, live_status) under the
        // server's saved record (id, screenshot_path) so downstream text —
        // preview, queue prompt, copy, new-session — carries the full context
        // even if the server doesn't echo every custom field. Drop the heavy
        // base64 so it doesn't linger on the in-memory annotation.
        savedAnnotation = Object.assign({}, payload, data.annotation || {});
        savedAnnotation.screenshot_warning = (data && data.screenshot_warning) || '';
        delete savedAnnotation.screenshot_b64;
        noteEl.disabled = true;
        if (cancelBtn) cancelBtn.hidden = true;
        if (openSessionBtn) openSessionBtn.disabled = false;
        if (uxQueueBtn) uxQueueBtn.disabled = false;
        if (saveBtn) { saveBtn.disabled = false; saveBtn.textContent = 'Copy'; }
        if (savedAnnotation && savedAnnotation.screenshot_path) {
          showOpToast('Annotation saved with screenshot', 'success');
        } else {
          const warn = (data && data.screenshot_warning)
            || 'No screenshot. Use the Screen button for a manual region capture, or paste an image before queueing.';
          showOpToast('Annotation saved (no screenshot): ' + warn, 'error');
        }
        return savedAnnotation;
      } catch (err) {
        errEl.textContent = 'Save failed: ' + ((err && err.message) || 'unknown');
        errEl.hidden = false;
        saveBtn.disabled = false;
        if (openSessionBtn) openSessionBtn.disabled = false;
        if (uxQueueBtn) uxQueueBtn.disabled = false;
        saveBtn.textContent = 'Save';
        return null;
      }
    };
    const save = async () => {
      if (savedAnnotation) {
        await copySaved();
        return;
      }
      await persistAnnotation('Saving…');
    };
    if (cancelBtn) cancelBtn.addEventListener('click', annStop);
    if (openSessionBtn) {
      openSessionBtn.addEventListener('click', async () => {
        const ann = await persistAnnotation('Saving…');
        if (ann) annOpenNewSessionWithContext(ann, annStop, errEl);
      });
    }
    if (uxQueueBtn) {
      uxQueueBtn.addEventListener('click', async () => {
        const ann = await persistAnnotation('Saving…');
        if (!ann) return;
        // "Queue + edit": show a pre-submit preview (stored text + screenshot +
        // truncation + copy) so the user can tweak the prompt. The annotation is
        // already persisted; the overlay can close, the preview is its own modal.
        annStop();
        annShowUxFixesPreview(ann, (editedText) => annOpenUxFixesQueue(ann, null, errEl, editedText));
      });
    }
    if (uxQueueNowBtn) {
      uxQueueNowBtn.addEventListener('click', async () => {
        const ann = await persistAnnotation('Saving…');
        if (!ann) return;
        // "Queue" (1-click, CCC-179): enqueue immediately with the default
        // prompt — no preview. annOpenUxFixesQueue closes the editor itself.
        annOpenUxFixesQueue(ann, annStop, errEl, null);
      });
    }
    saveBtn.addEventListener('click', save);
    noteEl.addEventListener('keydown', (e) => {
      if ((e.metaKey || e.ctrlKey) && e.key === 'Enter') save();
      e.stopPropagation();
    });
    setTimeout(() => noteEl.focus(), 0);
  }

  function annPointerDown(e) {
    if (!annotationState || e.target.closest('.ann-editor') || e.target.closest('.ann-hud')) return;
    e.preventDefault();
    annotationState.dragging = true;
    annotationState.start = { x: e.clientX, y: e.clientY };
    annotationState.rect = { x: e.clientX, y: e.clientY, width: 1, height: 1 };
    if (annotationState.hoverLabelEl) annotationState.hoverLabelEl.hidden = true;
    if (annotationState.editor) { annotationState.editor.remove(); annotationState.editor = null; }
    annUpdateSelection(annotationState.rect);
    try { annotationState.overlay.setPointerCapture(e.pointerId); } catch (_) {}
  }

  function annPointerMove(e) {
    if (!annotationState) return;
    if (!annotationState.dragging) {
      if (e.target.closest('.ann-editor') || e.target.closest('.ann-hud')) return;
      annPreviewAtPoint(e.clientX, e.clientY);
      return;
    }
    e.preventDefault();
    const rect = annNormalizeRect(annotationState.start, { x: e.clientX, y: e.clientY });
    annotationState.rect = rect;
    annUpdateSelection(rect);
  }

  async function annPointerUp(e) {
    if (!annotationState || !annotationState.dragging) return;
    e.preventDefault();
    annotationState.dragging = false;
    const raw = annNormalizeRect(annotationState.start, { x: e.clientX, y: e.clientY });
    const clicked = raw.width < 8 && raw.height < 8;
    const target = annElementAtPoint(e.clientX, e.clientY);
    annotationState.element = target;
    annotationState.rect = clicked ? annSelectionRectForElement(target, e.clientX, e.clientY) : raw;
    annUpdateSelection(annotationState.rect);
    if (annotationState.hoverLabelEl) annotationState.hoverLabelEl.hidden = true;
    annotationState.preEditorScreenshotPromise = annBeginPreEditorScreenshotCapture();
    // Fire the tab-capture prompt while the click gesture is still active.
    annBeginTabCaptureRequest();
    await annotationState.preEditorScreenshotPromise;
    if (!annotationState) return;
    annShowEditor();
  }

  function annHandleKeydown(e) {
    if (e.key === 'Escape' && annotationState) {
      e.preventDefault();
      annStop();
    }
  }

  function annStart() {
    if (annotationState) { annStop(); return; }
    const overlay = document.createElement('div');
    overlay.className = 'ann-overlay';
    overlay.innerHTML =
      '<div class="ann-hud"><span>Mark area</span><button type="button" class="ann-hud-close" aria-label="Close annotation mode">&times;</button></div>' +
      '<div class="ann-selection" hidden></div>' +
      '<div class="ann-hover-label" hidden></div>';
    document.body.appendChild(overlay);
    annotationState = {
      overlay,
      selectionEl: overlay.querySelector('.ann-selection'),
      hoverLabelEl: overlay.querySelector('.ann-hover-label'),
      editor: null,
      dragging: false,
      start: null,
      rect: null,
      element: null,
      hoverElement: null,
      hoverRect: null,
      preEditorScreenshotPromise: null,
    };
    overlay.addEventListener('pointerdown', annPointerDown);
    overlay.addEventListener('pointermove', annPointerMove);
    overlay.addEventListener('pointerup', annPointerUp);
    overlay.querySelector('.ann-hud-close').addEventListener('click', annStop);
    document.addEventListener('keydown', annHandleKeydown, true);
    if ($annotationStartBtn) $annotationStartBtn.classList.add('active');
    if ($annotationFabBtn) $annotationFabBtn.classList.add('active');
  }

  function annCloseScreenModal() {
    const modal = document.getElementById('annotationScreenModal');
    if (modal) modal.remove();
  }

  function annOpenScreenNote(capture) {
    annCloseScreenModal();
    const modal = document.createElement('div');
    modal.id = 'annotationScreenModal';
    modal.className = 'upd-overlay ann-screen-modal open';
    const imgSrc = 'data:' + (capture.mime || 'image/png') + ';base64,' + capture.image_b64;
    modal.innerHTML =
      '<div class="upd-backdrop" data-ann-screen-close></div>' +
      '<div class="upd-dialog ann-screen-dialog">' +
        '<div class="ann-notes-header">' +
          '<div class="upd-title">Screen Annotation</div>' +
          '<button type="button" class="ann-icon-btn" data-ann-screen-close aria-label="Close screen annotation">&times;</button>' +
        '</div>' +
        '<img class="ann-screen-preview" alt="Selected screen region">' +
        '<textarea class="ann-editor-note" rows="4" placeholder="Write a note for Claude…"></textarea>' +
        '<div class="ann-editor-error" hidden></div>' +
        '<div class="ann-editor-actions">' +
          '<button type="button" class="ann-btn" data-ann-screen-close data-ann-screen-cancel>Cancel</button>' +
          '<button type="button" class="ann-btn" data-ann-screen-open-session>Open new session</button>' +
          '<button type="button" class="ann-btn ann-queue-btn" data-ann-screen-ux-queue>Add to UX fixes queue</button>' +
          '<button type="button" class="ann-btn ann-primary" data-ann-screen-save>Save</button>' +
        '</div>' +
      '</div>';
    document.body.appendChild(modal);
    const previewImg = modal.querySelector('.ann-screen-preview');
    if (previewImg) previewImg.src = imgSrc;
    const noteEl = modal.querySelector('.ann-editor-note');
    try { if (typeof attachImagePaste === 'function') attachImagePaste(noteEl); } catch (_) {}
    const errEl = modal.querySelector('.ann-editor-error');
    const saveBtn = modal.querySelector('[data-ann-screen-save]');
    const cancelBtn = modal.querySelector('[data-ann-screen-cancel]');
    const openSessionBtn = modal.querySelector('[data-ann-screen-open-session]');
    const uxQueueBtn = modal.querySelector('[data-ann-screen-ux-queue]');
    const close = annCloseScreenModal;
    modal.querySelectorAll('[data-ann-screen-close]').forEach(btn => btn.addEventListener('click', close));
    let savedAnnotation = null;
    const copySaved = async () => {
      if (!savedAnnotation) return;
      try {
        await navigator.clipboard.writeText(annContextForClipboard(savedAnnotation));
        close();
      } catch (_) {
        errEl.textContent = 'Copy failed.';
        errEl.hidden = false;
      }
    };
    const persistAnnotation = async (busyLabel) => {
      if (savedAnnotation) return savedAnnotation;
      const note = noteEl.value.trim();
      if (!note) {
        errEl.textContent = 'Note is required.';
        errEl.hidden = false;
        noteEl.focus();
        return null;
      }
      errEl.hidden = true;
      saveBtn.disabled = true;
      if (openSessionBtn) openSessionBtn.disabled = true;
      if (uxQueueBtn) uxQueueBtn.disabled = true;
      saveBtn.textContent = busyLabel || 'Saving…';
      const payload = {
        note,
        source: 'screen-capture',
        url: '',
        title: 'Screen capture',
        session_id: (typeof currentSession !== 'undefined' && currentSession && currentSession.id) || '',
        repo_path: (typeof popoutRepoPath === 'function' && popoutRepoPath()) || '',
        screenshot_b64: capture.image_b64,
      };
      try {
        const res = await fetch('/api/annotations', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify(payload),
        });
        const data = await res.json().catch(() => ({}));
        if (!res.ok || !data.ok) throw new Error((data && data.error) || ('HTTP ' + res.status));
        // Merge the payload we built (enriched element, live_status) under the
        // server's saved record (id, screenshot_path) so downstream text —
        // preview, queue prompt, copy, new-session — carries the full context
        // even if the server doesn't echo every custom field. Drop the heavy
        // base64 so it doesn't linger on the in-memory annotation.
        savedAnnotation = Object.assign({}, payload, data.annotation || {});
        delete savedAnnotation.screenshot_b64;
        noteEl.disabled = true;
        if (cancelBtn) cancelBtn.hidden = true;
        if (openSessionBtn) openSessionBtn.disabled = false;
        if (uxQueueBtn) uxQueueBtn.disabled = false;
        saveBtn.disabled = false;
        saveBtn.textContent = 'Copy';
        showOpToast('Screen annotation saved', 'success');
        return savedAnnotation;
      } catch (err) {
        errEl.textContent = 'Save failed: ' + ((err && err.message) || 'unknown');
        errEl.hidden = false;
        saveBtn.disabled = false;
        if (openSessionBtn) openSessionBtn.disabled = false;
        if (uxQueueBtn) uxQueueBtn.disabled = false;
        saveBtn.textContent = 'Save';
        return null;
      }
    };
    const save = async () => {
      if (savedAnnotation) {
        await copySaved();
        return;
      }
      await persistAnnotation('Saving…');
    };
    if (openSessionBtn) {
      openSessionBtn.addEventListener('click', async () => {
        const ann = await persistAnnotation('Saving…');
        if (ann) annOpenNewSessionWithContext(ann, close, errEl);
      });
    }
    if (uxQueueBtn) {
      uxQueueBtn.addEventListener('click', async () => {
        const ann = await persistAnnotation('Saving…');
        if (ann) annOpenUxFixesQueue(ann, close, errEl);
      });
    }
    saveBtn.addEventListener('click', save);
    noteEl.addEventListener('keydown', (e) => {
      if ((e.metaKey || e.ctrlKey) && e.key === 'Enter') save();
      e.stopPropagation();
    });
    setTimeout(() => noteEl.focus(), 0);
  }

  async function annCaptureScreen() {
    if (!$annotationScreenBtn) return;
    const oldText = $annotationScreenBtn.textContent;
    $annotationScreenBtn.disabled = true;
    $annotationScreenBtn.textContent = 'Drawing…';
    try {
      const res = await fetch('/api/annotations/capture-screen', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ minimize: true }),
      });
      const data = await res.json().catch(() => ({}));
      if (data && data.cancelled) return;
      if (!res.ok || !data.ok || !data.image_b64) {
        throw new Error((data && data.error) || 'screen capture failed');
      }
      annOpenScreenNote(data);
    } catch (err) {
      showOpToast('Screen capture failed: ' + ((err && err.message) || 'unknown'), 'error');
    } finally {
      $annotationScreenBtn.disabled = false;
      $annotationScreenBtn.textContent = oldText;
    }
  }

  function annClipText(value, maxLen) {
    const s = String(value == null ? '' : value).replace(/\s+/g, ' ').trim();
    if (!s || !maxLen || s.length <= maxLen) return s;
    return s.slice(0, maxLen).trim() + '…';
  }

  function annContextForClipboard(ann) {
    const element = ann.element || {};
    const lines = ['Annotation: ' + annClipText(ann.note || '', 2000)];
    const anchors = [];
    if (ann.url) anchors.push('URL: ' + annClipText(ann.url, 240));
    if (ann.session_id) anchors.push('Session ID: ' + ann.session_id);
    if (element.selector) anchors.push('Selector: ' + annClipText(element.selector, 200));
    if (element.text) anchors.push('Element: ' + annClipText(element.text, 160));
    if (element.classes) anchors.push('Classes: ' + annClipText(element.classes, 160));
    if (element.aria) anchors.push('Aria-label: ' + annClipText(element.aria, 120));
    if (element.title) anchors.push('Title: ' + annClipText(element.title, 120));
    if (element.data && Object.keys(element.data).length) {
      const dataStr = Object.keys(element.data).map(k => k + '=' + element.data[k]).join(', ');
      anchors.push('Data-attrs: ' + annClipText(dataStr, 200));
    }
    const ls = ann.live_status;
    if (ls && (ls.source || ls.headless_present || ls.terminal_present || ls.live)) {
      const bits = [];
      if (ls.source) bits.push(ls.source);
      bits.push(ls.live ? 'live' : 'not-live');
      if (ls.headless_present) bits.push('headless' + (ls.headless_pid ? ' pid ' + ls.headless_pid : '') + (ls.headless_stale ? ' (STALE)' : ''));
      if (ls.terminal_present) bits.push('terminal' + (ls.tty ? ' ' + ls.tty : ''));
      if (ls.bg_present) bits.push('Claude-app terminal' + (ls.bg_pid ? ' pid ' + ls.bg_pid : ''));
      if (!ls.headless_present && !ls.terminal_present && !ls.bg_present) bits.push('no headless/terminal process');
      anchors.push('Session state: ' + bits.join(' · '));
    }
    if (ann.screenshot_path) anchors.push('Screenshot: ' + ann.screenshot_path);
    else if (ann.screenshot_warning) anchors.push('Screenshot warning: ' + annClipText(ann.screenshot_warning, 240));
    if (anchors.length) {
      lines.push('', 'Anchors:', anchors.map(v => '- ' + v).join('\n'));
    }
    return lines.join('\n');
  }

  async function annOpenNotes() {
    let modal = document.getElementById('annotationNotesModal');
    if (modal) modal.remove();
    modal = document.createElement('div');
    modal.id = 'annotationNotesModal';
    modal.className = 'upd-overlay ann-notes-modal open';
    modal.innerHTML =
      '<div class="upd-backdrop" data-ann-close></div>' +
      '<div class="upd-dialog ann-notes-dialog">' +
        '<div class="ann-notes-header">' +
          '<div class="upd-title">Annotation Notes</div>' +
          '<button type="button" class="ann-icon-btn" data-ann-close aria-label="Close annotation notes">&times;</button>' +
        '</div>' +
        '<div class="ann-notes-list"><div class="ann-notes-empty">Loading…</div></div>' +
      '</div>';
    document.body.appendChild(modal);
    const list = modal.querySelector('.ann-notes-list');
    const close = () => modal.remove();
    modal.querySelectorAll('[data-ann-close]').forEach(btn => btn.addEventListener('click', close));
    try {
      const res = await fetch('/api/annotations?limit=100', { cache: 'no-store' });
      const data = await res.json().catch(() => ({}));
      if (!res.ok || !data.ok) throw new Error((data && data.error) || ('HTTP ' + res.status));
      const notes = Array.isArray(data.annotations) ? data.annotations : [];
      if (!notes.length) {
        list.innerHTML = '<div class="ann-notes-empty">No annotations yet.</div>';
        return;
      }
      list.innerHTML = notes.map((ann) => {
        const when = ann.created_at ? new Date(ann.created_at).toLocaleString() : '';
        const selector = ann.element && ann.element.selector ? ann.element.selector : 'selected area';
        const urlHtml = ann.url ? '<div class="ann-note-url">' + escapeHtml(ann.url || '') + '</div>' : '';
        const shotUrl = ann.screenshot_path
          ? '/api/local-image?path=' + encodeURIComponent(ann.screenshot_path)
          : '';
        const shot = ann.screenshot_path
          ? '<div class="ann-note-shot">'
            + '<img src="' + escapeAttr(shotUrl) + '" alt="Annotation screenshot" loading="lazy">'
            + '<div class="ann-note-path">' + escapeHtml(ann.screenshot_path) + '</div>'
            + '</div>'
          : '';
        return '<div class="ann-note-row" data-ann-id="' + escapeAttr(ann.id || '') + '">' +
          '<div class="ann-note-main">' +
            '<div class="ann-note-text">' + escapeHtml(ann.note || '') + '</div>' +
            '<div class="ann-note-meta">' + escapeHtml(when) + ' · ' + escapeHtml(selector) + '</div>' +
            urlHtml +
            shot +
          '</div>' +
          '<div class="ann-note-actions">' +
            '<button type="button" class="ann-btn" data-ann-copy="' + escapeAttr(ann.id || '') + '">Copy context</button>' +
            '<button type="button" class="ann-btn" data-ann-ux-queue="' + escapeAttr(ann.id || '') + '">Add to UX fixes queue</button>' +
          '</div>' +
        '</div>';
      }).join('');
      const byId = new Map(notes.map(ann => [ann.id, ann]));
      list.querySelectorAll('[data-ann-copy]').forEach(btn => {
        btn.addEventListener('click', async () => {
          const ann = byId.get(btn.getAttribute('data-ann-copy'));
          if (!ann) return;
          try {
            await navigator.clipboard.writeText(annContextForClipboard(ann));
            btn.textContent = 'Copied';
            setTimeout(() => { btn.textContent = 'Copy context'; }, 1200);
          } catch (_) {
            showOpToast('Copy failed', 'error');
          }
        });
      });
      list.querySelectorAll('[data-ann-ux-queue]').forEach(btn => {
        btn.addEventListener('click', () => {
          const ann = byId.get(btn.getAttribute('data-ann-ux-queue'));
          if (!ann) return;
          annOpenUxFixesQueue(ann, close);
        });
      });
    } catch (err) {
      list.innerHTML = '<div class="ann-notes-empty error">Failed to load annotations: ' + escapeHtml((err && err.message) || 'unknown') + '</div>';
    }
  }

  const $statusRailAnnotateBtn = document.getElementById('statusRailAnnotateBtn');
  if ($statusRailAnnotateBtn) $statusRailAnnotateBtn.addEventListener('click', annStart);
  const $statusRailTitleRenameBtn = document.getElementById('statusRailTitleRenameBtn');
  if ($statusRailTitleRenameBtn) $statusRailTitleRenameBtn.addEventListener('click', (ev) => {
    ev.stopPropagation();
    startStatusRailTitleRename();
  });
  // CCC-467: "+ Object" in the RHS opens the same object-assign picker the
  // per-row "+" chip used to, but for the currently selected session.
  const $statusRailAddObjectBtn = document.getElementById('statusRailAddObjectBtn');
  if ($statusRailAddObjectBtn) $statusRailAddObjectBtn.addEventListener('click', (ev) => {
    ev.stopPropagation();
    const row = _statusRailActiveRow;
    const sid = row && (row.session_id || row.id);
    if (!sid) return;
    const title = (typeof flowRowTitle === 'function' ? flowRowTitle(row) : '') || row.display_name || '';
    _flowOpenObjectAssignPicker(sid, title);
  });
  if ($annotationStartBtn) $annotationStartBtn.addEventListener('click', annStart);
  if ($annotationScreenBtn) $annotationScreenBtn.addEventListener('click', annCaptureScreen);
  if ($annotationNotesBtn) $annotationNotesBtn.addEventListener('click', annOpenNotes);
  // Floating Annotate button for popout windows (CCC-166). The topbar Annotate
  // button is CSS-hidden in a conversation popout; this FAB drives the exact
  // same annStart flow so popped-out sessions get the affordance too. The whole
  // annotation flow (overlay → /api/annotations POST) is self-contained in this
  // window — it does not depend on the main dashboard window being open.
  const $annotationFabBtn = document.getElementById('annotationFabBtn');
  if ($annotationFabBtn) $annotationFabBtn.addEventListener('click', annStart);

  // Per-pane header actions (CCC-474): Annotate + Clear in the split-mode
  // pane titlebar. Clear is VISUAL ONLY — for screen recording a "clean
  // terminal". It stamps a jsonl-line watermark on the pane's view and
  // display:none's everything rendered at or below it; the transcript on
  // disk and the server are never touched. Watermark resets on the next
  // conversation (re)select, so reopening the session shows full history.
  function clearPaneScreenForVideo(paneId) {
    const $view = getConvViewForPane(paneId) || $conversationsView;
    if (!$view) return;
    let maxLine = parseInt($view.dataset.videoClearLine || '0', 10) || 0;
    $view.querySelectorAll('.event[data-jsonl-line]').forEach((el) => {
      const n = parseInt(el.dataset.jsonlLine, 10);
      if (!isNaN(n) && n > maxLine) maxLine = n;
    });
    $view.dataset.videoClearLine = String(maxLine);
    // .tool-call-group too: tool events nest inside group wrappers whose
    // "Ran N commands" header is not itself an .event and would stay visible.
    $view.querySelectorAll('.event, .stream-bubble, .conv-load-earlier, .tool-call-group')
      .forEach((el) => el.classList.add('ccc-video-cleared'));
    $view.classList.add('is-video-cleared');
  }
  document.addEventListener('click', (ev) => {
    const btn = ev.target && ev.target.closest
      ? ev.target.closest('[data-role="pane-annotate"], [data-role="pane-clear"], [data-role="pane-verbose"], [data-role="pane-replay"]') : null;
    if (!btn) return;
    ev.stopPropagation();
    const pane = btn.closest('.conv-pane[data-pane-id]');
    const paneId = (pane && pane.dataset.paneId) || activePaneId();
    if (btn.dataset.role === 'pane-annotate') { annStart(); return; }
    if (btn.dataset.role === 'pane-verbose') { toggleConvVerbose(); return; }
    if (btn.dataset.role === 'pane-replay') { startConvReplay(paneId); return; }
    clearPaneScreenForVideo(paneId);
  });

  // CCC-454: Verbose transcript toggle. Flips the persisted mode, restyles
  // every Verbose button (rail topbar + per-pane copies, incl. cloned split
  // panes — hence querySelectorAll at toggle time), and re-applies expansion
  // state to the conversation DOM already on screen (future renders honor
  // convVerboseOn()).
  function _syncVerboseButtons(on) {
    document.querySelectorAll('#verboseToggleBtn, [data-role="pane-verbose"]')
      .forEach((b) => b.setAttribute('aria-pressed', on ? 'true' : 'false'));
  }
  function toggleConvVerbose() {
    const on = !convVerboseOn();
    try { localStorage.setItem('ccc-conv-verbose', on ? '1' : '0'); } catch (_) {}
    _syncVerboseButtons(on);
    applyConvVerbose(on);
  }
  _syncVerboseButtons(convVerboseOn());
  const $verboseToggleBtn = document.getElementById('verboseToggleBtn');
  if ($verboseToggleBtn) $verboseToggleBtn.addEventListener('click', toggleConvVerbose);

  // ── In-app bug reporting ────────────────────────────────────────
  // Topbar link → modal → POST /api/bug-report → server shells out
  // to `gh issue create`. On gh failure the handler returns the
  // rendered markdown so we can offer a copy-to-clipboard fallback.
  const $bugLink = document.getElementById('bugReportLink');
  const $bugModal = document.getElementById('bugReportModal');
  const $bugBackdrop = document.getElementById('bugReportBackdrop');
  const $bugDescInput = document.getElementById('bugReportDescInput');
  const $bugMeta = document.getElementById('bugReportMeta');
  const $bugError = document.getElementById('bugReportError');
  const $bugSuccess = document.getElementById('bugReportSuccess');
  const $bugFallback = document.getElementById('bugReportFallback');
  const $bugCancelBtn = document.getElementById('bugReportCancelBtn');
  const $bugSubmitBtn = document.getElementById('bugReportSubmitBtn');
  const $bugCopyBtn = document.getElementById('bugReportCopyBtn');
  const $bugShotBtn = document.getElementById('bugReportShotBtn');
  const $bugShotBtnLabel = document.getElementById('bugReportShotBtnLabel');
  const $bugShotPreview = document.getElementById('bugReportShotPreview');
  const $bugShotImg = document.getElementById('bugReportShotImg');
  const $bugShotRetakeBtn = document.getElementById('bugReportShotRetakeBtn');
  const $bugShotRemoveBtn = document.getElementById('bugReportShotRemoveBtn');
  let bugCachedVersion = null;
  let bugFallbackMarkdown = '';
  let bugShotB64 = '';  // raw base64 PNG (no data: prefix), '' when no screenshot

  function bugEscape(s) {
    return String(s == null ? '' : s).replace(/[&<>"']/g, (c) => ({
      '&': '&amp;', '<': '&lt;', '>': '&gt;', '"': '&quot;', "'": '&#39;',
    })[c]);
  }

  async function bugFetchVersion() {
    if (bugCachedVersion) return bugCachedVersion;
    try {
      const r = await fetch('/api/version', { cache: 'no-store' });
      const d = await r.json();
      bugCachedVersion = d && d.version ? String(d.version) : '';
    } catch (_) {
      bugCachedVersion = '';
    }
    return bugCachedVersion;
  }

  async function bugRenderMeta() {
    const version = await bugFetchVersion();
    const ua = (typeof navigator !== 'undefined' && navigator.userAgent) || '';
    const sid = (typeof currentSession !== 'undefined' && currentSession && currentSession.id) || '';
    if (!$bugMeta) return;
    $bugMeta.innerHTML =
      '<div><strong>CCC version:</strong> <code>' + bugEscape(version || '—') + '</code></div>' +
      '<div><strong>Session:</strong> <code>' + bugEscape(sid || '—') + '</code></div>' +
      '<div><strong>User agent:</strong> <code>' + bugEscape(ua || '—') + '</code></div>';
  }

  function bugClearShot() {
    bugShotB64 = '';
    if ($bugShotImg) $bugShotImg.src = '';
    if ($bugShotPreview) $bugShotPreview.classList.remove('visible');
    if ($bugShotBtnLabel) $bugShotBtnLabel.textContent = 'Add screenshot';
    if ($bugShotBtn) $bugShotBtn.disabled = false;
  }

  // Reset only the transient UI chrome (error banner, success banner,
  // fallback markdown, button labels). Leaves user input (the Details
  // textarea and any attached screenshot) intact — used on each submit
  // click to wipe stale messages before the new attempt. The previous
  // version also called bugClearShot() here, which silently dropped
  // attached screenshots from every submission.
  function bugResetMessages() {
    if ($bugError) { $bugError.textContent = ''; $bugError.classList.remove('visible'); }
    if ($bugSuccess) { $bugSuccess.innerHTML = ''; $bugSuccess.classList.remove('visible'); }
    if ($bugFallback) { $bugFallback.textContent = ''; $bugFallback.classList.remove('visible'); }
    if ($bugCopyBtn) $bugCopyBtn.style.display = 'none';
    bugFallbackMarkdown = '';
    if ($bugSubmitBtn) {
      $bugSubmitBtn.disabled = false;
      $bugSubmitBtn.textContent = 'Send report';
    }
    if ($bugCancelBtn) { $bugCancelBtn.disabled = false; $bugCancelBtn.textContent = 'Cancel'; }
  }

  // Full reset for modal open: messages + any attached screenshot.
  // The description textarea is cleared separately in bugOpenModal so
  // bugResetState stays focused on derived UI state.
  function bugResetState() {
    bugResetMessages();
    bugClearShot();
  }

  async function bugCaptureScreenshot() {
    // Hands off to the server, which shells out to `screencapture -i` and
    // blocks until the user finishes drawing or hits Esc. The button stays
    // in a "spinner" state for the entire window so it's clear something
    // is waiting on the user.
    if (!$bugShotBtn) return;
    if ($bugError) { $bugError.textContent = ''; $bugError.classList.remove('visible'); }
    $bugShotBtn.disabled = true;
    if ($bugShotBtnLabel) $bugShotBtnLabel.textContent = 'Drawing…';
    let data;
    try {
      const r = await fetch('/api/bug-report/capture', { method: 'POST' });
      data = await r.json().catch(() => ({}));
    } catch (e) {
      if ($bugError) {
        $bugError.textContent = 'Capture failed: ' + (e && e.message ? e.message : 'unknown');
        $bugError.classList.add('visible');
      }
      bugClearShot();
      return;
    }
    if (data && data.cancelled) {
      // User pressed Esc — they bailed on purpose, no error noise.
      bugClearShot();
      return;
    }
    if (!data || !data.ok || !data.image_b64) {
      if ($bugError) {
        $bugError.textContent = (data && data.error) || 'Could not capture screenshot.';
        $bugError.classList.add('visible');
      }
      bugClearShot();
      return;
    }
    bugShotB64 = data.image_b64;
    if ($bugShotImg) $bugShotImg.src = 'data:' + (data.mime || 'image/png') + ';base64,' + data.image_b64;
    if ($bugShotPreview) $bugShotPreview.classList.add('visible');
    if ($bugShotBtnLabel) $bugShotBtnLabel.textContent = 'Replace screenshot';
    $bugShotBtn.disabled = false;
  }

  if ($bugShotBtn) $bugShotBtn.addEventListener('click', bugCaptureScreenshot);
  if ($bugShotRetakeBtn) $bugShotRetakeBtn.addEventListener('click', bugCaptureScreenshot);
  if ($bugShotRemoveBtn) $bugShotRemoveBtn.addEventListener('click', bugClearShot);

  function bugOpenModal() {
    if (!$bugModal) return;
    bugResetState();
    if ($bugDescInput) $bugDescInput.value = '';
    bugRenderMeta();
    $bugModal.classList.add('open');
    setTimeout(() => { if ($bugDescInput) $bugDescInput.focus(); }, 0);
  }
  function bugCloseModal() {
    if ($bugModal) $bugModal.classList.remove('open');
  }

  if ($bugLink) $bugLink.addEventListener('click', bugOpenModal);
  if ($bugBackdrop) $bugBackdrop.addEventListener('click', bugCloseModal);
  if ($bugCancelBtn) $bugCancelBtn.addEventListener('click', bugCloseModal);
  document.addEventListener('keydown', (e) => {
    if (e.key === 'Escape' && $bugModal && $bugModal.classList.contains('open')) {
      bugCloseModal();
    }
  });

  async function bugSubmit() {
    if (!$bugDescInput) return;
    const desc = $bugDescInput.value.trim();
    // Wipe stale UI chrome but keep the attached screenshot — the user
    // explicitly added it and expects it to ride along with this submit.
    bugResetMessages();
    if (!desc) {
      if ($bugError) { $bugError.textContent = 'Please describe the bug.'; $bugError.classList.add('visible'); }
      $bugDescInput.focus();
      return;
    }
    if ($bugSubmitBtn) {
      $bugSubmitBtn.disabled = true;
      // Sending an image takes a couple of seconds (push to a public branch
      // before gh issue create) — surface that explicitly so the user
      // doesn't think the submit hung.
      $bugSubmitBtn.textContent = bugShotB64 ? 'Sending (uploading screenshot)…' : 'Sending…';
    }
    if ($bugCancelBtn) $bugCancelBtn.disabled = true;
    const version = await bugFetchVersion();
    const sid = (typeof currentSession !== 'undefined' && currentSession && currentSession.id) || '';
    // Server derives the GitHub issue title from the first non-empty line
    // of `description`, so we only send the unified Details field now.
    const payload = {
      description: desc,
      ccc_version: version || '',
      user_agent: (navigator && navigator.userAgent) || '',
      session_id: sid,
    };
    if (bugShotB64) payload.screenshot_b64 = bugShotB64;
    let data;
    try {
      const r = await fetch('/api/bug-report', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(payload),
      });
      data = await r.json().catch(() => ({}));
    } catch (e) {
      if ($bugError) {
        $bugError.textContent = 'Network error: ' + (e && e.message ? e.message : 'unknown');
        $bugError.classList.add('visible');
      }
      if ($bugSubmitBtn) { $bugSubmitBtn.disabled = false; $bugSubmitBtn.textContent = 'Send report'; }
      if ($bugCancelBtn) $bugCancelBtn.disabled = false;
      return;
    }
    if (data && data.ok && data.url) {
      const safeUrl = bugEscape(data.url);
      let html = 'Thanks — issue filed: <a href="' + safeUrl + '" target="_blank" rel="noopener">' + safeUrl + '</a>';
      if (data.screenshot_needs_manual && data.screenshot_path) {
        // Push to bug-screenshots branch failed (typical for OSS users
        // without write access). Show the local path with a clear
        // drag-drop instruction, AND fire-and-forget a /reveal so Finder
        // pops to the file. The user finishes the attachment manually.
        const safePath = bugEscape(data.screenshot_path);
        html += '<div style="margin-top:8px;line-height:1.5;">'
              + 'Screenshot upload failed — saved locally at '
              + '<code style="font-family:\'SF Mono\',monospace;font-size:11px;">' + safePath + '</code>. '
              + 'Drag this file into a comment on the issue to attach it. '
              + 'Finder should be opening to it now.'
              + '</div>';
        try {
          fetch('/api/bug-report/reveal', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ path: data.screenshot_path }),
          });
        } catch (_) { /* best effort */ }
        try { window.open(data.url, '_blank', 'noopener'); } catch (_) {}
      }
      if ($bugSuccess) {
        $bugSuccess.innerHTML = html;
        $bugSuccess.classList.add('visible');
      }
      if ($bugSubmitBtn) { $bugSubmitBtn.disabled = true; $bugSubmitBtn.textContent = 'Sent'; }
      if ($bugCancelBtn) { $bugCancelBtn.disabled = false; $bugCancelBtn.textContent = 'Close'; }
      try { showOpToast('Bug report filed', 'success'); } catch (_) {}
      setTimeout(() => { bugCloseModal(); }, 2000);
      return;
    }
    // Failure path. If the server returned `markdown` we offer a copy-
    // to-clipboard fallback so the user can still file the issue manually.
    const errMsg = (data && data.error) || 'Failed to submit bug report.';
    if ($bugError) {
      let msg = errMsg;
      if (data && data.repo_url) {
        msg += '\n\nFile manually at: ' + data.repo_url;
      }
      $bugError.textContent = msg;
      $bugError.classList.add('visible');
    }
    if (data && data.markdown) {
      bugFallbackMarkdown = String(data.markdown);
      if ($bugFallback) {
        $bugFallback.textContent = bugFallbackMarkdown;
        $bugFallback.classList.add('visible');
      }
      if ($bugCopyBtn) $bugCopyBtn.style.display = 'inline-block';
    }
    if ($bugSubmitBtn) { $bugSubmitBtn.disabled = false; $bugSubmitBtn.textContent = 'Try again'; }
    if ($bugCancelBtn) $bugCancelBtn.disabled = false;
  }

  if ($bugSubmitBtn) $bugSubmitBtn.addEventListener('click', bugSubmit);
  if ($bugCopyBtn) $bugCopyBtn.addEventListener('click', async () => {
    const md = bugFallbackMarkdown;
    if (!md) return;
    try {
      await navigator.clipboard.writeText(md);
      if ($bugCopyBtn) { $bugCopyBtn.textContent = 'Copied'; setTimeout(() => { if ($bugCopyBtn) $bugCopyBtn.textContent = 'Copy markdown'; }, 1500); }
    } catch (_) {
      try { showOpToast('Copy failed — select the text and copy manually', 'error'); } catch (__) {}
    }
  });

  // Spawn defaults modal — the ONLY writer of /api/spawn-defaults. New
  // session / Kanban toolbar dropdowns read this default on load but only
  // mutate in-memory state (setSpawnEngine/setSpawnDefaultModel); a one-off
  // engine pick for a single session must never overwrite the saved default.
  const $spawnDefaultsBtn = document.getElementById('spawnDefaultsBtn');
  const $spawnDefaultsModal = document.getElementById('spawnDefaultsModal');
  const $spawnDefaultsBackdrop = document.getElementById('spawnDefaultsBackdrop');
  const $spawnDefaultsEngine = document.getElementById('spawnDefaultsEngine');
  const $spawnDefaultsModel = document.getElementById('spawnDefaultsModel');
  const $spawnDefaultsOtherModel = document.getElementById('spawnDefaultsOtherModel');
  const $spawnDefaultsError = document.getElementById('spawnDefaultsError');
  const $spawnDefaultsCancelBtn = document.getElementById('spawnDefaultsCancelBtn');
  const $spawnDefaultsSaveBtn = document.getElementById('spawnDefaultsSaveBtn');
  let spawnDefaultsDraft = null;

  function cloneSpawnDefaults() {
    return {
      engine: getSpawnEngine(),
      models: Object.assign({}, spawnDefaultsState.models || {}),
    };
  }
  function spawnDefaultsModalError(text) {
    if (!$spawnDefaultsError) return;
    $spawnDefaultsError.textContent = text || '';
    $spawnDefaultsError.classList.toggle('visible', !!text);
  }
  function renderSpawnDefaultsModelDraft() {
    if (!$spawnDefaultsModel || !spawnDefaultsDraft) return;
    const engine = normalizeSpawnDefaultEngine(spawnDefaultsDraft.engine);
    const currentModel = String((spawnDefaultsDraft.models || {})[engine] || '').trim();
    const options = modelOptionsForSpawnEngine(engine, currentModel, true);
    $spawnDefaultsModel.innerHTML = '';
    options.forEach(opt => {
      const el = document.createElement('option');
      el.value = opt.id;
      el.textContent = opt.label || opt.id;
      if (opt.disabled) {
        el.disabled = true;
        if (opt.reason) el.title = opt.reason;
      }
      $spawnDefaultsModel.appendChild(el);
    });
    const currentOpt = options.find(opt => opt.id === currentModel && !opt.disabled);
    const fallbackOpt = options.find(opt => !opt.disabled);
    $spawnDefaultsModel.value = currentOpt ? currentModel : (fallbackOpt ? fallbackOpt.id : SPAWN_DEFAULT_OTHER);
    if ($spawnDefaultsOtherModel) {
      const other = $spawnDefaultsModel.value === SPAWN_DEFAULT_OTHER;
      $spawnDefaultsOtherModel.style.display = other ? '' : 'none';
      $spawnDefaultsOtherModel.value = other ? currentModel : '';
    }
  }
  function renderSpawnDefaultsDraft() {
    if (!spawnDefaultsDraft) return;
    if ($spawnDefaultsEngine) $spawnDefaultsEngine.value = normalizeSpawnDefaultEngine(spawnDefaultsDraft.engine);
    renderSpawnDefaultsModelDraft();
  }
  async function openSpawnDefaultsModal() {
    if (!$spawnDefaultsModal) return;
    spawnDefaultsModalError('');
    if ($spawnDefaultsSaveBtn) { $spawnDefaultsSaveBtn.disabled = false; $spawnDefaultsSaveBtn.textContent = 'Save'; }
    // Always re-fetch from server on open so the modal reflects any changes
    // made by other sessions or orchestration scripts since startup.
    try { await loadSpawnDefaults(); } catch (_) {}
    spawnDefaultsDraft = cloneSpawnDefaults();
    renderSpawnDefaultsDraft();
    $spawnDefaultsModal.classList.add('open');
  }
  function closeSpawnDefaultsModal() {
    if ($spawnDefaultsModal) $spawnDefaultsModal.classList.remove('open');
    spawnDefaultsDraft = null;
  }
  function updateSpawnDefaultsDraftModelFromControls() {
    if (!spawnDefaultsDraft || !$spawnDefaultsModel) return;
    const engine = normalizeSpawnDefaultEngine(spawnDefaultsDraft.engine);
    let model = $spawnDefaultsModel.value;
    if (model === SPAWN_DEFAULT_OTHER) {
      model = ($spawnDefaultsOtherModel && $spawnDefaultsOtherModel.value || '').trim();
    }
    if (engine === 'claude' && !model) model = 'opus';
    if (engine === 'codex' && !model) model = 'gpt-5.5';
    if (engine === 'cursor' && !model) model = 'auto';
    spawnDefaultsDraft.models[engine] = model;
  }
  async function saveSpawnDefaultsDraft() {
    if (!$spawnDefaultsSaveBtn || !spawnDefaultsDraft) return;
    updateSpawnDefaultsDraftModelFromControls();
    spawnDefaultsModalError('');
    const engine = normalizeSpawnDefaultEngine(spawnDefaultsDraft.engine);
    const model = String((spawnDefaultsDraft.models || {})[engine] || '').trim();
    if ((engine === 'claude' || engine === 'codex' || engine === 'cursor') && !model) {
      spawnDefaultsModalError('Claude, Codex, and Cursor need an explicit default model.');
      return;
    }
    const unavailableReason = _modelUnavailableReason(engine, model);
    if (unavailableReason) {
      spawnDefaultsModalError(unavailableReason);
      return;
    }
    $spawnDefaultsSaveBtn.disabled = true;
    $spawnDefaultsSaveBtn.textContent = 'Saving...';
    try {
      const res = await fetch('/api/spawn-defaults', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(spawnDefaultsDraft),
      });
      const data = await res.json().catch(() => ({}));
      if (!res.ok || !data.ok) throw new Error((data && data.error) || ('HTTP ' + res.status));
      mergeSpawnDefaults(data);
      _spawnDefaultsLoaded = true;
      syncSpawnEngineDependentUi();
      if (typeof updateInputBar === 'function') updateInputBar();
      closeSpawnDefaultsModal();
      showOpToast('Spawn defaults saved', 'ok');
    } catch (err) {
      spawnDefaultsModalError((err && err.message) || 'Save failed.');
      $spawnDefaultsSaveBtn.disabled = false;
      $spawnDefaultsSaveBtn.textContent = 'Save';
    }
  }

  if ($spawnDefaultsBtn) $spawnDefaultsBtn.addEventListener('click', () => {
    if ($settingsPopover) $settingsPopover.classList.remove('open');
    openSpawnDefaultsModal();
  });
  const $runOnboardingBtn = document.getElementById('runOnboardingBtn');
  if ($runOnboardingBtn) $runOnboardingBtn.addEventListener('click', async () => {
    if ($settingsPopover) $settingsPopover.classList.remove('open');
    try {
      await fetch('/api/onboarding/reset', { method: 'POST' });
      const res = await fetch('/api/onboarding/status');
      const data = await res.json();
      showOnboarding(data);
    } catch (err) {
      console.error('Failed to trigger onboarding:', err);
      showOpToast('Failed to trigger onboarding.', 'error');
    }
  });
  if ($spawnDefaultsBackdrop) $spawnDefaultsBackdrop.addEventListener('click', closeSpawnDefaultsModal);
  if ($spawnDefaultsCancelBtn) $spawnDefaultsCancelBtn.addEventListener('click', closeSpawnDefaultsModal);
  if ($spawnDefaultsSaveBtn) $spawnDefaultsSaveBtn.addEventListener('click', saveSpawnDefaultsDraft);

  // ── Car Mode (hands-free voice operator) ──────────────────────────────
  // Explainer + cost + optional key setup + start/stop. Status/keys go through
  // /api/car-mode/*; the server never echoes key values, only booleans.
  const $carModeModal = document.getElementById('carModeModal');
  const $carModeBackdrop = document.getElementById('carModeBackdrop');
  const $carModeBanner = document.getElementById('carModeStatusBanner');
  const $carModeAnthropicKey = document.getElementById('carModeAnthropicKey');
  const $carModeDeepgramKey = document.getElementById('carModeDeepgramKey');
  const $carModeError = document.getElementById('carModeError');
  const $carModeCancelBtn = document.getElementById('carModeCancelBtn');
  const $carModeSaveBtn = document.getElementById('carModeSaveBtn');
  const $carModeStartBtn = document.getElementById('carModeStartBtn');
  const $carModeStopBtn = document.getElementById('carModeStopBtn');
  const $sidebarCarModeBtn = document.getElementById('sidebarCarModeBtn');
  const $carModeMenuBtn = document.getElementById('carModeMenuBtn');
  let carModePollTimer = null;

  function carModeError(text) {
    if (!$carModeError) return;
    $carModeError.textContent = text || '';
    $carModeError.classList.toggle('visible', !!text);
  }
  function renderCarModeStatus(d) {
    d = d || {};
    if ($sidebarCarModeBtn) $sidebarCarModeBtn.classList.toggle('car-mode-running', !!d.running);
    if (!$carModeBanner) return;
    let cls = 'warn', msg = '';
    if (d.running) {
      cls = 'running';
      msg = '● Car Mode is running. Talk to it in the voice window, or press Stop.';
    } else if (d.mode === 'voice') {
      cls = 'ok';
      msg = '✓ Ready for hands-free voice (both keys set). Press Start Car Mode.';
    } else if (d.mode === 'degraded_no_deepgram') {
      cls = 'warn';
      msg = "Anthropic key set, Deepgram key missing → hands-free voice is off. Add a Deepgram key below, or use CCC's built-in browser mic / read-aloud (free).";
    } else {
      cls = 'warn';
      msg = 'Add an Anthropic API key below to enable Car Mode (the dispatcher brain).';
    }
    $carModeBanner.className = 'car-mode-banner ' + cls;
    $carModeBanner.textContent = msg;
    $carModeBanner.style.display = '';
    if ($carModeStartBtn) {
      $carModeStartBtn.style.display = d.running ? 'none' : '';
      $carModeStartBtn.disabled = d.mode !== 'voice';
    }
    if ($carModeStopBtn) $carModeStopBtn.style.display = d.running ? '' : 'none';
    if ($carModeAnthropicKey) $carModeAnthropicKey.placeholder = d.anthropic_key_set ? 'stored ✓ — leave blank to keep it' : 'sk-ant-… (required)';
    if ($carModeDeepgramKey) $carModeDeepgramKey.placeholder = d.deepgram_key_set ? 'stored ✓ — leave blank to keep it' : 'optional — enables hands-free voice';
  }
  async function fetchCarModeStatus() {
    try {
      const res = await fetch('/api/car-mode/status', { cache: 'no-store' });
      const d = await res.json().catch(() => ({}));
      renderCarModeStatus(d);
      return d;
    } catch (_) { return null; }
  }
  function openCarModeModal() {
    if (!$carModeModal) return;
    carModeError('');
    if ($carModeAnthropicKey) $carModeAnthropicKey.value = '';
    if ($carModeDeepgramKey) $carModeDeepgramKey.value = '';
    fetchCarModeStatus();
    $carModeModal.classList.add('open');
    if (carModePollTimer) clearInterval(carModePollTimer);
    carModePollTimer = setInterval(fetchCarModeStatus, 3000);
  }
  function closeCarModeModal() {
    if ($carModeModal) $carModeModal.classList.remove('open');
    if (carModePollTimer) { clearInterval(carModePollTimer); carModePollTimer = null; }
  }
  async function saveCarModeKeys() {
    carModeError('');
    const payload = {};
    if ($carModeAnthropicKey && $carModeAnthropicKey.value.trim()) payload.anthropic_api_key = $carModeAnthropicKey.value.trim();
    if ($carModeDeepgramKey && $carModeDeepgramKey.value.trim()) payload.deepgram_api_key = $carModeDeepgramKey.value.trim();
    if (!Object.keys(payload).length) { carModeError('Enter a key to save (blank fields keep the stored key).'); return; }
    if ($carModeSaveBtn) { $carModeSaveBtn.disabled = true; $carModeSaveBtn.textContent = 'Saving…'; }
    try {
      const res = await fetch('/api/car-mode/config', { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify(payload) });
      const d = await res.json().catch(() => ({}));
      if (!res.ok) throw new Error((d && d.error) || ('HTTP ' + res.status));
      if ($carModeAnthropicKey) $carModeAnthropicKey.value = '';
      if ($carModeDeepgramKey) $carModeDeepgramKey.value = '';
      renderCarModeStatus(d);
      showOpToast('Car Mode keys saved', 'ok');
    } catch (err) {
      carModeError((err && err.message) || 'Save failed.');
    } finally {
      if ($carModeSaveBtn) { $carModeSaveBtn.disabled = false; $carModeSaveBtn.textContent = 'Save keys'; }
    }
  }
  async function startCarMode() {
    carModeError('');
    if ($carModeStartBtn) { $carModeStartBtn.disabled = true; $carModeStartBtn.textContent = 'Starting…'; }
    try {
      const res = await fetch('/api/car-mode/start', { method: 'POST' });
      const d = await res.json().catch(() => ({}));
      if (d && d.ok === false) { carModeError(d.error || 'Could not start Car Mode.'); renderCarModeStatus(d); return; }
      renderCarModeStatus(d);
      showOpToast('Car Mode starting — the voice window will open', 'ok');
    } catch (err) {
      carModeError((err && err.message) || 'Start failed.');
    } finally {
      if ($carModeStartBtn) { $carModeStartBtn.textContent = 'Start Car Mode'; }
      fetchCarModeStatus();
    }
  }
  async function stopCarMode() {
    carModeError('');
    try {
      const res = await fetch('/api/car-mode/stop', { method: 'POST' });
      const d = await res.json().catch(() => ({}));
      renderCarModeStatus(d);
      showOpToast('Car Mode stopped', 'ok');
    } catch (err) {
      carModeError((err && err.message) || 'Stop failed.');
    } finally { fetchCarModeStatus(); }
  }
  if ($sidebarCarModeBtn) $sidebarCarModeBtn.addEventListener('click', openCarModeModal);
  if ($carModeMenuBtn) $carModeMenuBtn.addEventListener('click', () => {
    if ($settingsPopover) $settingsPopover.classList.remove('open');
    openCarModeModal();
  });
  if ($carModeBackdrop) $carModeBackdrop.addEventListener('click', closeCarModeModal);
  if ($carModeCancelBtn) $carModeCancelBtn.addEventListener('click', closeCarModeModal);
  if ($carModeSaveBtn) $carModeSaveBtn.addEventListener('click', saveCarModeKeys);
  if ($carModeStartBtn) $carModeStartBtn.addEventListener('click', startCarMode);
  if ($carModeStopBtn) $carModeStopBtn.addEventListener('click', stopCarMode);
  // One status read at load so the sidebar 🚗 reflects a running instance.
  fetchCarModeStatus();
  if ($spawnDefaultsEngine) $spawnDefaultsEngine.addEventListener('change', () => {
    if (!spawnDefaultsDraft) return;
    updateSpawnDefaultsDraftModelFromControls();
    spawnDefaultsDraft.engine = normalizeSpawnDefaultEngine($spawnDefaultsEngine.value);
    renderSpawnDefaultsModelDraft();
  });
  if ($spawnDefaultsModel) $spawnDefaultsModel.addEventListener('change', () => {
    if ($spawnDefaultsOtherModel) {
      $spawnDefaultsOtherModel.style.display = $spawnDefaultsModel.value === SPAWN_DEFAULT_OTHER ? '' : 'none';
      if ($spawnDefaultsModel.value === SPAWN_DEFAULT_OTHER) $spawnDefaultsOtherModel.focus();
    }
    updateSpawnDefaultsDraftModelFromControls();
  });
  if ($spawnDefaultsOtherModel) $spawnDefaultsOtherModel.addEventListener('input', updateSpawnDefaultsDraftModelFromControls);
  document.addEventListener('keydown', (e) => {
    if (e.key === 'Escape' && $spawnDefaultsModal && $spawnDefaultsModal.classList.contains('open')) {
      closeSpawnDefaultsModal();
    }
  });

  // Network access modal — opt in to non-loopback access via Tailscale or
  // arbitrary trusted origins. POSTs to /api/network-config which writes
  // the JSON config and triggers an in-place restart.
  const $networkBtn = document.getElementById('networkAccessBtn');
  const $networkModal = document.getElementById('networkModal');
  const $networkBackdrop = document.getElementById('networkBackdrop');
  const $networkBindAll = document.getElementById('networkBindAll');
  const $networkTrustTailnet = document.getElementById('networkTrustTailnet');
  const $networkTailnetSummary = document.getElementById('networkTailnetSummary');
  const $networkExtraOrigins = document.getElementById('networkExtraOrigins');
  const $networkEnvNotice = document.getElementById('networkEnvNotice');
  const $networkError = document.getElementById('networkError');
  const $networkCancelBtn = document.getElementById('networkCancelBtn');
  const $networkSaveBtn = document.getElementById('networkSaveBtn');

  function networkEsc(s) {
    return String(s == null ? '' : s).replace(/[&<>"']/g, (c) => ({
      '&': '&amp;', '<': '&lt;', '>': '&gt;', '"': '&quot;', "'": '&#39;',
    })[c]);
  }
  function networkResetState() {
    if ($networkError) { $networkError.textContent = ''; $networkError.classList.remove('visible'); }
    if ($networkSaveBtn) { $networkSaveBtn.disabled = false; $networkSaveBtn.textContent = 'Save & restart'; }
    if ($networkCancelBtn) { $networkCancelBtn.disabled = false; }
  }
  function networkRenderTailnet(tn) {
    if (!$networkTailnetSummary) return;
    if (!tn || !tn.available) {
      $networkTailnetSummary.innerHTML = 'Tailscale CLI not found on PATH — install <a href="https://tailscale.com/download" target="_blank" rel="noopener">tailscale</a> to enable.';
      if ($networkTrustTailnet) $networkTrustTailnet.disabled = true;
      return;
    }
    if (!tn.running) {
      $networkTailnetSummary.textContent = 'Tailscale is installed but not running. Start it and reopen this dialog.';
      if ($networkTrustTailnet) $networkTrustTailnet.disabled = true;
      return;
    }
    if ($networkTrustTailnet) $networkTrustTailnet.disabled = false;
    const host = tn.hostname ? '<code>' + networkEsc(tn.hostname) + '</code>' : '(no MagicDNS hostname)';
    const originsList = (tn.origins || []).map(o => '<code>' + networkEsc(o) + '</code>').join(', ');
    $networkTailnetSummary.innerHTML =
      'Detected: ' + host + '. When trusted, these origins are allowed: ' + (originsList || '(none)');
  }
  function networkRenderEnvNotice(env) {
    if (!$networkEnvNotice) return;
    const pinned = [];
    if (env && env.bind_host) pinned.push('CCC_BIND_HOST');
    if (env && env.allowed_origins) pinned.push('CCC_ALLOWED_ORIGIN');
    if (env && env.trust_tailnet) pinned.push('CCC_TRUST_TAILNET');
    if (pinned.length === 0) {
      $networkEnvNotice.style.display = 'none';
      return;
    }
    $networkEnvNotice.style.display = '';
    $networkEnvNotice.innerHTML =
      'Some values are pinned by environment variables for this run: <code>' +
      pinned.map(networkEsc).join('</code>, <code>') +
      '</code>. Saving here will not change them — clear the env to take control from the UI.';
  }

  async function networkOpen() {
    if (!$networkModal) return;
    networkResetState();
    if ($networkExtraOrigins) $networkExtraOrigins.value = '';
    if ($networkBindAll) $networkBindAll.checked = false;
    if ($networkTrustTailnet) $networkTrustTailnet.checked = false;
    if ($networkTailnetSummary) $networkTailnetSummary.textContent = 'Detecting Tailscale…';
    $networkModal.classList.add('open');
    let data;
    try {
      const r = await fetch('/api/network-config', { cache: 'no-store' });
      data = await r.json();
    } catch (e) {
      if ($networkError) {
        $networkError.textContent = 'Could not load current settings: ' + (e && e.message || 'unknown');
        $networkError.classList.add('visible');
      }
      return;
    }
    const stored = data.stored || {};
    const runtime = data.runtime || {};
    if ($networkBindAll) $networkBindAll.checked = (stored.bind_host === '0.0.0.0') || (runtime.bind_host && runtime.bind_host !== '127.0.0.1' && runtime.bind_host !== 'localhost');
    if ($networkTrustTailnet) $networkTrustTailnet.checked = !!stored.trust_tailnet;
    // Show only the user-managed origins (those in the stored config).
    // Auto-detected tailnet origins and env-supplied ones are not shown
    // here — listing them would invite "delete = remove trust", which the
    // env / auto-detect layers don't honour. Tailnet origins are summarized
    // separately via the checkbox.
    if ($networkExtraOrigins) {
      $networkExtraOrigins.value = (stored.allowed_origins || []).join('\n');
    }
    networkRenderTailnet(data.tailnet);
    networkRenderEnvNotice(runtime.env_overrides);
  }
  function networkClose() {
    if ($networkModal) $networkModal.classList.remove('open');
  }

  async function networkSave() {
    if (!$networkSaveBtn) return;
    networkResetState();
    const bindAll = !!($networkBindAll && $networkBindAll.checked);
    const trust = !!($networkTrustTailnet && $networkTrustTailnet.checked);
    const extra = ($networkExtraOrigins && $networkExtraOrigins.value || '')
      .split(/\r?\n/).map(s => s.trim()).filter(Boolean);
    const bad = extra.find(o => !/^https?:\/\/[^\s]+$/.test(o));
    if (bad) {
      if ($networkError) {
        $networkError.textContent = 'Origin must look like http://host:port — got: ' + bad;
        $networkError.classList.add('visible');
      }
      return;
    }
    $networkSaveBtn.disabled = true;
    $networkSaveBtn.textContent = 'Saving…';
    if ($networkCancelBtn) $networkCancelBtn.disabled = true;
    try { sessionStorage.setItem('ccc-updating', '1'); } catch (_) {}
    let data;
    try {
      const r = await fetch('/api/network-config', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          bind_host: bindAll ? '0.0.0.0' : '127.0.0.1',
          allowed_origins: extra,
          trust_tailnet: trust,
        }),
      });
      data = await r.json().catch(() => ({}));
      if (!r.ok || !data.ok) {
        throw new Error(data && data.error ? data.error : 'save failed (' + r.status + ')');
      }
    } catch (e) {
      try { sessionStorage.removeItem('ccc-updating'); } catch (_) {}
      if ($networkError) {
        $networkError.textContent = (e && e.message) || 'Save failed.';
        $networkError.classList.add('visible');
      }
      $networkSaveBtn.disabled = false;
      $networkSaveBtn.textContent = 'Save & restart';
      if ($networkCancelBtn) $networkCancelBtn.disabled = false;
      return;
    }
    $networkSaveBtn.textContent = 'Restarting…';
    setTimeout(() => { try { location.reload(); } catch (_) {} }, 1200);
  }

  if ($networkBtn) $networkBtn.addEventListener('click', () => {
    if ($settingsPopover) $settingsPopover.classList.remove('open');
    networkOpen();
  });
  if ($networkBackdrop) $networkBackdrop.addEventListener('click', networkClose);
  if ($networkCancelBtn) $networkCancelBtn.addEventListener('click', networkClose);
  if ($networkSaveBtn) $networkSaveBtn.addEventListener('click', networkSave);
  document.addEventListener('keydown', (e) => {
    if (e.key === 'Escape' && $networkModal && $networkModal.classList.contains('open')) {
      networkClose();
    }
  });

  // Federation "Nodes & peers" modal — manage this node's identity, the
  // paired peers (SSH / loopback transports) and the repo-identity →
  // local-path map. Backend: /api/federation/* (see federation.py). The
  // modal fetches fresh state on open and simply re-fetches after every
  // mutation; pairing secrets never reach the browser (has_secret only).
  const $fedBtn = document.getElementById('federationPeersBtn');
  const $fedModal = document.getElementById('fedPeersModal');
  const $fedBackdrop = document.getElementById('fedPeersBackdrop');
  const $fedCloseBtn = document.getElementById('fedPeersCloseBtn');
  const $fedError = document.getElementById('fedPeersError');
  const $fedSelfName = document.getElementById('fedSelfName');
  const $fedSelfNameSave = document.getElementById('fedSelfNameSave');
  const $fedSelfMeta = document.getElementById('fedSelfMeta');
  const $fedPeersList = document.getElementById('fedPeersList');
  const $fedPairMode = document.getElementById('fedPairMode');
  const $fedPairSshHost = document.getElementById('fedPairSshHost');
  const $fedPairPort = document.getElementById('fedPairPort');
  const $fedPairName = document.getElementById('fedPairName');
  const $fedPairBtn = document.getElementById('fedPairBtn');
  const $fedPairError = document.getElementById('fedPairError');
  const $fedRepoMapList = document.getElementById('fedRepoMapList');
  const $fedRepoIdentity = document.getElementById('fedRepoIdentity');
  const $fedRepoPath = document.getElementById('fedRepoPath');
  const $fedRepoAddBtn = document.getElementById('fedRepoAddBtn');
  const $fedRepoError = document.getElementById('fedRepoError');
  let fedPeersCache = [];

  function fedEsc(s) {
    return String(s == null ? '' : s).replace(/[&<>"']/g, (c) => ({
      '&': '&amp;', '<': '&lt;', '>': '&gt;', '"': '&quot;', "'": '&#39;',
    })[c]);
  }
  function fedShortId(id) {
    return String(id || '').slice(0, 8);
  }
  function fedLastSeen(v) {
    // last_seen is an ISO-8601 string written by the server.
    const ms = Date.parse(v || '');
    return isFinite(ms) ? 'seen ' + relativeTime(ms / 1000) : 'never seen';
  }
  function fedSetError(el, msg) {
    if (!el) return;
    el.textContent = msg || '';
    el.classList.toggle('visible', !!msg);
  }
  async function fedPost(path, body) {
    const r = await fetch(path, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(body || {}),
    });
    const data = await r.json().catch(() => ({}));
    if (!r.ok || data.ok === false) {
      throw new Error((data && (data.detail || data.error)) || ('request failed (' + r.status + ')'));
    }
    return data;
  }
  function fedTransportSummary(t) {
    const type = t && t.type;
    if (type === 'ssh') return 'ssh ' + (t.host || '');
    if (type === 'loopback') return 'loopback :' + (t.port || '?');
    return 'no route back';
  }

  function fedRenderSelf(self) {
    if (!self) return;
    if ($fedSelfName) $fedSelfName.value = self.display_name || '';
    if ($fedSelfMeta) {
      $fedSelfMeta.innerHTML =
        '<span class="fed-node-id" title="' + fedEsc(self.node_id) + '">' + fedEsc(fedShortId(self.node_id)) + '</span>' +
        (self.version ? ' · v' + fedEsc(self.version) : '') +
        (self.port ? ' · port ' + fedEsc(self.port) : '');
    }
  }
  function fedRenderPeers(peers) {
    if (!$fedPeersList) return;
    if (!peers || !peers.length) {
      $fedPeersList.innerHTML = '<div class="fed-empty">No paired peers yet — add one below.</div>';
      return;
    }
    $fedPeersList.innerHTML = peers.map((p) => {
      const t = p.transport || {};
      const chip = (!t.type || t.type === 'unconfigured')
        ? ' <span class="fed-chip-warn" title="This peer has no transport configured back to this node — it can be called but cannot call back.">no route back</span>'
        : '';
      return '<div class="fed-row" data-fed-node="' + fedEsc(p.node_id) + '">' +
        '<div class="fed-row-main">' +
          '<span class="fed-peer-name">' + fedEsc(p.name || '(unnamed)') + chip + '</span>' +
          '<div class="fed-meta">' +
            fedEsc(fedTransportSummary(t)) +
            ' · <span class="fed-node-id" title="' + fedEsc(p.node_id) + '">' + fedEsc(fedShortId(p.node_id)) + '</span>' +
            ' · ' + fedEsc(fedLastSeen(p.last_seen)) +
            (p.version ? ' · v' + fedEsc(p.version) : '') +
          '</div>' +
          '<span class="fed-test-result" data-fed-test-result></span>' +
        '</div>' +
        '<div class="fed-row-actions">' +
          '<button type="button" class="upd-btn fed-btn" data-fed-act="test">Test</button>' +
          '<button type="button" class="upd-btn fed-btn" data-fed-act="rename">Rename</button>' +
          '<button type="button" class="upd-btn fed-btn" data-fed-act="remove">Remove</button>' +
        '</div>' +
      '</div>';
    }).join('');
  }
  function fedRenderRepoMap(map) {
    if (!$fedRepoMapList) return;
    const identities = Object.keys(map || {}).sort();
    if (!identities.length) {
      $fedRepoMapList.innerHTML = '<div class="fed-empty">No mappings yet.</div>';
      return;
    }
    $fedRepoMapList.innerHTML = identities.map((identity) =>
      '<div class="fed-row">' +
        '<div class="fed-row-main">' +
          '<span class="fed-peer-name">' + fedEsc(identity) + '</span>' +
          '<div class="fed-meta">' + fedEsc(map[identity]) + '</div>' +
        '</div>' +
        '<div class="fed-row-actions">' +
          '<button type="button" class="upd-btn fed-btn" data-fed-repo-remove="' + fedEsc(identity) + '">Remove</button>' +
        '</div>' +
      '</div>'
    ).join('');
  }

  async function fedRefresh() {
    fedSetError($fedError, '');
    let data, ok;
    try {
      const r = await fetch('/api/federation/peers', { cache: 'no-store' });
      ok = r.ok;
      data = await r.json();
    } catch (e) {
      fedSetError($fedError, 'Could not load peers: ' + ((e && e.message) || 'unknown'));
      return;
    }
    if (!ok || !data || data.ok === false) {
      fedSetError($fedError, 'Could not load peers: ' + ((data && (data.detail || data.error)) || 'unknown'));
      return;
    }
    fedPeersCache = data.peers || [];
    fedRenderSelf(data.self);
    fedRenderPeers(fedPeersCache);
    fedRenderRepoMap(data.repo_map || {});
  }

  function openFederationPeersModal() {
    if (!$fedModal) return;
    fedSetError($fedError, '');
    fedSetError($fedPairError, '');
    fedSetError($fedRepoError, '');
    if ($fedPeersList) $fedPeersList.innerHTML = '<div class="fed-empty">Loading…</div>';
    if ($fedRepoMapList) $fedRepoMapList.innerHTML = '';
    $fedModal.classList.add('open');
    fedRefresh();
  }
  function fedClose() {
    if ($fedModal) $fedModal.classList.remove('open');
  }

  async function fedSaveSelfName() {
    const name = (($fedSelfName && $fedSelfName.value) || '').trim();
    if (!name) return;
    if ($fedSelfNameSave) { $fedSelfNameSave.disabled = true; $fedSelfNameSave.textContent = 'Saving…'; }
    try {
      await fedPost('/api/federation/node', { display_name: name });
      await fedRefresh();
      showOpToast('Node name saved', 'ok');
    } catch (e) {
      fedSetError($fedError, 'Could not save the node name: ' + e.message);
    }
    if ($fedSelfNameSave) { $fedSelfNameSave.disabled = false; $fedSelfNameSave.textContent = 'Save'; }
  }

  async function fedHandlePeerAction(act, nodeId, rowEl) {
    const peer = fedPeersCache.find((p) => p.node_id === nodeId) || {};
    if (act === 'test') {
      const $res = rowEl.querySelector('[data-fed-test-result]');
      if ($res) { $res.textContent = 'testing…'; $res.className = 'fed-test-result'; }
      try {
        const data = await fedPost('/api/federation/peers/test', { node_id: nodeId });
        if ($res) {
          $res.textContent = '✓ ' + (data.latency_ms != null ? data.latency_ms + 'ms' : 'ok');
          $res.classList.add('ok');
        }
      } catch (e) {
        if ($res) { $res.textContent = '✗ ' + e.message; $res.classList.add('err'); }
      }
      return;
    }
    if (act === 'rename') {
      const name = prompt('New name for this peer:', peer.name || '');
      if (name == null || !name.trim()) return;
      try {
        await fedPost('/api/federation/peers/rename', { node_id: nodeId, name: name.trim() });
        await fedRefresh();
      } catch (e) {
        fedSetError($fedError, 'Rename failed: ' + e.message);
      }
      return;
    }
    if (act === 'remove') {
      if (!confirm('Remove peer "' + (peer.name || fedShortId(nodeId)) + '"? This also asks the peer to forget this node.')) return;
      try {
        await fedPost('/api/federation/peers/remove', { node_id: nodeId });
        await fedRefresh();
      } catch (e) {
        fedSetError($fedError, 'Remove failed: ' + e.message);
      }
    }
  }

  async function fedPair() {
    fedSetError($fedPairError, '');
    const mode = ($fedPairMode && $fedPairMode.value) || 'ssh';
    let transport;
    if (mode === 'loopback') {
      const port = parseInt(($fedPairPort && $fedPairPort.value) || '', 10);
      if (!port) { fedSetError($fedPairError, "Enter the peer's local port (e.g. 8091)."); return; }
      transport = { type: 'loopback', port };
    } else {
      const host = (($fedPairSshHost && $fedPairSshHost.value) || '').trim();
      if (!host) { fedSetError($fedPairError, 'Enter an SSH destination like user@host.'); return; }
      transport = { type: 'ssh', host };
    }
    const body = { transport };
    const name = (($fedPairName && $fedPairName.value) || '').trim();
    if (name) body.name = name;
    if ($fedPairBtn) { $fedPairBtn.disabled = true; $fedPairBtn.textContent = 'Pairing…'; }
    try {
      await fedPost('/api/federation/peers/pair', body);
      if ($fedPairSshHost) $fedPairSshHost.value = '';
      if ($fedPairPort) $fedPairPort.value = '';
      if ($fedPairName) $fedPairName.value = '';
      showOpToast('Peer paired', 'ok');
      await fedRefresh();
    } catch (e) {
      fedSetError($fedPairError, e.message);
    }
    if ($fedPairBtn) { $fedPairBtn.disabled = false; $fedPairBtn.textContent = 'Pair'; }
  }

  async function fedRepoAdd() {
    fedSetError($fedRepoError, '');
    const identity = (($fedRepoIdentity && $fedRepoIdentity.value) || '').trim();
    const localPath = (($fedRepoPath && $fedRepoPath.value) || '').trim();
    if (!identity || !localPath) {
      fedSetError($fedRepoError, 'Both the repo identity and a local path are required.');
      return;
    }
    if ($fedRepoAddBtn) $fedRepoAddBtn.disabled = true;
    try {
      await fedPost('/api/federation/repo-map', { identity, local_path: localPath });
      if ($fedRepoIdentity) $fedRepoIdentity.value = '';
      if ($fedRepoPath) $fedRepoPath.value = '';
      await fedRefresh();
    } catch (e) {
      fedSetError($fedRepoError, e.message);
    }
    if ($fedRepoAddBtn) $fedRepoAddBtn.disabled = false;
  }
  async function fedRepoRemove(identity) {
    fedSetError($fedRepoError, '');
    try {
      await fedPost('/api/federation/repo-map', { identity, local_path: '' });
      await fedRefresh();
    } catch (e) {
      fedSetError($fedRepoError, e.message);
    }
  }

  if ($fedBtn) $fedBtn.addEventListener('click', () => {
    if ($settingsPopover) $settingsPopover.classList.remove('open');
    openFederationPeersModal();
  });
  if ($fedBackdrop) $fedBackdrop.addEventListener('click', fedClose);
  if ($fedCloseBtn) $fedCloseBtn.addEventListener('click', fedClose);
  document.addEventListener('keydown', (e) => {
    if (e.key === 'Escape' && $fedModal && $fedModal.classList.contains('open')) {
      fedClose();
    }
  });
  if ($fedSelfNameSave) $fedSelfNameSave.addEventListener('click', fedSaveSelfName);
  if ($fedSelfName) $fedSelfName.addEventListener('keydown', (e) => {
    if (e.key === 'Enter') fedSaveSelfName();
  });
  if ($fedPairMode) $fedPairMode.addEventListener('change', () => {
    const loop = $fedPairMode.value === 'loopback';
    if ($fedPairSshHost) $fedPairSshHost.style.display = loop ? 'none' : '';
    if ($fedPairPort) $fedPairPort.style.display = loop ? '' : 'none';
  });
  if ($fedPairBtn) $fedPairBtn.addEventListener('click', fedPair);
  if ($fedPeersList) $fedPeersList.addEventListener('click', (e) => {
    const btn = e.target.closest('button[data-fed-act]');
    if (!btn) return;
    const row = btn.closest('[data-fed-node]');
    if (!row) return;
    fedHandlePeerAction(btn.dataset.fedAct, row.dataset.fedNode, row);
  });
  if ($fedRepoAddBtn) $fedRepoAddBtn.addEventListener('click', fedRepoAdd);
  if ($fedRepoMapList) $fedRepoMapList.addEventListener('click', (e) => {
    const btn = e.target.closest('button[data-fed-repo-remove]');
    if (btn) fedRepoRemove(btn.dataset.fedRepoRemove);
  });


  // ── "Continue on…" session handoff ────────────────────────────────
  // Hands the open session off to a paired federation node: pick a peer,
  // preview the preflight plan (git facts + steps + blockers), then POST
  // the handoff and surface the destination cwd / rewrites / resume hint.
  // Reuses the fed* helpers (fedEsc/fedShortId) and the .upd-* modal shell.
  const $handoffModal = document.getElementById('handoffModal');
  const $handoffBackdrop = document.getElementById('handoffBackdrop');
  const $handoffCloseBtn = document.getElementById('handoffCloseBtn');
  const $handoffSubtitle = document.getElementById('handoffSubtitle');
  const $handoffDest = document.getElementById('handoffDest');
  const $handoffPreflightBtn = document.getElementById('handoffPreflightBtn');
  const $handoffNoPeers = document.getElementById('handoffNoPeers');
  const $handoffOpenPeers = document.getElementById('handoffOpenPeers');
  const $handoffPlan = document.getElementById('handoffPlan');
  const $handoffError = document.getElementById('handoffError');
  const $handoffRecheckBtn = document.getElementById('handoffRecheckBtn');
  const $handoffConfirmBtn = document.getElementById('handoffConfirmBtn');
  let handoffSessionId = null;
  let handoffPeers = [];
  let handoffReady = false;

  function handoffSetError(msg) {
    if (!$handoffError) return;
    $handoffError.textContent = msg || '';
    $handoffError.classList.toggle('visible', !!msg);
  }
  // Raw POST that returns the full payload (status + body) without throwing,
  // so structured error shapes (not_owner + owner_node, preflight_blocked +
  // blockers) can be rendered rather than collapsed to a message string.
  async function handoffPost(path, body) {
    const r = await fetch(path, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(body || {}),
    });
    const data = await r.json().catch(() => ({}));
    return { status: r.status, data: data || {} };
  }
  function handoffRewriteCount(rw) {
    const v = rw && rw.cwd_rewrites;
    if (Array.isArray(v)) return v.length;
    return Number(v || 0);
  }

  async function handoffLoadPeers() {
    if (!$handoffDest) return;
    $handoffDest.innerHTML = '';
    try {
      const r = await fetch('/api/federation/peers', { cache: 'no-store' });
      const data = await r.json().catch(() => ({}));
      handoffPeers = (data && data.peers) || [];
    } catch (_) {
      handoffPeers = [];
    }
    const hasPeers = handoffPeers.length > 0;
    if ($handoffNoPeers) $handoffNoPeers.hidden = hasPeers;
    if ($handoffDest) $handoffDest.style.display = hasPeers ? '' : 'none';
    if ($handoffPreflightBtn) $handoffPreflightBtn.style.display = hasPeers ? '' : 'none';
    if (!hasPeers) return;
    $handoffDest.innerHTML = handoffPeers.map((p) =>
      '<option value="' + fedEsc(p.node_id) + '">'
      + fedEsc((p.name || '(unnamed)') + ' · ' + fedShortId(p.node_id))
      + '</option>'
    ).join('');
  }

  function handoffDestName() {
    const opt = $handoffDest && $handoffDest.selectedOptions && $handoffDest.selectedOptions[0];
    if (opt && opt.textContent) return opt.textContent;
    const peer = handoffPeers.find((p) => p.node_id === ($handoffDest && $handoffDest.value));
    return (peer && peer.name) || 'the destination node';
  }

  function handoffRenderHardError(data) {
    // 404 unpaired_peer / 409 not_owner / 400 unsupported_capability, or any
    // {ok:false,error,detail}. not_owner also carries owner_node.
    let msg = (data.detail || data.error || 'Handoff failed');
    if (data.error === 'not_owner' && data.owner_node) {
      msg += '\nCurrent owner: ' + data.owner_node;
    }
    handoffSetError(msg);
    if ($handoffPlan) { $handoffPlan.hidden = true; $handoffPlan.innerHTML = ''; }
    if ($handoffConfirmBtn) { $handoffConfirmBtn.hidden = true; $handoffConfirmBtn.disabled = true; }
    if ($handoffRecheckBtn) $handoffRecheckBtn.hidden = false;
    handoffReady = false;
  }

  function handoffRenderPlan(data) {
    if (!$handoffPlan) return;
    const git = data.git || {};
    const steps = Array.isArray(data.steps) ? data.steps : [];
    const blockers = Array.isArray(data.blockers) ? data.blockers : [];
    let html = '';

    // Git facts row.
    html += '<div class="handoff-git">'
      + 'branch <strong>' + fedEsc(git.branch || '—') + '</strong>'
      + ' · <span class="handoff-commit">' + fedEsc((git.commit || '').slice(0, 8) || '—') + '</span>'
      + ' · ' + fedEsc(git.dirty_count != null ? git.dirty_count : 0) + ' uncommitted'
      + ' · ' + fedEsc(git.unpublished_commits != null ? git.unpublished_commits : 0) + ' unpushed'
      + (git.has_upstream === false ? ' · <span class="handoff-warn-text">no upstream</span>' : '')
      + '</div>';

    // Plan steps — "needed" ones highlighted.
    if (steps.length) {
      html += '<div class="fed-section-title">Plan</div><div class="handoff-steps">';
      for (const s of steps) {
        const needed = !!s.needed;
        html += '<div class="handoff-step' + (needed ? ' is-needed' : '') + '">'
          + '<span class="handoff-step-name">' + fedEsc(s.step || '') + '</span>'
          + (s.detail ? '<span class="handoff-step-detail">' + fedEsc(s.detail) + '</span>' : '')
          + '</div>';
      }
      html += '</div>';
    }

    // Blockers in red — code + detail + first files.
    if (blockers.length) {
      html += '<div class="handoff-blockers">';
      for (const b of blockers) {
        const files = Array.isArray(b.files) ? b.files : [];
        html += '<div class="handoff-blocker">'
          + '<span class="handoff-blocker-code">' + fedEsc(b.code || 'blocked') + '</span>'
          + (b.detail ? '<span class="handoff-blocker-detail">' + fedEsc(b.detail) + '</span>' : '')
          + (files.length
            ? '<span class="handoff-blocker-files">' + fedEsc(files.slice(0, 5).join(', ')) + (files.length > 5 ? ' …' : '') + '</span>'
            : '')
          + '</div>';
      }
      html += '</div>';
    }

    $handoffPlan.innerHTML = html;
    $handoffPlan.hidden = false;
    handoffReady = !!data.ready;
    if ($handoffConfirmBtn) {
      $handoffConfirmBtn.hidden = false;
      $handoffConfirmBtn.disabled = !handoffReady;
      $handoffConfirmBtn.textContent = 'Hand off';
    }
    if ($handoffRecheckBtn) $handoffRecheckBtn.hidden = false;
  }

  function handoffRenderSuccess(data) {
    if (!$handoffPlan) return;
    const rw = data.rewrites || {};
    const warnings = Array.isArray(rw.warnings) ? rw.warnings : [];
    let html = '<div class="handoff-success">';
    html += '<div class="handoff-success-title">✓ Handed off to <strong>'
      + fedEsc(handoffDestName()) + '</strong></div>';
    html += '<div class="handoff-kv"><span>Destination path</span><code>'
      + fedEsc(data.dest_cwd || '—') + '</code></div>';
    html += '<div class="handoff-kv"><span>Path rewrites</span><span>'
      + fedEsc(handoffRewriteCount(rw)) + '</span></div>';
    if (warnings.length) {
      html += '<div class="handoff-warnings">';
      for (const w of warnings) html += '<div>⚠ ' + fedEsc(w) + '</div>';
      html += '</div>';
    }
    if (data.resume_hint) {
      html += '<div class="handoff-resume"><span>Resume with</span>'
        + '<code class="handoff-copy" data-handoff-copy="' + fedEsc(data.resume_hint) + '"'
        + ' title="Click to copy">' + fedEsc(data.resume_hint) + '</code></div>';
    }
    html += '</div>';
    $handoffPlan.innerHTML = html;
    $handoffPlan.hidden = false;
    handoffSetError('');
    if ($handoffConfirmBtn) $handoffConfirmBtn.hidden = true;
    if ($handoffRecheckBtn) $handoffRecheckBtn.hidden = true;
    if ($handoffPreflightBtn) $handoffPreflightBtn.disabled = false;
    if ($handoffDest) $handoffDest.disabled = false;
    showOpToast('Session handed off to ' + handoffDestName(), 'ok');
    // The source session is no longer owned here — refresh the moved chip.
    if (handoffSessionId) {
      _handoffMovedBySid[handoffSessionId] = { owner: handoffDestName() };
      refreshHandoffMovedChip();
    }
  }

  async function handoffPreflight() {
    const dest = $handoffDest && $handoffDest.value;
    if (!handoffSessionId || !dest) return;
    handoffSetError('');
    handoffReady = false;
    if ($handoffConfirmBtn) { $handoffConfirmBtn.hidden = true; $handoffConfirmBtn.disabled = true; }
    if ($handoffRecheckBtn) $handoffRecheckBtn.hidden = true;
    if ($handoffPreflightBtn) { $handoffPreflightBtn.disabled = true; $handoffPreflightBtn.textContent = 'Checking…'; }
    if ($handoffPlan) { $handoffPlan.hidden = false; $handoffPlan.innerHTML = '<div class="fed-empty">Running preflight…</div>'; }
    try {
      const { data } = await handoffPost('/api/federation/handoff/preflight', {
        session_id: handoffSessionId, dest_node_id: dest,
      });
      if (data.ok === false || (data.error && data.ready === undefined)) {
        handoffRenderHardError(data);
      } else {
        handoffRenderPlan(data);
      }
    } catch (e) {
      handoffRenderHardError({ error: 'request_failed', detail: (e && e.message) || 'Preflight request failed' });
    }
    if ($handoffPreflightBtn) { $handoffPreflightBtn.disabled = false; $handoffPreflightBtn.textContent = 'Preflight'; }
  }

  async function handoffStart() {
    const dest = $handoffDest && $handoffDest.value;
    if (!handoffReady || !handoffSessionId || !dest) return;
    handoffSetError('');
    if ($handoffConfirmBtn) { $handoffConfirmBtn.disabled = true; $handoffConfirmBtn.textContent = 'Handing off…'; }
    if ($handoffPreflightBtn) $handoffPreflightBtn.disabled = true;
    if ($handoffDest) $handoffDest.disabled = true;
    try {
      const { data } = await handoffPost('/api/federation/handoff/start', {
        session_id: handoffSessionId, dest_node_id: dest,
      });
      if (data.ok === false || data.error) {
        if (data.error === 'preflight_blocked') {
          handoffRenderPlan({
            ready: false,
            blockers: data.blockers || [],
            steps: data.steps || [],
            git: data.git || {},
          });
          handoffSetError('Preflight blocked — resolve the blockers, then re-check.');
        } else {
          handoffRenderHardError(data);
        }
        if ($handoffConfirmBtn) { $handoffConfirmBtn.textContent = 'Hand off'; $handoffConfirmBtn.disabled = !handoffReady; }
        if ($handoffPreflightBtn) $handoffPreflightBtn.disabled = false;
        if ($handoffDest) $handoffDest.disabled = false;
        return;
      }
      handoffRenderSuccess(data);
    } catch (e) {
      handoffSetError((e && e.message) || 'Handoff request failed');
      if ($handoffConfirmBtn) { $handoffConfirmBtn.textContent = 'Hand off'; $handoffConfirmBtn.disabled = !handoffReady; }
      if ($handoffPreflightBtn) $handoffPreflightBtn.disabled = false;
      if ($handoffDest) $handoffDest.disabled = false;
    }
  }

  function openHandoffModal(sessionId, displayName) {
    if (!$handoffModal) return;
    handoffSessionId = sessionId || null;
    handoffReady = false;
    handoffSetError('');
    if ($handoffSubtitle) {
      $handoffSubtitle.textContent = displayName
        ? 'Move "' + displayName + '" to a paired node — its git state and working copy travel with it.'
        : 'Move this session to a paired node — its git state and working copy travel with it.';
    }
    if ($handoffPlan) { $handoffPlan.hidden = true; $handoffPlan.innerHTML = ''; }
    if ($handoffConfirmBtn) { $handoffConfirmBtn.hidden = true; $handoffConfirmBtn.disabled = true; $handoffConfirmBtn.textContent = 'Hand off'; }
    if ($handoffRecheckBtn) $handoffRecheckBtn.hidden = true;
    if ($handoffPreflightBtn) { $handoffPreflightBtn.disabled = false; $handoffPreflightBtn.textContent = 'Preflight'; }
    if ($handoffDest) $handoffDest.disabled = false;
    $handoffModal.classList.add('open');
    handoffLoadPeers();
  }
  function handoffClose() {
    if ($handoffModal) $handoffModal.classList.remove('open');
  }

  if ($handoffBackdrop) $handoffBackdrop.addEventListener('click', handoffClose);
  if ($handoffCloseBtn) $handoffCloseBtn.addEventListener('click', handoffClose);
  if ($handoffPreflightBtn) $handoffPreflightBtn.addEventListener('click', handoffPreflight);
  if ($handoffRecheckBtn) $handoffRecheckBtn.addEventListener('click', handoffPreflight);
  if ($handoffConfirmBtn) $handoffConfirmBtn.addEventListener('click', handoffStart);
  if ($handoffDest) $handoffDest.addEventListener('change', handoffPreflight);
  if ($handoffOpenPeers) $handoffOpenPeers.addEventListener('click', () => {
    handoffClose();
    if (typeof openFederationPeersModal === 'function') openFederationPeersModal();
  });
  if ($handoffPlan) $handoffPlan.addEventListener('click', (e) => {
    const code = e.target.closest('[data-handoff-copy]');
    if (!code) return;
    const text = code.getAttribute('data-handoff-copy') || '';
    try {
      navigator.clipboard.writeText(text);
      showOpToast('Resume command copied', 'ok');
    } catch (_) {}
  });
  document.addEventListener('keydown', (e) => {
    if (e.key === 'Escape' && $handoffModal && $handoffModal.classList.contains('open')) {
      handoffClose();
    }
  });

  // "Moved to <node>" chip — when a conversation is opened, fetch its handoff
  // ownership once (no polling). If it's owned elsewhere now, mark it so the
  // breadcrumb renders a small warning chip. Keyed by session id so the chip
  // survives breadcrumb rebuilds (updatePaneHeader re-includes it each pass).
  const _handoffMovedBySid = {};
  const _handoffStatusFetched = new Set();
  function handoffMovedChipHtml(row) {
    if (!row) return '';
    // Look up by both keys: the status fetch keys by the conversation id
    // (usually the session UUID), while rows may expose session_id too.
    const moved = _handoffMovedBySid[row.id] || _handoffMovedBySid[row.session_id];
    if (!moved) return '';
    const owner = moved.owner || 'another node';
    return '<span class="handoff-moved-chip" title="Owned by ' + escapeAttr(owner) + '">Moved to another node</span>';
  }
  function refreshHandoffMovedChip() {
    const bc = document.getElementById('cccBreadcrumb');
    if (!bc) return;
    const existing = bc.querySelector('.handoff-moved-chip');
    if (existing) existing.remove();
    const row = (typeof _statusRailActiveRow !== 'undefined' && _statusRailActiveRow)
      ? _statusRailActiveRow : (typeof openConvRow === 'function' ? openConvRow() : null);
    const html = handoffMovedChipHtml(row);
    if (!html) return;
    const tmp = document.createElement('template');
    tmp.innerHTML = html.trim();
    const chip = tmp.content.firstChild;
    if (!chip) return;
    const title = bc.querySelector('.ccc-breadcrumb-title');
    if (title) bc.insertBefore(chip, title);
    else bc.appendChild(chip);
  }
  async function fetchHandoffStatusForConv(sid) {
    if (!sid || !/^[0-9a-f-]{8,}$/i.test(sid)) return;
    if (_handoffStatusFetched.has(sid)) { refreshHandoffMovedChip(); return; }
    _handoffStatusFetched.add(sid);
    try {
      const r = await fetch('/api/federation/handoff/status?session_id=' + encodeURIComponent(sid), { cache: 'no-store' });
      const data = await r.json().catch(() => ({}));
      if (data && data.ok !== false && data.owned_here === false) {
        _handoffMovedBySid[sid] = { owner: (data.lease && data.lease.owner_node) || data.node_id || 'another node' };
      } else {
        delete _handoffMovedBySid[sid];
      }
    } catch (_) {
      // Federation may be disabled / status endpoint absent — leave no chip.
      _handoffStatusFetched.delete(sid);
    }
    if (typeof currentConversation !== 'undefined' && currentConversation === sid) {
      refreshHandoffMovedChip();
    }
  }
  // Expose for updatePaneHeader (breadcrumb build) and selectConversation.
  window._cccHandoffMovedChipHtml = handoffMovedChipHtml;
  window._cccFetchHandoffStatus = fetchHandoffStatusForConv;

  // ── Fleet view ────────────────────────────────────────────────────
  // The repo × node matrix. Every dimension (worktrees, default branch,
  // PRs, deployment, sessions) is rendered independently, each carrying its
  // own observation time; stale sources are badged rather than hidden. The
  // "Resolve all" flow builds a reviewed plan and runs it as a persisted
  // job, polling to completion. Reuses the fed* helpers (fedEsc/fedShortId),
  // relativeTime, showOpToast and the .upd-* modal shell.
  const $fleetModal = document.getElementById('fleetModal');
  const $fleetBackdrop = document.getElementById('fleetBackdrop');
  const $fleetCloseBtn = document.getElementById('fleetCloseBtn');
  const $fleetBtn = document.getElementById('fleetViewBtn');
  const $fleetRefreshBtn = document.getElementById('fleetRefreshBtn');
  const $fleetRefreshSpinner = document.getElementById('fleetRefreshSpinner');
  const $fleetRefreshTime = document.getElementById('fleetRefreshTime');
  const $fleetResolveBtn = document.getElementById('fleetResolveBtn');
  const $fleetHealthStrip = document.getElementById('fleetHealthStrip');
  const $fleetMatrix = document.getElementById('fleetMatrix');
  const $fleetError = document.getElementById('fleetError');
  let fleetInventory = null;
  let fleetLoading = false;

  function fleetSetError(msg) {
    if (!$fleetError) return;
    $fleetError.textContent = msg || '';
    $fleetError.classList.toggle('visible', !!msg);
  }
  function fleetRel(ts) {
    const n = Number(ts);
    return (isFinite(n) && n > 0) ? relativeTime(n) : 'unknown';
  }
  function fleetObsTitle(label, ts) {
    return (label ? label + ' — ' : '') + 'observed ' + fleetRel(ts);
  }
  function fleetBase(p) {
    const parts = String(p || '').split('/');
    return parts[parts.length - 1] || String(p || '');
  }
  async function fleetGet(path) {
    const r = await fetch(path, { cache: 'no-store' });
    const d = await r.json().catch(() => ({}));
    return { status: r.status, data: d || {} };
  }
  async function fleetPost(path, body) {
    const r = await fetch(path, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(body || {}),
    });
    const d = await r.json().catch(() => ({}));
    return { status: r.status, data: d || {} };
  }

  // ── Node health strip ──
  function renderFleetHealth(nodes) {
    if (!$fleetHealthStrip) return;
    if (!nodes || !nodes.length) {
      $fleetHealthStrip.innerHTML = '<div class="fed-empty">No nodes.</div>';
      return;
    }
    $fleetHealthStrip.innerHTML = nodes.map((n) => {
      const name = n.name || fedShortId(n.node_id);
      const ok = n.ok !== false && !n.error;
      let cls = 'fleet-node-chip ' + (ok ? 'is-ok' : 'is-err');
      if (n.stale) cls += ' is-stale';
      let html = '<span class="fleet-node-name" title="' + fedEsc(n.node_id) + '">' + fedEsc(name) + '</span>';
      if (n.self) html += '<span class="fleet-self-marker" title="This node">self</span>';
      if (ok) html += '<span class="fleet-node-status ok" title="reachable">✓</span>';
      else html += '<span class="fleet-node-status err" title="' + fedEsc(n.detail || n.error || 'unreachable') + '">✗ ' + fedEsc(n.error || 'error') + '</span>';
      if (n.stale) html += '<span class="fleet-stale-badge" title="' + fedEsc(fleetObsTitle('', n.observed_at)) + '">stale: ' + fedEsc(fleetRel(n.observed_at)) + '</span>';
      return '<div class="' + cls + '">' + html + '</div>';
    }).join('');
  }

  // ── Repo matrix ──
  function renderFleetMatrix(repos, nodes) {
    if (!$fleetMatrix) return;
    if (!repos || !repos.length) {
      $fleetMatrix.innerHTML = '<div class="fed-empty">No repositories mapped yet — open a repo to auto-map it, or add a mapping under Nodes &amp; peers.</div>';
      return;
    }
    const nodesById = {};
    (nodes || []).forEach((n) => { nodesById[n.node_id] = n; });
    $fleetMatrix.innerHTML = repos.map((repo) => {
      const nodeIds = Object.keys(repo.nodes || {});
      const cells = nodeIds.map((nid) =>
        renderFleetNodeCell(repo, nid, repo.nodes[nid], nodesById[nid] || { node_id: nid })
      ).join('');
      return '<div class="fleet-repo-card">'
        + '<div class="fleet-repo-head">'
        + (repo.pinned ? '<span class="fleet-pin" title="Pinned">📌</span>' : '')
        + '<span class="fleet-repo-title">' + fedEsc(repo.identity) + '</span>'
        + (repo.kind ? '<span class="fleet-repo-kind">' + fedEsc(repo.kind) + '</span>' : '')
        + '</div>'
        + '<div class="fleet-repo-nodes">' + cells + '</div>'
        + '</div>';
    }).join('');
  }

  function renderFleetNodeCell(repo, nodeId, entry, node) {
    const nodeName = (node && node.name) || (entry && entry.node_name) || fedShortId(nodeId);
    const stale = !!(entry && entry.stale);
    const staleBadge = stale
      ? '<span class="fleet-stale-badge" title="' + fedEsc(fleetObsTitle('', entry.observed_at)) + '">stale: ' + fedEsc(fleetRel(entry.observed_at)) + '</span>'
      : '';
    const head = '<div class="fleet-cell-head">'
      + '<span class="fleet-cell-node" title="' + fedEsc(nodeId) + '">' + fedEsc(nodeName) + '</span>'
      + (node && node.self ? '<span class="fleet-self-marker" title="This node">self</span>' : '')
      + staleBadge
      + '</div>';
    if (!entry || entry.ok === false) {
      const detail = (entry && (entry.detail || entry.error)) || 'inventory failed';
      return '<div class="fleet-cell is-err' + (stale ? ' is-stale' : '') + '">' + head
        + '<div class="fleet-dim"><span class="fleet-chip chip-red" title="' + fedEsc(detail) + '">✗ ' + fedEsc((entry && entry.error) || 'error') + '</span></div>'
        + '<div class="fleet-cell-detail">' + fedEsc(detail) + '</div>'
        + '</div>';
    }
    const body = renderFleetWorktreesDim(repo, nodeId, entry)
      + renderFleetBranchDim(entry)
      + renderFleetPrsDim(entry)
      + renderFleetDeployDim(entry)
      + renderFleetSessionsDim(entry);
    return '<div class="fleet-cell' + (stale ? ' is-stale' : '') + '">' + head + body + '</div>';
  }

  function fleetDim(label, chipsHtml, extraHtml) {
    return '<div class="fleet-dim"><span class="fleet-dim-label">' + label + '</span>'
      + '<div class="fleet-chip-row">' + chipsHtml + '</div>' + (extraHtml || '') + '</div>';
  }

  function renderFleetWorktreesDim(repo, nodeId, entry) {
    const wts = Array.isArray(entry.worktrees) ? entry.worktrees : [];
    const obs = fleetObsTitle('worktrees', entry.observed_at);
    let dirtyFiles = 0, unpublished = 0, cleanable = 0;
    wts.forEach((wt) => {
      if (wt.dirty) dirtyFiles += Number(wt.dirty_files || 0);
      if (wt.unpublished_commits) unpublished += Number(wt.unpublished_commits || 0);
      if (!wt.is_primary_clone && !wt.dirty && wt.merged_into_default === true && !wt.unpublished_commits) cleanable++;
    });
    let chips = '<span class="fleet-chip" title="' + fedEsc(obs) + '">' + wts.length + ' worktree' + (wts.length === 1 ? '' : 's') + '</span>';
    if (dirtyFiles) chips += '<span class="fleet-chip chip-red" title="' + fedEsc(obs) + '">' + dirtyFiles + ' dirty</span>';
    if (unpublished) chips += '<span class="fleet-chip chip-orange" title="' + fedEsc(obs) + '">' + unpublished + ' unpublished</span>';
    if (cleanable) chips += '<span class="fleet-chip chip-green" title="' + fedEsc(obs) + '">' + cleanable + ' cleanable</span>';
    let rows = '';
    const dirty = wts.filter((wt) => wt.dirty);
    if (dirty.length) {
      rows = '<div class="fleet-wt-rows">' + dirty.map((wt) =>
        '<div class="fleet-wt-row">'
        + '<span class="fleet-wt-name" title="' + fedEsc(wt.path || '') + '">' + fedEsc(fleetBase(wt.path)) + (wt.branch ? ' · ' + fedEsc(wt.branch) : '') + '</span>'
        + '<span class="fleet-wt-dirty">' + Number(wt.dirty_files || 0) + ' dirty</span>'
        + '<button type="button" class="upd-btn fleet-mini-btn" data-fleet-who="1"'
        + ' data-fleet-identity="' + fedEsc(repo.identity) + '" data-fleet-node="' + fedEsc(nodeId) + '"'
        + ' data-fleet-path="' + fedEsc(wt.path || '') + '">Who?</button>'
        + '</div>'
      ).join('') + '</div>';
    }
    return fleetDim('Worktrees', chips, rows);
  }

  function renderFleetBranchDim(entry) {
    const db = entry.default_branch || {};
    const obs = fleetObsTitle('default branch', entry.observed_at);
    const sha = db.sha ? String(db.sha).slice(0, 8) : '—';
    let chips = '<span class="fleet-chip" title="' + fedEsc(obs) + '">' + fedEsc(db.branch || '—') + ' @ <span class="fleet-sha">' + fedEsc(sha) + '</span></span>';
    const primary = (entry.worktrees || []).find((wt) => wt.is_primary_clone);
    if (primary && db.sha && primary.head_sha && primary.head_sha !== db.sha
        && primary.branch === db.branch && !primary.unpublished_commits) {
      chips += '<span class="fleet-chip chip-orange" title="local ' + fedEsc(String(primary.head_sha).slice(0, 8))
        + ' vs origin ' + fedEsc(sha) + '">behind origin</span>';
    }
    return fleetDim('Default branch', chips);
  }

  function renderFleetPrsDim(entry) {
    const prs = entry.prs || {};
    const obs = fleetObsTitle('PRs', prs.observed_at || entry.observed_at);
    let chips;
    if (prs.error) {
      chips = '<span class="fleet-chip chip-warn" title="' + fedEsc(String(prs.error)) + '">PR data unavailable</span>';
    } else if (prs.skipped) {
      chips = '<span class="fleet-chip chip-muted" title="' + fedEsc(String(prs.skipped)) + '">no remote</span>';
    } else {
      const open = Array.isArray(prs.open) ? prs.open : [];
      let failing = 0, drafts = 0;
      open.forEach((p) => {
        if (Array.isArray(p.checks_failing) && p.checks_failing.length) failing++;
        if (p.draft) drafts++;
      });
      chips = '<span class="fleet-chip" title="' + fedEsc(obs) + '">' + open.length + ' open</span>';
      if (failing) chips += '<span class="fleet-chip chip-red" title="' + fedEsc(obs) + '">' + failing + ' failing</span>';
      if (drafts) chips += '<span class="fleet-chip chip-muted" title="' + fedEsc(obs) + '">' + drafts + ' draft' + (drafts === 1 ? '' : 's') + '</span>';
    }
    return fleetDim('PRs', chips);
  }

  function renderFleetDeployDim(entry) {
    const dep = entry.deployment || {};
    const obs = fleetObsTitle('deployment', dep.observed_at || entry.observed_at);
    let chip;
    if (dep.error) {
      chip = '<span class="fleet-chip chip-warn" title="' + fedEsc(String(dep.error)) + '">deploy error</span>';
    } else if (dep.skipped) {
      chip = '<span class="fleet-chip chip-muted" title="' + fedEsc(String(dep.skipped)) + '">no deploy</span>';
    } else if (dep.state) {
      const st = String(dep.state).toUpperCase();
      let c = 'chip-muted';
      if (st === 'READY') c = 'chip-green';
      else if (st === 'ERROR') c = 'chip-red';
      else if (st === 'BUILDING' || st === 'QUEUED' || st === 'INITIALIZING') c = 'chip-orange';
      const title = obs + (dep.commit_sha ? ' · ' + String(dep.commit_sha).slice(0, 8) : '');
      chip = '<span class="fleet-chip ' + c + '" title="' + fedEsc(title) + '">' + fedEsc(dep.state) + '</span>';
    } else {
      chip = '<span class="fleet-chip chip-muted" title="' + fedEsc(obs) + '">no data</span>';
    }
    return fleetDim('Deploy', chip);
  }

  function renderFleetSessionsDim(entry) {
    const ss = Array.isArray(entry.sessions) ? entry.sessions : [];
    const obs = fleetObsTitle('sessions', entry.observed_at);
    const live = ss.filter((s) => s.is_live).length;
    let chips = '<span class="fleet-chip" title="' + fedEsc(obs) + '">' + ss.length + ' session' + (ss.length === 1 ? '' : 's') + (live ? ' · ' + live + ' live' : '') + '</span>';
    let badges = '';
    if (ss.length) {
      badges = '<div class="fleet-session-badges">' + ss.slice(0, 8).map((s) =>
        '<span class="fleet-session-badge' + (s.is_live ? ' is-live' : '') + '" title="' + fedEsc(s.ref || s.session_id || '') + '">'
        + fedEsc(s.display_name || fedShortId(s.session_id)) + '</span>'
      ).join('') + (ss.length > 8 ? '<span class="fleet-session-badge more">+' + (ss.length - 8) + '</span>' : '') + '</div>';
    }
    return fleetDim('Sessions', chips, badges);
  }

  function renderFleetView(data) {
    fleetInventory = data;
    renderFleetHealth((data && data.nodes) || []);
    renderFleetMatrix((data && data.repos) || [], (data && data.nodes) || []);
    if ($fleetRefreshTime) $fleetRefreshTime.textContent = 'Updated ' + fleetRel(data && data.observed_at);
  }

  async function loadFleetInventory(fetchRemote) {
    if (fleetLoading) return;
    fleetLoading = true;
    fleetSetError('');
    if ($fleetRefreshBtn) $fleetRefreshBtn.disabled = true;
    if ($fleetRefreshSpinner) $fleetRefreshSpinner.hidden = false;
    try {
      const { status, data } = await fleetGet('/api/fleet/inventory?fetch=' + (fetchRemote ? '1' : '0'));
      if (status !== 200 || !data || data.ok === false) {
        fleetSetError('Could not load the fleet: ' + ((data && (data.detail || data.error)) || ('HTTP ' + status)));
      } else {
        renderFleetView(data);
      }
    } catch (e) {
      fleetSetError('Could not load the fleet: ' + ((e && e.message) || 'unknown'));
    }
    if ($fleetRefreshSpinner) $fleetRefreshSpinner.hidden = true;
    if ($fleetRefreshBtn) $fleetRefreshBtn.disabled = false;
    fleetLoading = false;
  }

  function openFleetView() {
    if (!$fleetModal) return;
    fleetSetError('');
    if ($fleetHealthStrip) $fleetHealthStrip.innerHTML = '<div class="fed-empty">Loading…</div>';
    if ($fleetMatrix) $fleetMatrix.innerHTML = '';
    $fleetModal.classList.add('open');
    loadFleetInventory(false);
  }
  function fleetClose() {
    if ($fleetModal) $fleetModal.classList.remove('open');
    fleetHideAttrPopover();
  }

  // ── "Who?" attribution popover ──
  // A floating popover (appended to <body> so it layers above the modal),
  // positioned under the clicked button. Lists candidate sessions with
  // confidence + evidence kinds, each offering a "Ping to commit".
  let $fleetAttrPop = null;
  function fleetEnsureAttrPopover() {
    if ($fleetAttrPop) return $fleetAttrPop;
    const el = document.createElement('div');
    el.className = 'fleet-attr-popover';
    el.hidden = true;
    document.body.appendChild(el);
    $fleetAttrPop = el;
    document.addEventListener('click', (e) => {
      if (!$fleetAttrPop || $fleetAttrPop.hidden) return;
      if ($fleetAttrPop.contains(e.target)) return;
      if (e.target.closest('[data-fleet-who]')) return;
      fleetHideAttrPopover();
    });
    return el;
  }
  function fleetHideAttrPopover() {
    if ($fleetAttrPop) { $fleetAttrPop.hidden = true; $fleetAttrPop.innerHTML = ''; }
  }
  function fleetPositionPopover(btn) {
    const el = $fleetAttrPop;
    if (!el || !btn) return;
    const r = btn.getBoundingClientRect();
    el.style.top = (r.bottom + 6) + 'px';
    el.style.left = r.left + 'px';
    const rect = el.getBoundingClientRect();
    if (rect.right > window.innerWidth - 8) {
      el.style.left = Math.max(8, window.innerWidth - 8 - rect.width) + 'px';
    }
    if (rect.bottom > window.innerHeight - 8) {
      el.style.top = Math.max(8, r.top - rect.height - 6) + 'px';
    }
  }
  async function fleetShowWho(btn) {
    const el = fleetEnsureAttrPopover();
    const identity = btn.getAttribute('data-fleet-identity') || '';
    const nodeId = btn.getAttribute('data-fleet-node') || '';
    const path = btn.getAttribute('data-fleet-path') || '';
    el.hidden = false;
    el.innerHTML = '<div class="fleet-attr-loading">Attributing…</div>';
    fleetPositionPopover(btn);
    const body = { path };
    if (identity) body.identity = identity;
    if (nodeId) body.node_id = nodeId;
    let res;
    try {
      res = await fleetPost('/api/fleet/attribute', body);
    } catch (e) {
      el.innerHTML = '<div class="fleet-attr-empty">Attribution failed: ' + fedEsc((e && e.message) || 'error') + '</div>';
      fleetPositionPopover(btn);
      return;
    }
    const data = res.data || {};
    if (res.status !== 200 || data.ok === false) {
      el.innerHTML = '<div class="fleet-attr-empty">' + fedEsc(data.detail || data.error || 'attribution failed') + '</div>';
      fleetPositionPopover(btn);
      return;
    }
    const cands = Array.isArray(data.candidates) ? data.candidates : [];
    let html = '<div class="fleet-attr-head" title="' + fedEsc(path) + '">Who touched ' + fedEsc(fleetBase(path)) + '?</div>';
    if (!cands.length) {
      html += '<div class="fleet-attr-empty">unknown — no evidence</div>';
    } else {
      html += cands.map((c) => {
        const evk = Array.isArray(c.evidence) ? c.evidence.map((e) => e.kind).filter(Boolean) : [];
        const uniqEv = evk.filter((v, i) => evk.indexOf(v) === i);
        return '<div class="fleet-attr-cand">'
          + '<div class="fleet-attr-cand-head">'
          + '<span class="fleet-attr-name">' + fedEsc(c.display_name || fedShortId(c.session_id)) + '</span>'
          + '<span class="fleet-attr-conf conf-' + fedEsc(c.confidence || 'low') + '">' + fedEsc(c.confidence || 'low') + '</span>'
          + (c.is_live ? '<span class="fleet-attr-live">live</span>' : '')
          + '</div>'
          + '<div class="fleet-attr-ev" title="' + fedEsc(uniqEv.join(', ')) + '">' + fedEsc(uniqEv.join(', ') || 'correlated') + '</div>'
          + '<button type="button" class="upd-btn fleet-mini-btn" data-fleet-ping="1"'
          + ' data-fleet-ref="' + fedEsc(c.ref || c.session_id || '') + '"'
          + ' data-fleet-target="' + fedEsc(path) + '">Ping to commit</button>'
          + '</div>';
      }).join('');
    }
    el.innerHTML = html;
    fleetPositionPopover(btn);
  }
  async function fleetPing(btn) {
    const ref = btn.getAttribute('data-fleet-ref') || '';
    const target = btn.getAttribute('data-fleet-target') || '';
    if (!ref) return;
    btn.disabled = true;
    btn.textContent = 'Pinging…';
    try {
      const { status, data } = await fleetPost('/api/fleet/ping-session', { ref, kind: 'commit', target });
      if (status === 200 && data.ok !== false) {
        showOpToast('Pinged the session to commit', 'ok');
        btn.textContent = 'Pinged ✓';
      } else {
        showOpToast('Ping failed: ' + ((data && (data.detail || data.error)) || 'error'), 'error');
        btn.disabled = false;
        btn.textContent = 'Ping to commit';
      }
    } catch (e) {
      showOpToast('Ping failed: ' + ((e && e.message) || 'error'), 'error');
      btn.disabled = false;
      btn.textContent = 'Ping to commit';
    }
  }

  // ── Resolve-all: plan review + job progress ──
  const $fleetPlanModal = document.getElementById('fleetPlanModal');
  const $fleetPlanBackdrop = document.getElementById('fleetPlanBackdrop');
  const $fleetPlanCancel = document.getElementById('fleetPlanCancel');
  const $fleetPlanConfirm = document.getElementById('fleetPlanConfirm');
  const $fleetPlanBody = document.getElementById('fleetPlanBody');
  const $fleetPlanError = document.getElementById('fleetPlanError');
  const $fleetPlanSubtitle = document.getElementById('fleetPlanSubtitle');
  let fleetPlan = null;
  let fleetJobPlanId = null;
  let fleetJobPollTimer = null;

  function fleetPlanSetError(msg) {
    if (!$fleetPlanError) return;
    $fleetPlanError.textContent = msg || '';
    $fleetPlanError.classList.toggle('visible', !!msg);
  }
  function fleetPlanStopPolling() {
    if (fleetJobPollTimer) { clearTimeout(fleetJobPollTimer); fleetJobPollTimer = null; }
  }
  function fleetPlanClose() {
    fleetPlanStopPolling();
    if ($fleetPlanModal) $fleetPlanModal.classList.remove('open');
  }

  function fleetEvidenceSummary(ev) {
    if (!ev || typeof ev !== 'object') return '';
    const parts = [];
    if (ev.dirty_files != null) parts.push(ev.dirty_files + ' dirty');
    if (ev.unpublished_commits != null) parts.push(ev.unpublished_commits + ' unpublished');
    if (ev.head_sha) parts.push('head ' + String(ev.head_sha).slice(0, 8));
    if (ev.origin_head) parts.push('origin ' + String(ev.origin_head).slice(0, 8));
    if (ev.local_head) parts.push('local ' + String(ev.local_head).slice(0, 8));
    if (ev.merged_into_default === true) parts.push('merged into default');
    if (ev.attribution) parts.push(String(ev.attribution));
    if (ev.pr && ev.pr.number) parts.push('PR #' + ev.pr.number);
    if (Array.isArray(ev.candidate_sessions) && ev.candidate_sessions.length) {
      const names = ev.candidate_sessions.map((s) => s.display_name || fedShortId(s.session_id)).filter(Boolean).slice(0, 3);
      if (names.length) parts.push('candidates: ' + names.join(', '));
    }
    if (ev.deployment && ev.deployment.state) parts.push('deploy ' + ev.deployment.state);
    if (Array.isArray(ev.failing) && ev.failing.length) parts.push('failing: ' + ev.failing.slice(0, 3).join(', '));
    if (!parts.length) return '';
    return fedEsc(parts.join(' · '));
  }

  function renderFleetPlanAction(a) {
    const status = a.status || ((a.blockers && a.blockers.length) ? 'blocked' : 'proposed');
    const selectable = status === 'proposed';
    let cls = 'fleet-action';
    if (a.destructive) cls += ' is-destructive';
    if (!selectable) cls += ' is-locked';
    let html = '<label class="' + cls + '" data-fleet-action-id="' + fedEsc(a.id) + '">';
    html += '<input type="checkbox" class="fleet-action-check" ' + (selectable ? 'checked' : 'disabled')
      + ' data-fleet-action-check="' + fedEsc(a.id) + '">';
    html += '<div class="fleet-action-main">';
    html += '<div class="fleet-action-top">'
      + '<span class="fleet-kind-badge kind-' + fedEsc(a.kind) + (a.destructive ? ' is-destructive' : '') + '">' + fedEsc(a.kind) + '</span>'
      + (a.destructive ? '<span class="fleet-destructive-tag" title="Destructive action">destructive</span>' : '')
      + (status !== 'proposed' ? '<span class="fleet-status-tag status-' + fedEsc(status) + '">' + fedEsc(status) + '</span>' : '')
      + (a.target ? '<span class="fleet-action-target" title="' + fedEsc(a.target) + '">' + fedEsc(a.target) + '</span>' : '')
      + '</div>';
    if (a.reason) html += '<div class="fleet-action-reason">' + fedEsc(a.reason) + '</div>';
    if (a.command_intent) html += '<div class="fleet-action-cmd' + (a.destructive ? ' is-destructive' : '') + '"><code>' + fedEsc(a.command_intent) + '</code></div>';
    const ev = fleetEvidenceSummary(a.evidence);
    if (ev) html += '<div class="fleet-action-ev">' + ev + '</div>';
    const blockers = Array.isArray(a.blockers) ? a.blockers : [];
    if (blockers.length) {
      html += '<div class="fleet-action-blockers">' + blockers.map((b) =>
        '<span class="fleet-blocker" title="' + fedEsc(b.detail || '') + '"><span class="fleet-blocker-code">'
        + fedEsc(b.code || 'blocked') + '</span>' + (b.detail ? ' ' + fedEsc(b.detail) : '') + '</span>'
      ).join('') + '</div>';
    } else if (status === 'manual') {
      html += '<div class="fleet-action-blockers"><span class="fleet-blocker"><span class="fleet-blocker-code">manual</span> needs a human — not auto-executable</span></div>';
    }
    html += '</div></label>';
    return html;
  }

  function renderFleetPlan(plan) {
    if (!$fleetPlanBody) return;
    const actions = Array.isArray(plan.actions) ? plan.actions : [];
    if (!actions.length) {
      $fleetPlanBody.innerHTML = '<div class="fed-empty">Nothing to resolve — every repo is clean and published.</div>';
      if ($fleetPlanConfirm) $fleetPlanConfirm.hidden = true;
      return;
    }
    const byRepo = {};
    actions.forEach((a) => {
      const k = a.repo_identity || '(repo)';
      (byRepo[k] = byRepo[k] || []).push(a);
    });
    let html = '';
    Object.keys(byRepo).sort().forEach((repoKey) => {
      html += '<div class="fleet-plan-repo"><div class="fleet-plan-repo-title">' + fedEsc(repoKey) + '</div>';
      const byNode = {};
      byRepo[repoKey].forEach((a) => {
        const nk = a.node_name || fedShortId(a.node_id) || 'this node';
        (byNode[nk] = byNode[nk] || []).push(a);
      });
      Object.keys(byNode).forEach((nodeKey) => {
        html += '<div class="fleet-plan-node"><div class="fleet-plan-node-title">' + fedEsc(nodeKey) + '</div>';
        byNode[nodeKey].forEach((a) => { html += renderFleetPlanAction(a); });
        html += '</div>';
      });
      html += '</div>';
    });
    $fleetPlanBody.innerHTML = html;
    fleetUpdatePlanConfirm();
  }

  function fleetUpdatePlanConfirm() {
    if (!$fleetPlanConfirm || !$fleetPlanBody) return;
    const n = $fleetPlanBody.querySelectorAll('.fleet-action-check:checked:not(:disabled)').length;
    $fleetPlanConfirm.textContent = n ? ('Confirm ' + n + ' action' + (n === 1 ? '' : 's')) : 'Confirm';
    $fleetPlanConfirm.disabled = n === 0;
  }

  async function openFleetPlan() {
    if (!$fleetPlanModal) return;
    fleetPlanStopPolling();
    fleetPlanSetError('');
    fleetJobPlanId = null;
    if ($fleetPlanSubtitle) {
      $fleetPlanSubtitle.hidden = false;
      $fleetPlanSubtitle.textContent = 'Review the proposed actions. Destructive steps are outlined in red. Nothing runs until you confirm.';
    }
    if ($fleetPlanBody) $fleetPlanBody.innerHTML = '<div class="fed-empty">Building plan…</div>';
    if ($fleetPlanConfirm) { $fleetPlanConfirm.hidden = false; $fleetPlanConfirm.disabled = true; $fleetPlanConfirm.textContent = 'Confirm'; }
    if ($fleetPlanCancel) $fleetPlanCancel.textContent = 'Cancel';
    $fleetPlanModal.classList.add('open');
    try {
      const { status, data } = await fleetPost('/api/fleet/plan', {});
      if (status !== 200 || !data || data.ok === false || !data.plan) {
        fleetPlanSetError('Could not build a plan: ' + ((data && (data.detail || data.error)) || ('HTTP ' + status)));
        if ($fleetPlanBody) $fleetPlanBody.innerHTML = '';
        if ($fleetPlanConfirm) $fleetPlanConfirm.hidden = true;
        return;
      }
      fleetPlan = data.plan;
      renderFleetPlan(fleetPlan);
    } catch (e) {
      fleetPlanSetError('Could not build a plan: ' + ((e && e.message) || 'unknown'));
      if ($fleetPlanBody) $fleetPlanBody.innerHTML = '';
      if ($fleetPlanConfirm) $fleetPlanConfirm.hidden = true;
    }
  }

  async function fleetConfirmPlan() {
    if (!fleetPlan || !$fleetPlanBody) return;
    const ids = Array.from($fleetPlanBody.querySelectorAll('.fleet-action-check:checked:not(:disabled)'))
      .map((c) => c.getAttribute('data-fleet-action-check'));
    if (!ids.length) { fleetPlanSetError('Select at least one action.'); return; }
    fleetPlanSetError('');
    if ($fleetPlanConfirm) { $fleetPlanConfirm.disabled = true; $fleetPlanConfirm.textContent = 'Starting…'; }
    try {
      const { status, data } = await fleetPost('/api/fleet/execute', { plan_id: fleetPlan.plan_id, selected: ids });
      if (status !== 200 || data.ok === false) {
        fleetPlanSetError('Could not start: ' + ((data && (data.detail || data.error)) || ('HTTP ' + status)));
        if ($fleetPlanConfirm) { $fleetPlanConfirm.disabled = false; fleetUpdatePlanConfirm(); }
        return;
      }
      fleetJobPlanId = fleetPlan.plan_id;
      if ($fleetPlanSubtitle) $fleetPlanSubtitle.textContent = 'Running ' + data.selected + ' action' + (data.selected === 1 ? '' : 's') + '…';
      if ($fleetPlanConfirm) $fleetPlanConfirm.hidden = true;
      if ($fleetPlanCancel) $fleetPlanCancel.textContent = 'Close';
      fleetPollJob();
    } catch (e) {
      fleetPlanSetError('Could not start: ' + ((e && e.message) || 'unknown'));
      if ($fleetPlanConfirm) { $fleetPlanConfirm.disabled = false; fleetUpdatePlanConfirm(); }
    }
  }

  function renderFleetJob(job) {
    if (!$fleetPlanBody) return;
    const actions = Array.isArray(job.actions) ? job.actions : [];
    const active = actions.filter((a) => a.status && a.status !== 'skipped' && a.status !== 'proposed');
    let html = '<div class="fleet-job-status">Job ' + fedEsc(job.status || '') + '</div>';
    html += '<div class="fleet-job-actions">' + active.map((a) => {
      const st = a.status || '';
      let icon = '', cls = '';
      if (st === 'running') { icon = '<span class="fleet-spinner"></span>'; cls = 'is-running'; }
      else if (st === 'done') { icon = '✓'; cls = 'is-done'; }
      else if (st === 'failed') { icon = '✗'; cls = 'is-failed'; }
      else if (st === 'stopped_stale') { icon = '⚠'; cls = 'is-stale'; }
      else { icon = '…'; cls = 'is-pending'; }
      const detail = a.result && (a.result.detail || a.result.error);
      return '<div class="fleet-job-action ' + cls + '">'
        + '<span class="fleet-job-icon">' + icon + '</span>'
        + '<span class="fleet-job-kind">' + fedEsc(a.kind) + '</span>'
        + '<span class="fleet-job-target" title="' + fedEsc(a.target || '') + '">' + fedEsc(a.target || '') + '</span>'
        + (detail ? '<span class="fleet-job-detail">' + fedEsc(detail) + '</span>' : '')
        + '</div>';
    }).join('') + '</div>';
    const log = Array.isArray(job.log) ? job.log : [];
    if (log.length) {
      html += '<div class="fleet-job-log">' + log.slice(-60).map((l) =>
        '<div class="fleet-log-line level-' + fedEsc(l.level || 'info') + '">'
        + '<span class="fleet-log-t">' + fedEsc(fleetRel(l.t)) + '</span> ' + fedEsc(l.text || '') + '</div>'
      ).join('') + '</div>';
    }
    $fleetPlanBody.innerHTML = html;
  }

  async function fleetPollJob() {
    if (!fleetJobPlanId) return;
    let done = false;
    try {
      const { status, data } = await fleetGet('/api/fleet/job?id=' + encodeURIComponent(fleetJobPlanId));
      if (status === 200 && data.ok !== false && data.job) {
        renderFleetJob(data.job);
        done = data.job.status === 'finished';
      }
    } catch (_) { /* transient — keep polling */ }
    if (done) {
      fleetPlanStopPolling();
      if (!$fleetModal || $fleetModal.classList.contains('open')) loadFleetInventory(false);
      return;
    }
    fleetJobPollTimer = setTimeout(fleetPollJob, 1500);
  }

  // ── Fleet event wiring ──
  if ($fleetBtn) $fleetBtn.addEventListener('click', () => {
    if (typeof $settingsPopover !== 'undefined' && $settingsPopover) $settingsPopover.classList.remove('open');
    openFleetView();
  });
  if ($fleetBackdrop) $fleetBackdrop.addEventListener('click', fleetClose);
  if ($fleetCloseBtn) $fleetCloseBtn.addEventListener('click', fleetClose);
  if ($fleetRefreshBtn) $fleetRefreshBtn.addEventListener('click', () => loadFleetInventory(true));
  if ($fleetResolveBtn) $fleetResolveBtn.addEventListener('click', openFleetPlan);
  if ($fleetMatrix) $fleetMatrix.addEventListener('click', (e) => {
    const who = e.target.closest('[data-fleet-who]');
    if (who) { e.preventDefault(); e.stopPropagation(); fleetShowWho(who); }
  });
  document.addEventListener('click', (e) => {
    const ping = e.target.closest('[data-fleet-ping]');
    if (ping) { e.preventDefault(); fleetPing(ping); }
  });
  if ($fleetPlanBackdrop) $fleetPlanBackdrop.addEventListener('click', fleetPlanClose);
  if ($fleetPlanCancel) $fleetPlanCancel.addEventListener('click', fleetPlanClose);
  if ($fleetPlanConfirm) $fleetPlanConfirm.addEventListener('click', fleetConfirmPlan);
  if ($fleetPlanBody) $fleetPlanBody.addEventListener('change', (e) => {
    if (e.target.closest('.fleet-action-check')) fleetUpdatePlanConfirm();
  });
  document.addEventListener('keydown', (e) => {
    if (e.key !== 'Escape') return;
    if ($fleetPlanModal && $fleetPlanModal.classList.contains('open')) { fleetPlanClose(); return; }
    if ($fleetModal && $fleetModal.classList.contains('open')) fleetClose();
  });

  // If we just finished restarting, briefly acknowledge the trigger.
  try {
    if (sessionStorage.getItem('ccc-restarting')) {
      sessionStorage.removeItem('ccc-restarting');
      showOpToast('Server restarted', 'ok');
    } else if (sessionStorage.getItem('ccc-updating')) {
      sessionStorage.removeItem('ccc-updating');
      showOpToast('Updated to the latest version', 'ok');
    }
  } catch (_) {}

  // ── Sidebar primary "+ New session" button ─────────────────────
  // Opens an empty conversation pane on the right with the input bar
  // ready to receive a prompt — pressing Enter spawns a fresh agent.
  const $sidebarNewBtn = document.getElementById('sidebarNewBtn');
  if ($sidebarNewBtn) {
    $sidebarNewBtn.addEventListener('click', () => {
      if (isFlowView()) createFlowDraftSession();
      else enterNewSessionMode();
    });
  }

  // ── Sidebar "+ New Group chat" button ──────────────────────────
  // Creates an empty group chat (the user renames it via ✏️ on the
  // row and drags sessions in to add participants). Same affordance
  // as the inline "+" inside the In Progress section's group-chat
  // header — duplicated up here so it's always visible without
  // scrolling, mirroring the "+ New session" button.
  const $sidebarNewGroupChatBtn = document.getElementById('sidebarNewGroupChatBtn');
  if ($sidebarNewGroupChatBtn) {
    $sidebarNewGroupChatBtn.addEventListener('click', () => {
      try { createEmptyGroupChat(); }
      catch (_) { /* function defined later in same scope; ignore early-click race */ }
    });
  }
  const $sidebarGroupChatLiveBtn = document.getElementById('sidebarGroupChatLiveBtn');
  if ($sidebarGroupChatLiveBtn) {
    // One live window only (CCC-103): a NAMED window.open lets the browser
    // reuse the existing tab/window; keeping the handle lets us focus it.
    let _gcLiveWindow = null;
    $sidebarGroupChatLiveBtn.addEventListener('click', () => {
      // Mac app shell (WKWebView): window.open('', name) surfaces as an
      // about:blank/empty navigation that older shells hand to NSWorkspace —
      // Finder then shows "The application can't be opened. -50". Use the
      // plain named open there; the shell raises the popout on navigation.
      if (window.__CCC_MAC_APP__) {
        _gcLiveWindow = window.open('/group-chat-live.html', 'ccc-gc-live');
        try { if (_gcLiveWindow) _gcLiveWindow.focus(); } catch (_) {}
        return;
      }
      // Re-acquire the named window with an EMPTY url: window.open('', name)
      // returns the existing window without navigating it. Opening with the
      // real URL re-navigates (reloads) the live page, and the browser won't
      // raise a window that's mid-reload — that's why "Live" didn't pop it
      // to the front after a dashboard reload lost the handle.
      let w = null;
      try {
        w = (_gcLiveWindow && !_gcLiveWindow.closed)
          ? _gcLiveWindow
          : window.open('', 'ccc-gc-live');
      } catch (_) {}
      if (!w) { _gcLiveWindow = window.open('/group-chat-live.html', 'ccc-gc-live'); return; }
      _gcLiveWindow = w;
      let blank = false;
      try { blank = !/group-chat-live/.test(w.location.pathname); } catch (_) { blank = true; }
      if (blank) {
        try { w.location.replace('/group-chat-live.html'); } catch (_) {}
      } else {
        showOpToast('Live group chat window focused');
      }
      try { w.focus(); } catch (_) {}
    });
  }
  // "Manage group chats" modal — lists every chat from _gcActiveChats
  // with a per-row pause / unpause toggle. Opens from the gear button
  // next to "+ New Group chat".
  const $sidebarManageGroupChatsBtn = document.getElementById('sidebarManageGroupChatsBtn');
  const $gcManageModal = document.getElementById('gcManageModal');
  const $gcManageBody = document.getElementById('gcManageBody');
  function _gcManageRender() {
    if (!$gcManageBody) return;
    const chats = Array.isArray(_gcActiveChats) ? _gcActiveChats.slice() : [];
    if (!chats.length) {
      $gcManageBody.innerHTML = '<div style="padding:24px;color:var(--text-muted);text-align:center;">No group chats yet. Use "+ New Group chat" to create one.</div>';
      return;
    }
    // Newest first by last_activity / last_mtime so the row the user
    // is most likely to touch shows at the top.
    chats.sort((a, b) => {
      const at = Math.max(a.last_activity || 0, a.last_mtime || 0);
      const bt = Math.max(b.last_activity || 0, b.last_mtime || 0);
      return bt - at;
    });
    const rows = chats.map(chat => {
      const topic = chat.topic || '(unnamed chat)';
      const id = chat.uuid || chat.id || '';
      const path = chat.path_tilde || chat.path || '';
      const paused = chat.paused === true
        || chat.status === 'paused'
        || chat.orchestrator_timer_active === false;
      const closed = chat.status === 'closed';
      const participants = Array.isArray(chat.session_ids) ? chat.session_ids.length : 0;
      const ageSec = (() => {
        const t = Math.max(chat.last_activity || 0, chat.last_mtime || 0);
        if (!t) return null;
        return Math.max(0, Math.floor(Date.now() / 1000 - t));
      })();
      const ageLabel = ageSec == null
        ? ''
        : (ageSec < 60 ? 'just now'
          : ageSec < 3600 ? Math.floor(ageSec / 60) + 'm ago'
          : Math.floor(ageSec / 3600) + 'h ago');
      const statusLabel = closed ? 'closed'
        : paused ? 'paused'
        : 'active';
      const statusColor = closed ? 'var(--text-muted)'
        : paused ? 'var(--orange)'
        : 'var(--green)';
      const btnLabel = closed ? '—'
        : paused ? 'Resume'
        : 'Pause';
      const btnDisabled = closed ? ' disabled' : '';
      return ''
        + '<div class="gc-manage-row" style="display:flex;align-items:center;gap:10px;padding:10px 12px;border-bottom:1px solid var(--border);">'
        +   '<div style="flex:1 1 auto;min-width:0;">'
        +     '<div style="font-weight:600;color:var(--text);white-space:nowrap;overflow:hidden;text-overflow:ellipsis;">' + escapeHtml(topic) + '</div>'
        +     '<div style="font-size:11px;color:var(--text-muted);">'
        +       '<span style="color:' + statusColor + ';">' + statusLabel + '</span>'
        +       ' · ' + participants + (participants === 1 ? ' session' : ' sessions')
        +       (ageLabel ? ' · ' + ageLabel : '')
        +     '</div>'
        +   '</div>'
        +   '<button type="button" class="btn" data-gc-manage-toggle'
        +     ' data-gc-path="' + escapeAttr(path) + '"'
        +     ' data-gc-id="' + escapeAttr(id) + '"'
        +     ' data-gc-target-paused="' + (paused ? '0' : '1') + '"'
        +     btnDisabled + '>' + btnLabel + '</button>'
        + '</div>';
    }).join('');
    $gcManageBody.innerHTML = rows;
    // Wire each row's pause/resume button.
    $gcManageBody.querySelectorAll('[data-gc-manage-toggle]').forEach(btn => {
      btn.addEventListener('click', async () => {
        const path = btn.getAttribute('data-gc-path') || '';
        const id = btn.getAttribute('data-gc-id') || '';
        const target = btn.getAttribute('data-gc-target-paused') === '1';
        btn.disabled = true;
        btn.textContent = target ? 'Pausing…' : 'Resuming…';
        try {
          await setGroupChatPaused(path, id, target);
        } catch (_) { /* setGroupChatPaused surfaces its own toast */ }
        _gcManageRender();
      });
    });
  }
  function _gcManageOpen() {
    if (!$gcManageModal) return;
    _gcManageRender();
    $gcManageModal.hidden = false;
    $gcManageModal.classList.add('open');
    // Refresh from the server in case the cache is stale, then re-render.
    if (typeof pollGcActive === 'function') {
      try { pollGcActive().then(_gcManageRender).catch(() => {}); } catch (_) {}
    }
  }
  function _gcManageClose() {
    if (!$gcManageModal) return;
    $gcManageModal.hidden = true;
    $gcManageModal.classList.remove('open');
  }
  if ($sidebarManageGroupChatsBtn) $sidebarManageGroupChatsBtn.addEventListener('click', _gcManageOpen);
  if ($gcManageModal) {
    $gcManageModal.querySelectorAll('[data-gc-manage-close]').forEach(el => {
      el.addEventListener('click', _gcManageClose);
    });
    document.addEventListener('keydown', (ev) => {
      if (ev.key === 'Escape' && !$gcManageModal.hidden) _gcManageClose();
    });
  }

  // ── Spawn cwd picker (new-session mode) ──────────────────────────────
  // Populates a path input above the input box so the user picks or types
  // exactly where the new session will land. This is the explicit repo
  // context for All-repos mode.
  const SPAWN_CWD_KEY = 'ccc-spawn-cwd';
  const SPAWN_CWD_CHIP_LIMIT = 6;
  let spawnCwdOptions = [];

  function normalizeSpawnCwdPath(value) {
    return String(value || '').trim();
  }

  function findSpawnCwdRepo(path) {
    const wanted = normalizeSpawnCwdPath(path);
    if (!wanted || !repoListState || !Array.isArray(repoListState.repos)) return null;
    return repoListState.repos.find(r => r && r.path === wanted) || null;
  }

  function spawnCwdLabel(path) {
    const wanted = normalizeSpawnCwdPath(path);
    if (!wanted) return '';
    const match = findSpawnCwdRepo(wanted);
    return (match && (match.label || match.path)) || _pathLeaf(wanted) || wanted;
  }

  function populateSpawnCwdPicker() {
    const sel = document.getElementById('spawnCwdPicker');
    if (!sel) return;

    // Source list: known repos (recent ∪ pinned). Reuse the dropdown's
    // own option-builder for label disambiguation but strip the "All"
    // sentinel — spawning needs an exact folder.
    let options = [];
    try {
      options = (typeof _archiveFolderOptions === 'function')
        ? _archiveFolderOptions()
        : [];
    } catch (_) {}
    if (!options.length && repoListState && Array.isArray(repoListState.repos)) {
      options = repoListState.repos.map(r => ({
        value: r.path, path: r.path, label: r.label || r.path,
      }));
    }
    // Deduplicate by path — folder filter and repoListState can overlap.
    const seen = new Set();
    options = options.filter(o => {
      const key = o.value || o.path;
      if (!key || seen.has(key)) return false;
      seen.add(key);
      return true;
    });
    spawnCwdOptions = options.map(o => ({
      value: o.value || o.path,
      path: o.path || o.value,
      label: o.label || o.value || o.path,
    })).filter(o => o.value);

    // Default selection priority:
    //   1. User's last spawn cwd (localStorage)
    //   2. The popout's pinned repo (conversation popout only)
    //   3. First known repo option
    let saved = '';
    try { saved = normalizeSpawnCwdPath(localStorage.getItem(SPAWN_CWD_KEY) || ''); } catch (_) {}
    const defaultPath = saved
      || popoutRepoPath()
      || (options[0] && (options[0].value || options[0].path))
      || '';

    const prevValue = normalizeSpawnCwdPath(sel.value);
    sel.value = prevValue || defaultPath;
    if (isSpawnCwdMenuOpen()) renderSpawnCwdMenu('');
    renderSpawnCwdQuickChips();
  }

  function spawnCwdOptionForPath(path) {
    const value = normalizeSpawnCwdPath(path);
    if (!value) return null;
    const known = findSpawnCwdRepo(value);
    return {
      value,
      label: (known && (known.label || known.path)) || _pathLeaf(value) || value,
    };
  }

  function spawnCwdQuickChipOptions(current) {
    const wanted = normalizeSpawnCwdPath(current);
    const out = [];
    const seen = new Set();
    const addPath = (path) => {
      const opt = spawnCwdOptionForPath(path);
      if (!opt || seen.has(opt.value)) return;
      seen.add(opt.value);
      out.push(opt);
    };

    for (const path of ((repoListState && repoListState.recent) || [])) {
      addPath(path);
      if (out.length >= SPAWN_CWD_CHIP_LIMIT) break;
    }
    if (out.length < SPAWN_CWD_CHIP_LIMIT) {
      for (const opt of (spawnCwdOptions || [])) {
        addPath(opt && opt.value);
        if (out.length >= SPAWN_CWD_CHIP_LIMIT) break;
      }
    }
    if (!out.length) {
      for (const repo of ((repoListState && repoListState.repos) || [])) {
        addPath(repo && repo.path);
        if (out.length >= SPAWN_CWD_CHIP_LIMIT) break;
      }
    }
    if (wanted && !seen.has(wanted)) {
      const currentOpt = spawnCwdOptionForPath(wanted);
      if (currentOpt) out.unshift(currentOpt);
    }
    return out.slice(0, SPAWN_CWD_CHIP_LIMIT);
  }

  function renderNewSessionRepoSuggestions(root) {
    const wrap = (root || document).querySelector('#nsRepoSuggestions');
    if (!wrap) return;
    const current = getSpawnCwd();
    const chips = spawnCwdQuickChipOptions(current);
    wrap.innerHTML = '';
    if (!chips.length) {
      wrap.hidden = true;
      return;
    }
    wrap.hidden = false;
    const label = document.createElement('div');
    label.className = 'ns-choice-title';
    label.textContent = 'Pick a repo';
    wrap.appendChild(label);
    const row = document.createElement('div');
    row.className = 'ns-repo-chips';
    wrap.appendChild(row);
    for (const opt of chips) {
      const active = normalizeSpawnCwdPath(opt.value) === normalizeSpawnCwdPath(current);
      const btn = document.createElement('button');
      btn.type = 'button';
      btn.className = 'ns-repo-chip' + (active ? ' is-current' : '');
      btn.textContent = opt.label;
      btn.title = 'Start the new session in ' + opt.value;
      btn.setAttribute('data-ns-repo', opt.value);
      btn.setAttribute('aria-pressed', active ? 'true' : 'false');
      row.appendChild(btn);
    }
  }

  function renderSpawnCwdQuickChips() {
    const wrap = document.getElementById('spawnCwdQuickChips');
    if (!wrap) return;
    const current = getSpawnCwd();
    const chips = spawnCwdQuickChipOptions(current);
    wrap.innerHTML = '';
    wrap.style.display = chips.length ? '' : 'none';
    if (chips.length) {
      const label = document.createElement('span');
      label.className = 'spawn-cwd-chip-label';
      label.textContent = 'Recent folders';
      wrap.appendChild(label);
    }
    for (const opt of chips) {
      const active = normalizeSpawnCwdPath(opt.value) === normalizeSpawnCwdPath(current);
      const btn = document.createElement('button');
      btn.type = 'button';
      btn.className = 'spawn-cwd-chip' + (active ? ' active' : '');
      btn.textContent = opt.label;
      btn.title = 'Use ' + opt.value + ' as the folder';
      btn.setAttribute('aria-pressed', active ? 'true' : 'false');
      if (active) btn.setAttribute('aria-current', 'true');
      btn.addEventListener('click', (ev) => {
        ev.preventDefault();
        ev.stopPropagation();
        setSpawnCwdInputValue(opt.value);
      });
      wrap.appendChild(btn);
    }
    renderNewSessionRepoSuggestions();
  }

  function refreshNewSessionCwdUi(paneId) {
    if (currentConversation !== '__new__') return;
    const spawnCwd = getSpawnCwd();
    updatePaneHeader(paneId || activePaneId(), {
      source: getSpawnEngine(),
      display_name: 'New session',
      folder_label_chip: spawnCwdLabel(spawnCwd),
    }, { category: 'new session', title: 'New session' });
    updateNewSessionCwdNotice();
    updateInputBar();
  }

  function ensureSpawnCwdOptionsLoaded(paneId) {
    if (spawnCwdOptions.length || (repoListState && repoListState.repos && repoListState.repos.length)) return;
    loadRepoList().then(() => {
      if (currentConversation !== '__new__') return;
      populateSpawnCwdPicker();
      refreshNewSessionCwdUi(paneId);
    }).catch(() => {});
  }

  function isSpawnCwdMenuOpen() {
    const menu = document.getElementById('spawnCwdMenu');
    return !!(menu && menu.classList.contains('open'));
  }

  function setSpawnCwdMenuOpen(open) {
    const menu = document.getElementById('spawnCwdMenu');
    const btn = document.getElementById('spawnCwdMenuBtn');
    if (!menu) return;
    menu.classList.toggle('open', !!open);
    if (btn) btn.setAttribute('aria-expanded', open ? 'true' : 'false');
  }

  function renderSpawnCwdMenu(filterText) {
    const menu = document.getElementById('spawnCwdMenu');
    if (!menu) return;
    const q = normalizeSpawnCwdPath(filterText).toLowerCase();
    const matches = spawnCwdOptions
      .filter(opt => {
        if (!q) return true;
        return String(opt.label || '').toLowerCase().includes(q)
          || String(opt.value || '').toLowerCase().includes(q);
      })
      .slice(0, 60);
    menu.innerHTML = '';
    if (!matches.length) {
      const empty = document.createElement('div');
      empty.className = 'spawn-cwd-menu-empty';
      empty.textContent = 'No matching folders';
      menu.appendChild(empty);
      return;
    }
    for (const opt of matches) {
      const item = document.createElement('button');
      item.type = 'button';
      item.className = 'spawn-cwd-option';
      item.setAttribute('role', 'option');
      item.dataset.value = opt.value;
      const label = document.createElement('span');
      label.className = 'spawn-cwd-option-label';
      label.textContent = opt.label || opt.value;
      const path = document.createElement('span');
      path.className = 'spawn-cwd-option-path';
      path.textContent = opt.value;
      item.appendChild(label);
      item.appendChild(path);
      item.addEventListener('click', () => {
        const input = document.getElementById('spawnCwdPicker');
        if (input) {
          input.value = opt.value;
          persistSpawnCwdPickerValue({ target: input });
          input.focus();
        }
        setSpawnCwdMenuOpen(false);
      });
      menu.appendChild(item);
    }
  }

  function openSpawnCwdMenu(filterText) {
    if (!spawnCwdOptions.length) populateSpawnCwdPicker();
    setSpawnCwdMenuOpen(true);
    renderSpawnCwdMenu(filterText || '');
  }

  function closeSpawnCwdMenu() {
    setSpawnCwdMenuOpen(false);
  }

  function setSpawnCwdInputValue(path, opts = {}) {
    const input = document.getElementById('spawnCwdPicker');
    const value = normalizeSpawnCwdPath(path);
    if (!input || !value) return;
    input.value = value;
    persistSpawnCwdPickerValue({ target: input });
    // Reactive callers (the new-project name field's auto-CWD suggestion) must
    // NOT steal focus: doing so bounced focus out of #nsNewProjectName on every
    // keystroke/focus, making the name field read as "not editable" (CCC-144).
    if (opts.focus !== false) input.focus();
  }

  document.addEventListener('click', (ev) => {
    const btn = ev.target && ev.target.closest && ev.target.closest('#nsRepoSuggestions [data-ns-repo]');
    if (!btn) return;
    ev.preventDefault();
    setSpawnCwdInputValue(btn.getAttribute('data-ns-repo') || '');
    renderNewSessionRepoSuggestions();
    const input = composerInputForPane(activePaneId()) || $convInput;
    if (input) input.focus();
  });

  async function chooseSpawnCwdFolder() {
    const btn = document.getElementById('spawnCwdBrowseBtn');
    if (btn) btn.disabled = true;
    closeSpawnCwdMenu();
    try {
      const r = await fetch('/api/fs/pick-folder', { method: 'POST' });
      const picked = await r.json().catch(() => ({}));
      if (picked && picked.cancelled) return;
      if (!picked || !picked.ok || !picked.path) {
        showOpToast('Folder picker failed: ' + ((picked && picked.error) || 'unknown'), 'error');
        return;
      }
      let selectedPath = picked.path;
      try {
        const addRes = await fetch('/api/repo/add', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ path: selectedPath }),
        });
        const addData = await addRes.json().catch(() => ({}));
        if (addRes.ok && addData && addData.ok) {
          selectedPath = addData.path || selectedPath;
          if (Array.isArray(addData.repos)) repoListState.repos = addData.repos;
          populateSpawnCwdPicker();
        }
      } catch (_) {}
      setSpawnCwdInputValue(selectedPath);
    } catch (err) {
      showOpToast('Folder picker failed: ' + ((err && err.message) || 'network'), 'error');
    } finally {
      if (btn) btn.disabled = false;
    }
  }

  // CCC-128: click the "📁 cwd missing — set folder" pill to point a session at
  // its real directory. Native folder picker → register the repo → persist the
  // override server-side → re-fetch the workspace so the pill refreshes.
  async function setSessionCwdViaPicker(sid, triggerEl) {
    if (!sid) return;
    if (triggerEl) triggerEl.disabled = true;
    try {
      const r = await fetch('/api/fs/pick-folder', { method: 'POST' });
      const picked = await r.json().catch(() => ({}));
      if (picked && picked.cancelled) return;
      if (!picked || !picked.ok || !picked.path) {
        showOpToast('Folder picker failed: ' + ((picked && picked.error) || 'unknown'), 'error');
        return;
      }
      const chosen = picked.path;
      try {
        const addRes = await fetch('/api/repo/add', {
          method: 'POST', headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ path: chosen }),
        });
        const addData = await addRes.json().catch(() => ({}));
        if (addRes.ok && addData && addData.ok && Array.isArray(addData.repos)) {
          repoListState.repos = addData.repos;
        }
      } catch (_) {}
      const setRes = await fetch('/api/session/' + encodeURIComponent(sid) + '/cwd', {
        method: 'POST', headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ cwd: chosen }),
      });
      const setData = await setRes.json().catch(() => ({}));
      if (!setRes.ok || !setData.ok) {
        showOpToast('Could not set folder: ' + ((setData && setData.error) || ('HTTP ' + setRes.status)), 'error');
        return;
      }
      showOpToast('Folder set: ' + setData.cwd, 'success');
      if (typeof fetchSessionWorkspace === 'function') fetchSessionWorkspace(sid);
    } catch (err) {
      showOpToast('Could not set folder: ' + ((err && err.message) || 'network'), 'error');
    } finally {
      if (triggerEl) triggerEl.disabled = false;
    }
  }
  document.addEventListener('click', (ev) => {
    const btn = ev.target && ev.target.closest && ev.target.closest('[data-action="set-cwd"]');
    if (!btn) return;
    ev.preventDefault();
    ev.stopPropagation();
    setSessionCwdViaPicker(btn.getAttribute('data-sid') || '', btn);
  });

  function updateNewSessionCwdNotice() {
    if (currentConversation !== '__new__') return;
    const notice = document.getElementById('newSessionCwdNotice');
    if (!notice) return;
    const cwd = getSpawnCwd();
    notice.textContent = spawnCwdLabel(cwd) || 'pick a folder below';
    notice.title = cwd || '';
  }

  // Persist the user's choice the moment they change it.
  function persistSpawnCwdPickerValue(ev) {
    if (ev.target && ev.target.id === 'spawnCwdPicker') {
      try { localStorage.setItem(SPAWN_CWD_KEY, normalizeSpawnCwdPath(ev.target.value)); } catch (_) {}
      if (isSpawnCwdMenuOpen()) renderSpawnCwdMenu(ev.target.value);
      renderSpawnCwdQuickChips();
      updateNewSessionCwdNotice();
      // Keep the chooser's repo chips honest when the CWD is edited by
      // hand (CCC-91): highlight the chip matching the typed path, clear
      // the highlight when the path matches none of them.
      const _cwdNow = normalizeSpawnCwdPath(ev.target.value);
      document.querySelectorAll('.ns-repo-chip').forEach(b => {
        b.classList.toggle('is-current',
          normalizeSpawnCwdPath(b.getAttribute('data-ns-repo') || '') === _cwdNow);
      });
      if (currentConversation === '__new__') updateInputBar();
    }
  }
  document.addEventListener('change', persistSpawnCwdPickerValue);
  document.addEventListener('input', persistSpawnCwdPickerValue);

  {
    const spawnCwdBtn = document.getElementById('spawnCwdMenuBtn');
    const spawnCwdBrowseBtn = document.getElementById('spawnCwdBrowseBtn');
    const spawnCwdInput = document.getElementById('spawnCwdPicker');
    if (spawnCwdBtn) {
      spawnCwdBtn.addEventListener('click', (ev) => {
        ev.preventDefault();
        ev.stopPropagation();
        if (isSpawnCwdMenuOpen()) closeSpawnCwdMenu();
        else openSpawnCwdMenu('');
      });
    }
    if (spawnCwdBrowseBtn) {
      spawnCwdBrowseBtn.addEventListener('click', (ev) => {
        ev.preventDefault();
        ev.stopPropagation();
        chooseSpawnCwdFolder();
      });
    }
    if (spawnCwdInput) {
      spawnCwdInput.addEventListener('keydown', (ev) => {
        if (ev.key === 'ArrowDown') {
          ev.preventDefault();
          openSpawnCwdMenu('');
        } else if (ev.key === 'Escape') {
          closeSpawnCwdMenu();
        }
      });
    }
    document.addEventListener('click', (ev) => {
      const row = document.querySelector('.spawn-cwd-row');
      if (row && row.contains(ev.target)) return;
      closeSpawnCwdMenu();
    });
  }

  function getSpawnCwd() {
    const sel = document.getElementById('spawnCwdPicker');
    return normalizeSpawnCwdPath(sel && sel.value);
  }

  // CCC-86: adopt the REAL spawn-cwd controls (input + ▾ menu + 📁 browse,
  // plus the worktree toggle) from the bottom input-context strip into the
  // chooser's card 1. Moving the live DOM nodes keeps every existing
  // handler (menu, browse, persistence) wired — one folder control, not
  // two. _restoreCwdControlsToInputBar puts them back when a session opens.
  // Original DOM home of the composer (#convInputBar) while the new-session
  // stage borrows it — captured at adopt time so restore is exact.
  let _adoptedComposerHome = null;
  function _adoptCwdControlsIntoChooser($view) {
    const slot = $view && $view.querySelector('#nsCwdSlot');
    const cic = document.getElementById('convInputContext');
    if (!slot || !cic) return;
    const row = cic.querySelector('.spawn-cwd-row');
    const wt = cic.querySelector('.spawn-worktree-row');
    if (row) slot.appendChild(row);
    if (wt) slot.appendChild(wt);
    cic.classList.add('cwd-controls-adopted');
    // Composer stays at the bottom of the pane (its normal position).
  }
  function _restoreCwdControlsToInputBar() {
    const cic = document.getElementById('convInputContext');
    if (!cic || !cic.classList.contains('cwd-controls-adopted')) return;
    const slot = document.getElementById('nsCwdSlot');
    const row = slot && slot.querySelector('.spawn-cwd-row');
    const wt = slot && slot.querySelector('.spawn-worktree-row');
    const usage = cic.querySelector('.wp-usage');
    if (row) cic.insertBefore(row, usage || null);
    if (wt) cic.insertBefore(wt, usage || null);
    cic.classList.remove('cwd-controls-adopted');
    const bar = document.getElementById('convInputBar');
    if (bar && _adoptedComposerHome && _adoptedComposerHome.parent
        && bar.parentElement !== _adoptedComposerHome.parent) {
      bar.classList.remove('is-centered-stage');
      _adoptedComposerHome.parent.insertBefore(bar, _adoptedComposerHome.next || null);
    }
    _adoptedComposerHome = null;
  }

  // Fun default project names for the New-project card. A random one is
  // prefilled on entry; the 🎲 button rolls again. Slugify turns the
  // pick into the ~/dev/<slug> folder suggestion.
